INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709519', 'Aerothon 2026 - HAL x IITI', 'Aerothon 2026 is a national-level aerospace hackathon organized by Hindustan Aeronautics Limited (HAL) in collaboration with IIT Indore, bringing together innovators, engineers, programmers, and researchers to tackle real-world challenges in aerospace engineering using data-driven approaches. From machine learning for aerodynamic prediction to surrogate modelling for propulsion systems and intelligent optimization of aerospace designs, participants will work on cutting-edge problem statements inspired by modern aerospace engineering challenges. Competition Format: Round 1: Online Screening Round Teams will select and solve one of the provided problem statements and submit their proposed solution, methodology, and implementation. The best teams from across the country will be shortlisted for the Grand Finale. Only the Team Leader needs to register and add their remaining team members. The Problem Statements are available in the brief/case section of round 1 after team registration Grand Finale: 24-Hour Hackathon at IIT Indore Shortlisted teams will be invited to IIT Indore for an intense 24-hour hackathon on 7th&ndash;8th August 2026, where they will build, refine, and present their solutions before an expert panel. The finale offers participants an opportunity to: Work on industry-inspired aerospace challenges. Interact with faculty and researchers from IIT Indore. Engage with experts and officials from HAL. Network with students and innovators from across the country. Present solutions to a distinguished jury from academia and industry. Compete for prizes worth up to ₹2,10,000. Who Should Participate? Students interested in: Aerospace Engineering Artificial Intelligence and Machine Learning Data Science and Analytics Optimization and Scientific Computing Whether you''re an aerospace enthusiast, an AI developer, a simulation expert, or a problem solver looking to apply technology to the next generation of aviation and space systems, Aerothon 2026 is your platform to innovate and compete. Please note that the data is open source and/or generated and is not original data from HAL or IIT Indore Team Details: Team Size: 2&ndash;4 members Eligibility: Undergraduate and postgraduate students from recognized institutions across India Think. Build. Fly.', '2026-07-01T00:00:00+05:30', '2026-08-08T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/aerothon-2026-hal-x-iiti-iit-indore-1709519', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709515', 'AI Career Hackathon', 'AI Career Challenge Ready to showcase your engineering skills beyond your resume? The AI Career Challenge is an AI-native hiring challenge for developers with 1+ year of experience. We''re looking for talented engineers for two roles: Frontend Engineer and Backend Engineer. On the day of the challenge, participants will receive a real-world AI product problem statement and will have 2.5 hours to build an MVP using AI tools and modern development workflows. Throughout the challenge, you''ll interact with mentors, discuss your technical approach, and present your solution in a startup-style technical interview. We evaluate more than just the final product. Our focus is on: Problem-solving approach Engineering fundamentals Technical decision-making Product thinking Communication and technical reasoning Top-performing participants will be referred to our startup hiring partners based on their skills and role fit. If you''re excited to solve challenging AI problems and demonstrate how you think, we''d love to see you there.', '2026-07-01T00:00:00+05:30', '2026-07-04T16:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/shebuilds-ai-career-hackathon-shebuilds-1709515', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709331', 'Smart School FinTech Innovation Challenge 2026', 'Smart School FinTech Innovation Challenge 2026 Build the Future of Education Through Technology Technology has transformed industries worldwide, yet many educational institutions continue to face challenges such as fragmented software systems, manual administrative processes, disconnected communication, outdated financial workflows, and inefficient operations. At PaperBuddy, we believe that the next generation of Software Engineers has the potential to solve these challenges by building innovative and impactful technology solutions. The Smart School FinTech Innovation Challenge 2026 is a national-level software engineering hackathon where students, developers, designers, and innovators come together to create production-ready software that solves real-world problems. This is more than just a hackathon&mdash;it''s an opportunity to demonstrate your engineering skills, solve meaningful challenges, collaborate with talented minds across India, and compete for exciting rewards, including a Software Engineer Pre-Placement Offer (PPO). Whether you''re passionate about Full Stack Development, Mobile Applications, Artificial Intelligence, Cloud Computing, Backend Systems, or Product Engineering, this challenge is built for you. Challenge Statement Educational institutions generate enormous amounts of data every day, yet many schools still rely on disconnected software, paperwork, inefficient fee management systems, and outdated administrative workflows. Your challenge is to design and develop a production-ready software solution capable of solving real-world problems within Smart Schools, Education Technology, Financial Technology, or Digital Productivity. Your solution should focus on creating measurable value by improving efficiency, enhancing user experience, automating repetitive processes, or introducing innovative digital solutions that can positively impact students, teachers, parents, and educational institutions. We encourage participants to think beyond traditional solutions and build products that are scalable, practical, and capable of solving real business problems. Submission Format Every participating team must submit the following before the final submission deadline: Project Presentation (PPT) The presentation should include: Problem Statement Proposed Solution Key Features System Architecture Technology Stack Future Scope Working Prototype Working Prototype A fully functional web, mobile, or desktop application demonstrating your solution. Source Code A complete GitHub repository with clean, well-documented, and properly structured code. Demo Video A 3&ndash;5-minute demonstration explaining the project, its features, workflow, and real-world impact. Project Documentation Include: Installation & Setup Guide Project Architecture APIs & Integrations (if applicable) Technical Overview Live Demo (Optional but Recommended) If your application is deployed, share the live URL for easier evaluation. Note: All submissions must be original. Any form of plagiarism will result in immediate disqualification. Eligibility Open to students across India. Individual and Team Participation (1&ndash;4 Members). Students from any branch or academic year are eligible. Beginners as well as experienced developers are welcome. Rewards & Recognition Winner Software Engineer Pre-Placement Offer (PPO) at PaperBuddy (subject to final technical evaluation and interview). Runner-Up ₹30,000 Cash Prize Second Runner-Up ₹20,000 Cash Prize All eligible participants will receive a Digital Certificate of Participation. Evaluation Criteria Projects will be evaluated based on: Innovation & Creativity Problem Solving Approach Technical Excellence Software Architecture Code Quality UI/UX Design Scalability & Performance Business Impact Product Demonstration & Presentation Rules & Guidelines Projects must be original and developed by the participating team. Plagiarism or copied work will lead to immediate disqualification. AI tools may be used as development assistants; however, participants must be able to explain their implementation during evaluation. Teams must own the submitted source code and project assets. The decision of the judging panel will be final and binding. Why Participate? Solve real-world challenges. Build a production-ready software product. Strengthen your resume and portfolio. Compete with talented innovators across India. Win exciting cash prizes. Earn an opportunity for a Software Engineer PPO at PaperBuddy. Showcase your skills before industry professionals.', '2026-07-01T00:00:00+05:30', '2026-07-16T19:15:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/smart-school-fintech-innovation-challenge-2026-paper-buddy-1709331', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709437', 'AI for Bharat Hackathon 2026 – Build AI Solutions for India''s Real Problems', 'AI for Bharat Hackathon 2026 India faces problems that global, off-the-shelf AI solutions often fail to solve - language diversity, rural access gaps, agricultural unpredictability, and healthcare reach. This hackathon challenges participants to build AI-powered solutions tailored to real Indian contexts. Theme Tracks Regional Language AI (voice, translation, low-resource NLP) AgriTech (crop advisory, pest detection, yield prediction) Rural Healthcare Access (diagnostics, telemedicine tools) Smart Public Transport & Civic Infrastructure Financial Inclusion (rural banking, fraud detection, micro-credit) EligibilityOpen to students (undergraduate & postgraduate) and early-career professionals. Only Individual participation allowed for final submission. Format Stage 1: Idea/PPT submission (shortlisting round) Stage 2: 24&ndash;36 hour build sprint (online) Stage 3: Final presentation & live demo to judges Rules Use of open-source datasets, public APIs, and pre-trained models is allowed and encouraged Code must be original and built during the hackathon window (prior ideation is fine) Plagiarism or use of pre-built products will lead to disqualification All submissions must include a working prototype/demo + GitHub repo + 2-min explainer video Judging Criteria Innovation & relevance to Indian context (25%) Technical implementation (25%) Feasibility/scalability (20%) UI/UX & presentation (15%) Social impact potential (15%) Prizes Winner: ₹1000 Runner-up: ₹700 Best Use of AI for Social Good: ₹500 Winning Certificate', '2026-07-01T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-for-bharat-hackathon-2026-build-ai-solutions-for-indias-real-problems-indraprastha-institute-of-informatio-1709437', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708678', 'MSOC 2026 — MSTC Summer of Code Data Science', 'MSOC 2026 &mdash; MSTC Summer of Code (Data Science & Analytics Track) About the Program: MSOC (MSTC Summer of Code) is a guided learning-to-build program organized by the Microsoft Student Technical Club (MSTC), DA-IICT. Participants spend the initial weeks developing practical skills in Data Science and Applied AI before applying their knowledge in a structured, two-round hackathon. This track is designed for students who want to move beyond tutorials and build a complete data-driven project&mdash;from identifying a real-world problem to developing, documenting, and presenting a working solution. Track Details: Track: Data Science & Analytics. Team Size: 1&ndash;2 members. Mode: Online. What You''ll Do: Receive a real-world problem statement. Build, document, and demonstrate a working data-driven solution. Receive evaluation and feedback from MSTC mentors and faculty. Who Should Participate? This track is open to anyone interested in Data Science or Generative AI, whether beginner or intermediate, who wants a structured opportunity to build their first real-world project instead of learning only through tutorials. Eligibility: Open to all current undergraduate and postgraduate students of DA-IICT. Open to students from all academic years and disciplines. No prior experience in Data Science, AI, or Machine Learning is required. Each participant may be part of only one team. Both team members (for teams of two) must register individually on Unstop before the registration deadline. Community Support: Join the official MSOC WhatsApp community for updates, announcements, and mentor support: Rules & Regulations: All work must be original and created specifically for MSOC 2026. Reused or previously submitted projects are not permitted. The use of open-source libraries, frameworks, pre-trained models, and AI coding tools is allowed, provided they are properly credited in the project README. Teams may seek guidance from MSTC mentors; however, all core development must be completed by the team members. All updates regarding submissions, deadlines, and clarifications will be communicated through the official MSOC WhatsApp community and Unstop. Participants are responsible for staying informed. The organizing committee reserves the right to modify timelines, problem statements, or evaluation criteria if required, with prior notice. Participants are expected to maintain professionalism in all interactions with mentors, judges, organizers, and fellow participants. The decisions of the judging panel and organizing committee shall be final and binding. Disqualification Criteria: A team will be disqualified if: The submitted project is plagiarized, copied, or substantially reused from an existing public project without proper disclosure. The GitHub repository is private, inaccessible, or unavailable during evaluation. The team misrepresents dataset sources or fabricates results. Any form of misconduct, including impersonation or submission tampering, is identified. The submission is made after the deadline without prior approved extension.', '2026-06-29T00:00:00+05:30', '2026-07-13T00:00:00+05:30', 'Online', 'online', '₹ 600', 'https://unstop.com/hackathons/msoc-2026-mstc-summer-of-code-data-science-dhirubhai-ambani-institute-of-information-and-communication-techno-1708678', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001671501', 'Roboauto-2026', 'RoboAuto Hackathon 2026 &ndash; AGV & Automation Challenge: RoboAuto Hackathon 2026 is an intensive 24-hour hands-on robotics and automation challenge designed to push the boundaries of innovation in autonomous systems. Organized by the Robotics and Innovation Club of Vidya Jyothi Institute of Technology (VJIT), Hyderabad, this event invites engineering students to design and build Automated Guided Vehicle (AGV)-like robots and smart automation solutions that solve real-world industrial problems. Participants will work in teams to develop functional prototypes capable of tasks such as line-following, path planning, obstacle avoidance, and material transport&mdash;core concepts used in modern factories and warehouses. Throughout the hackathon, teams will receive guidance from experienced mentors and faculty, helping them refine their ideas and improve execution under real-time constraints. What You''ll Build: AGV-like robots for material handling. Line-following or path-guided systems. Obstacle detection and avoidance solutions. Mini automation systems simulating industrial workflows. Event Format: Duration: 24 hours (continuous build and overnight hacking). Structure: Idea pitching. Development and mentorship rounds. Final demo and evaluation. Why Participate?: Gain hands-on experience in robotics, embedded systems, and automation. Work on real-world industrial problem statements. Collaborate in teams within a competitive environment. Win exciting prizes from a ₹10,000 prize pool. Earn certificates and recognition.', '2026-04-25T07:30:00+05:30', '2026-07-05T18:29:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/roboauto-2026-vidya-jyothi-institute-of-technology-1671501', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708852', 'Breaking Bot IPEC', 'About Breaking Bot IPEC: Breaking Bot IPEC is the flagship national-level hackathon jointly organized by IEEE Student Branch, Indraprastha Engineering College (IPEC), Ghaziabad, and Coders Den. Inspired by the iconic Breaking Bad universe, the hackathon challenges participants to "break" conventional thinking, experiment with bold ideas, and build innovative technology that solves real-world problems. More than just a coding competition, Breaking Bot IPEC is where creativity meets technology. Participants will collaborate in teams to transform ambitious ideas into impactful solutions while experiencing an energetic atmosphere filled with mentorship, networking, and innovation. Mandatory Steps: Fill the Mandatory Registration Form: https://forms.gle/MgGrg1WNp2zy8ESJA Submit the Idea Presentation (PPT) before the submission deadline. Failure to complete either of the above mandatory steps may result in disqualification. Join the official WhatsApp Community for important announcements, updates, and event-related communication: https://chat.whatsapp.com/FKgLSZ4OZ3cI0XfN8gjvIr Hackathon Tracks: Artificial Intelligence & Machine Learning Web Development Mobile App Development Cloud Computing Cybersecurity Blockchain & Web3 Internet of Things (IoT) Healthcare & MedTech Sustainability & Climate Technology Education Technology FinTech Open Innovation Participants are encouraged to solve real-world challenges by developing innovative, scalable, and impactful technology-driven solutions. Eligibility: Undergraduate students Postgraduate students Developers, designers, and technology enthusiasts from recognized institutions across India Team Size: 2&ndash;3 Members Cross-college teams are allowed. Cross-disciplinary teams are encouraged. Each participant can be a member of only one team. Competition Format: Round 1 &ndash; Online Idea Submission (Screening Round): The first round is an online elimination stage. Teams must submit a PowerPoint Presentation (PPT) explaining their proposed solution. The PPT should clearly cover the problem statement, existing challenges, proposed solution, key features, workflow or system architecture, technology stack, implementation roadmap, innovation, scalability, expected impact, and future scope of the project. The presentation should effectively communicate the originality, feasibility, and potential real-world impact of the proposed solution. Every submission will be evaluated on: Innovation Technical feasibility Problem relevance Practical implementation Clarity of presentation Scalability Real-world impact Only the highest-ranked teams will advance to the Offline Grand Finale. Round 2 &ndash; Offline Grand Finale: Shortlisted teams will be invited to Indraprastha Engineering College, Ghaziabad, where they will compete in an intensive offline hackathon. During the event, participants will: Build a fully functional prototype. Receive mentorship from industry experts. Validate and refine their solution. Present and demonstrate their project before an expert judging panel. Network with fellow innovators, mentors, recruiters, and professionals. The highest-scoring teams will be declared winners and receive exciting prizes, certificates, goodies, and recognition. Judging Criteria: Projects will be evaluated based on: Projects will be evaluated based on innovation and creativity, technical implementation, problem relevance, user experience (UI/UX), scalability, business potential, practical feasibility, presentation and demonstration, and the overall impact of the solution. Rules & Guidelines: All project ideas must be original. Teams are expected to build their prototype during the hackathon. Previously developed or commercially available projects are not permitted. Participants may use open-source tools, APIs, and frameworks while complying with their respective licenses. Any plagiarism, unethical conduct, or violation of the event rules will result in immediate disqualification. Shortlisted teams must remain present throughout the Offline Grand Finale. The decision of the organizing committee and judging panel shall be final. Why Participate? Build innovative solutions to real-world problems. Collaborate with talented developers and designers. Learn directly from experienced mentors and industry professionals. Present projects before experts and recruiters. Expand their professional network. Win exciting prizes, goodies, and certificates. Strengthen their portfolio with a real-world project. Gain exposure to internship, hiring, and collaboration opportunities. Enhance technical, communication, and teamwork skills. Why "Breaking Bot"? Inspired by the legendary Breaking Bad universe, Breaking Bot IPEC symbolizes breaking traditional boundaries of innovation and engineering. Just as the series challenged conventions, this hackathon encourages participants to think differently, solve complex problems, and build technology that creates meaningful impact. Bring your ideas, experiment fearlessly, and "cook" your next big innovation. Stay Connected: LinkedIn: https://www.linkedin.com/company/ieee-ipec/?viewAsMember=true Instagram: https://www.instagram.com/ieeeipec/ WhatsApp Community: https://chat.whatsapp.com/FKgLSZ4OZ3cI0XfN8gjvIr About the Organizers: IEEE Student Branch, IPEC: The IEEE IPEC Student Branch at Indraprastha Engineering College is committed to fostering innovation, technical excellence, and professional growth through hackathons, workshops, seminars, technical competitions, and industry collaborations. As a part of the world''s largest technical professional organization, IEEE IPEC empowers students to build impactful technologies for the future. Coders Den: Coders Den is a thriving student developer community focused on building technical skills through coding contests, hackathons, collaborative projects, workshops, and peer learning. Together with IEEE IPEC, Coders Den aims to create an engaging ecosystem where innovation, collaboration, and creativity thrive. Break Limits. Build Solutions. Become the One Who Breaks the Bot. Assemble your team, unleash your creativity, and get ready for an unforgettable innovation journey at Breaking Bot IPEC!', '2026-07-01T13:00:00+05:30', '2026-08-08T12:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/breaking-bot-ipec-inderprastha-engineering-college-ipec-ghaziabad-1708852', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001706104', 'COSC Hackweek', 'COSC Hackweek is a week long online event, presented by the CBIT Open Source Community. Hackweek is designed to help you learn, build, and explore the world of technology and open-source through daily challenges throughout the week. Whether you are taking your first step into tech or you''re an experienced developer looking to sharpen your skills, Hackweek offers something for everyone. Explore new technologies, solve hands-on challenges, and get exposure to various tools while being part of a vibrant learning community. Details: Participation: Individual participation Registration Fee: FREE Date: 06th July 2026 - 12th July 2026 Mode: Online Platform: Official COSC HackWeek Website + Discord  Eligibility Criteria: Open to all students, professionals, and coding enthusiasts regardless of their field or background Participants with varying levels of expertise from beginners to advanced programmers are welcome to join Basic programming knowledge in any language is recommended Guidelines & Rules: Daily challenges will be released on the official COSC HackWeek website Participants can attempt any number of challenges during the event period Solutions can be submitted as GitHub links, screenshots or other required formats. All submissions must be made before the final deadline (July 11, 2026 - 11:59 PM IST) Maintain respectful conduct and fair competition throughout the event Any form of misconduct or plagiarism may lead to disqualification Note: Stay tuned to the announcements channel for daily challenge releases and important updates Use the help channel for challenge-related queries and community support Points will be awarded based on challenge completions, and top performers will be featured and rewarded Participation certificates will be provided to all registered participants who submit atleast one solution during the course of the week. Embrace this fantastic opportunity to enhance your skills and connect with the programming community! Register now for FREE and let your coding brilliance shine at COSC HackWeek 2026!', '2026-06-27T00:00:00+05:30', '2026-07-05T23:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/cosc-hackweek-chaitanya-bharathi-institute-of-technology-cbit-hyderabad-1706104', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703344', 'Vibe2Vision', 'All participants are requested to read the complete rule book before the event. Vibe2Vision 2026 is a 36-hour innovation hackathon organized by the IEEE Women in Engineering (WIE) Chapter, VSSUT Student Branch. Participants will design and build impactful technology solutions under the theme "Catalyst for Equity &ndash; Engineering Resilient Ecosystems for Women." The hackathon emphasizes creativity, problem-solving, rapid development, and effective use of modern AI-assisted development tools to create functional, user-centric applications. Rules & Architecture Teams are free to choose any programming language, framework, AI tool, IDE, database, cloud platform, or deployment technology. Teams are expected to maintain active development throughout the event. The hackathon will run continuously for 36 hours. Participation is allowed in teams of 1 to 3 members. Every team must work on one of the three official challenge tracks. A GitHub push/check-in is mandatory every 6 hours to demonstrate continuous progress. (Night hours from 10:00 PM to 6:00 AM are exempt from mandatory check-ins.) Organizers reserve the right to monitor repositories and verify development progress at any stage of the hackathon. All submitted work must be original and created during the hackathon.', '2026-06-28T17:00:00+05:30', '2026-07-07T10:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/vibe2vision-ieee-sheaspire-30-veer-surendra-sai-university-of-technology-vssut-odisha-1703344', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704689', 'Cascade - A Cryptic Hunt', 'General: The competition will be conducted entirely through the official Cryptic Hunt Portal. Each registered team will receive unique login credentials before the event. Participants are responsible for keeping their login credentials secure throughout the competition. Competition Format: Teams must begin by reading the mission briefing available on the portal. The event consists of multiple case files that can be solved in any order unless specified otherwise. Answers must be submitted through the portal only. Successfully completing all case files unlocks the Final Stage. Completing the Final Stage marks the official completion of the event. Time & Ranking: The event timer starts when a participant first logs into the portal. Logging out does not pause the timer. Every submission is automatically timestamped. Final rankings will primarily be based on: Successful completion of all case files. Completion of the Final Stage. Official completion timestamp (earlier completion ranks higher). In case no team completes the Final Stage, rankings will be determined by overall progress. Any ties will be resolved using the timestamp of the last successfully completed case. Technical Guidelines: Participants are advised to use a stable internet connection. Technical issues arising from a participant&rsquo;s device or internet connection will not qualify for additional time. In case of portal-related issues, participants should immediately contact the organizing team. Fair Play Policy: Sharing answers or collaborating with other teams is strictly prohibited. Attempting to exploit bugs, gain unauthorized access, or interfere with the event portal is prohibited. Any form of plagiarism, cheating, or unfair practices will lead to immediate disqualification. The organizing committee reserves the right to review submissions in case of suspicious activity. Important: Decisions made by the judges and the organizing committee shall be final and binding. The organizing committee reserves the right to modify the rules if necessary. By participating, teams agree to abide by all event rules and the decisions of the organizing committee.', '2026-06-27T00:00:00+05:30', '2026-07-05T00:00:00+05:30', 'Online', 'online', '3k worth goodies from Upto Skills , Coding Ninjas ', 'https://unstop.com/hackathons/cascade-a-cryptic-hunt-manipal-university-mu-jaipur-1704689', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001705001', 'Hack to Survive', 'Think you have what it takes to survive the ultimate challenge? Whatsapp group link - https://chat.whatsapp.com/Dhqhr4lbkY23HinrAD5wLe Hack to Survive is a thrilling Squid Game-inspired hackathon where every round is a test of skill, creativity, strategy, and innovation. Participants must survive multiple elimination rounds, solve real-world problems, and build impactful solutions under pressure to advance to the next stage. Whether you''re a developer, designer, entrepreneur, or problem solver, this is your chance to showcase your talent, compete against the best minds, and fight for the top spot on the leaderboard. Event Details: Date: 8 August 2026 Venue: TBA  Mode: To Be Announced What to Expect? Multiple survival-themed challenge rounds Exciting problem statements Networking with talented participants Certificates and recognition Prizes for top-performing teams A unique Squid Game-inspired competitive experience Only the strongest ideas survive. Will yours make it to the end?', '2026-06-27T00:00:00+05:30', '2026-08-08T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hack-to-survive-kiras-logic-1705001', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704716', 'Bizzathon-Hackathon', 'About the Competition: Bizzathon is an 18-hour hackathon where participants solve real-world problem statements provided by the judging panel at the start of the competition. Teams analyze the problem, develop an innovative and practical solution, and prepare a comprehensive presentation within the allotted time. The competition evaluates creativity, critical thinking, teamwork, and problem-solving under time constraints. Teams present their solutions before a panel of judges at the end of the hackathon. Solutions are evaluated based on innovation, feasibility, scalability, impact, presentation skills, and overall effectiveness. Participants gain hands-on experience, receive feedback from mentors and industry experts, and develop entrepreneurial and collaborative skills. Competition Format: Round 1: Online Quiz (Screening Round) Online aptitude and business quiz. Assesses analytical thinking, problem-solving abilities, and entrepreneurial knowledge. Top-performing teams qualify for the next round. Round 2: Business & Innovation Hackathon Real-world problem statement provided at the beginning of the hackathon. Teams get 18 hours to analyze the problem, develop innovative solutions, create a business or implementation strategy, and prepare the final presentation. Round 3: Final Presentation Teams present their solutions before the judging panel. Followed by a question-and-answer session. Evaluation is based on innovation, feasibility, scalability, business viability, presentation skills, problem-solving approach, and overall impact. Rules: Eligibility: Team size: 1&ndash;3 members. Open to students enrolled in any recognized university in India. Registration through Unstop before the deadline is mandatory. General Rules: Shortlisted teams must report to the venue at least 30 minutes before the event. Valid college ID cards are mandatory for verification. Professional conduct must be maintained throughout the event. Problem statement will be revealed only at the beginning of the hackathon. Teams must work only on the assigned problem statement. Internet and publicly available resources may be used unless stated otherwise. Plagiarism, malpractice, or unfair practices will result in immediate disqualification. Judges'' and organizers'' decisions will be final and binding. Organizers reserve the right to modify the schedule, rules, or format if required. Any dispute will be resolved by the Organizing Team, whose decision will be final. Submission Guidelines: Only teams shortlisted through the screening quiz can participate in the hackathon. Final presentation must be submitted in PPT or PDF format before the announced deadline. Only one final submission per team is allowed. The submitted solution must be the team''s original work. Teams must carry offline copies of the presentation in both PPT and PDF formats. Each team will receive a fixed presentation time followed by a Q&A session. All presentations and interactions must be conducted in English.', '2026-06-27T10:00:00+05:30', '2026-08-09T16:00:00+05:30', 'Online', 'online', '₹ 12,000', 'https://unstop.com/hackathons/bizzathon-hackathon-e-summit-2026-iit-ism-dhanbad-indian-institute-of-technology-indian-school-of-mines-iit-i-1704716', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704834', 'AlgoQuest 2026 – National Level Coding Competition', 'Tagline Code. Compete. Conquer. Rise Beyond Limits. About the Event Ascent Quest 2026 is the flagship national-level online coding competition organized by The Ascent Circle to bring together aspiring programmers, competitive coders, and problem solvers from across India. Designed to test logical reasoning, programming expertise, algorithmic thinking, and problem-solving abilities, the competition offers participants an opportunity to compete against the best while enhancing their coding skills. Whether you''re taking your first step into competitive programming or you''re an experienced developer looking to challenge yourself, Ascent Quest 2026 provides the perfect platform to learn, compete, and grow. The coding contest will be conducted on the official HackerRank Coding Arena, while registrations will be managed through Unstop. Event Details Event Name: Ascent Quest 2026 Organized By: The Ascent Circle Registration Platform: Unstop Coding Platform: HackerRank Coding Arena Contest Date: 5 July 2026 Unstop Registration Deadline: 5 July 2026 | 10:30 AM IST HackerRank Registration Deadline: 5 July 2026 | 10:45 AM IST (Mandatory) Contest Window: 11:00 AM &ndash; 8:00 PM IST Contest Duration: 90 Minutes Mode: Online Registration Fee: Free Participation: Individual Eligibility: Open to School Students (Class XI&ndash;XII), College Students, Freshers, Professionals, and Coding Enthusiasts across India. How to Participate Step 1 Register for Ascent Quest 2026 on Unstop. Step 2 Complete the mandatory registration on the official HackerRank Coding Arena. HackerRank Contest Link:https://www.hackerrank.com/ascent-quest Step 3 Join the official WhatsApp group shared after registration. Step 4 On 5 July 2026, log in to HackerRank anytime between 11:00 AM and 8:00 PM IST. Step 5 Start the contest whenever you''re ready. Once started, your 90-minute timer begins and cannot be paused. Competition Format Individual coding competition Hosted on HackerRank Multiple algorithmic programming challenges Beginner to intermediate difficulty level Use any programming language supported by HackerRank Automatic evaluation using visible and hidden test cases Live leaderboard during the contest Final rankings based on score and submission time Why Participate? Compete with talented programmers from across India Test your coding and problem-solving skills Solve real-world algorithmic challenges Improve DSA and competitive programming skills Gain hands-on coding contest experience Earn a Digital Certificate Win exciting prizes and recognition Strengthen your resume and coding portfolio Perks Digital Certificate of Participation Certificates of Excellence for winners Exciting prizes for top performers National-level recognition Competitive programming experience Live leaderboard and rankings Opportunity to benchmark your coding skills Who Can Participate? School Students (Class XI&ndash;XII) Diploma Students Undergraduate Students Postgraduate Students Freshers Software Developers Competitive Programmers Coding Enthusiasts Rules Individual participation only. Registration on both Unstop and HackerRank is mandatory. Participants can start the contest anytime between 11:00 AM and 8:00 PM IST. Once started, the contest timer cannot be paused. Each participant gets 90 minutes to complete the contest. Only submissions made within the allotted contest duration will be evaluated. Multiple submissions are allowed; the best valid submission before the timer ends will be considered. Plagiarism, collaboration, or any unfair means will result in immediate disqualification. The organizing team reserves the right to modify the rules if required. The decision of The Ascent Circle will be final and binding. Judging Criteria Participants will be evaluated based on: Correctness of solutions Number of problems solved Total score achieved Submission time Code efficiency Performance on hidden test cases Prerequisites Basic knowledge of any programming language Laptop or Desktop Stable internet connection Active HackerRank account Updated web browser Certificate Policy Every participant who: Registers on Unstop Completes mandatory HackerRank registration Participates in the contest Submits at least one valid solution will receive a Digital Certificate of Participation. Top-performing participants will receive Certificates of Excellence. Prize Details Exciting prizes for top performers Certificates of Excellence National-level recognition Performance-based rankings Exclusive recognition from The Ascent Circle Registration Process Register on Unstop. Complete the mandatory HackerRank registration. Join the official WhatsApp group. Log in on 5 July 2026. Start the contest anytime between 11:00 AM and 8:00 PM IST. Complete all challenges within 90 minutes. Official Coding Arena HackerRank Registration & Contest Link https://www.hackerrank.com/ascent-quest Important Notes Registration on HackerRank is mandatory to participate. Participants may start the contest at any time between 11:00 AM and 8:00 PM IST. The contest duration is 90 minutes from the moment the participant starts. Ensure your HackerRank account is active before contest day. Join early if you plan to begin at the opening time. Use a stable internet connection throughout the contest. Read all contest instructions carefully before starting. Any malpractice, plagiarism, or unfair means will result in immediate disqualification. Code. Compete. Conquer. Rise Beyond Limits.', '2026-06-27T00:00:00+05:30', '2026-07-05T10:23:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/algoquest-2026-national-level-coding-competition-apex-institute-of-technology-chandigarh-university-1704834', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704703', 'Grand Hack IPEC', 'Grand Hack IPEC is a 24-hour national-level offline hackathon organized by HackShastra in collaboration with Inderprastha Engineering College (IPEC), Ghaziabad. Inspired by the iconic GTA San Andreas theme, the hackathon combines innovation, technology, and creativity in an immersive experience where participants build impactful solutions to real-world challenges. The Offline Grand Finale will take place on 26&ndash;27 September 2026 at Inderprastha Engineering College, Ghaziabad. Idea submissions are currently open, while the schedule for the online shortlisting and mentorship round will be announced soon. Whether you''re a developer, designer, AI enthusiast, cybersecurity expert, or an aspiring entrepreneur, Grand Hack IPEC provides the perfect platform to showcase your skills, collaborate with like-minded innovators, receive mentorship from industry professionals, and compete for exciting prizes. Tracks: Participants can build projects under any of the following themes: Artificial Intelligence & Machine Learning Cybersecurity Web3 & Blockchain Internet of Things (IoT) AR/VR & Immersive Technologies Smart Cities & Urban Innovation Open Innovation Eligibility: Open to undergraduate and postgraduate students from all colleges and universities across India. Participants can register individually or as a team. Team size: 2&ndash;4 members. Cross-college and cross-disciplinary teams are allowed. Each participant can be a part of only one team. Competition Format: Round 1: Online Idea Submission (Open) Teams are required to submit a presentation (PPT) outlining their problem statement, proposed solution, implementation approach, technology stack, and expected impact. This round evaluates the innovation, feasibility, and clarity of each idea. Round 2: Online Shortlisting & Mentorship Shortlisted teams will be invited to participate in mentorship sessions with industry experts to refine their ideas and prepare for the final round. The dates and schedule for this round will be announced after the completion of idea submissions. Round 3: Offline Grand Finale Selected teams will compete in the 24-hour overnight hackathon on 26&ndash;27 September 2026 at Inderprastha Engineering College, Ghaziabad, where they will build working prototypes and present their solutions before an expert judging panel. Judging Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Implementation Problem Relevance User Experience & Design Scalability Presentation & Demonstration Rules: All submitted work must be original. Teams must build their projects during the hackathon. Existing projects are not permitted. Participants are encouraged to use open-source tools and APIs while complying with their respective licenses. Any form of plagiarism or unethical conduct will result in immediate disqualification. Teams must be present throughout the offline finale. The decision of the organizing team and judges will be final. Why Participate? Build innovative solutions with fellow creators. Receive mentorship from experienced professionals. Network with students, founders, recruiters, and industry experts. Win exciting prizes and exclusive goodies. Gain certificates, recognition, and potential internship and hiring opportunities. Experience one of India''s most exciting GTA San Andreas-inspired hackathons. Get ready to enter the city, build without limits, and make your mark at Grand Hack IPEC. Join Our Community For the latest updates, announcements, important notices, and hackathon-related discussions, join our official WhatsApp Community: https://chat.whatsapp.com/KYayQzqqp3HJ5XGkDIeJuH', '2026-06-26T00:00:00+05:30', '2026-09-27T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/grand-hack-ipec-hackshastra-1704703', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704216', 'Student Innovation & Product Summit (SIPS) 2026', 'Official Telegram Group:- https://t.me/+bbJ75C7KqOA5NDM9 Google Form Required to Fill:- https://docs.google.com/forms/d/1EK09lyL-bsI76Fgj-SgFmyPHSwpASrGuN-IEWdUNyqA/edit The Student Innovation & Product Summit (SIPS) 2026 is a national innovation competition organized by the Centre for Software & IT Management (CSITM), IIM Bangalore. The summit provides undergraduate students with an opportunity to showcase technology-driven solutions that address real-world challenges through functional prototypes. SIPS exists for one reason: to give your best work the stage it deserves. Bring your software project, your prototype, your idea and walk away with recognition, feedback, and a push toward what''s next. Themes: Participants may submit their project under one of the following themes: AI & Intelligent Systems Digital Trust & Infrastructure Tech for Impact Eligibility: Open to undergraduate students from recognized colleges and universities across India. Team Size: 1-3 members per team. Inter-college teams are allowed. Each team may submit only one project under one theme. Competition Structure: Round 1 &ndash; Online Submission Teams must submit a 7-slide PDF presentation describing their project. Submissions will be evaluated based on innovation, technical quality, feasibility, impact, and presentation. The top teams from each theme will advance to the next round. Round 2 &ndash; Video Pitch Shortlisted teams will submit a 4&ndash;5 minute recorded video pitch, an updated project deck, and a prototype link for evaluation. Grand Finale: Finalist teams will be invited to IIM Bangalore to present their projects through a live pitch, prototype demonstration, and jury interaction. Submission Requirements: Each team must submit: 7-slide PDF Presentation Project Title Project Abstract Theme Selection Team Details (Optional) GitHub Repository Prototype Demo Video Live Demo Link Evaluation Criteria: Projects will be assessed on: Problem Relevance Innovation & Originality Technical Excellence Prototype Readiness Feasibility Product Thinking Real-World Impact Presentation & Communication We look forward to discovering innovative solutions that have the potential to create meaningful impact through technology.', '2026-06-26T00:00:00+05:30', '2026-07-30T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/student-innovation-product-summit-sips-2026-iim-bangalore-1704216', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704081', 'Build in AI for India', 'About Build in AI for India Build in AI for India is a nationwide 7-day online AI hackathon bringing together students, developers, founders, researchers, and builders to create AI-powered solutions for real-world challenges across India. Participants build products that create meaningful impact in sectors such as healthcare, education, agriculture, governance, MSMEs, financial inclusion, regional languages, accessibility, and developer tools. India doesn''t need more AI demos&mdash;India needs AI products that solve real problems. This is where builders come together to ship them. Joining the WhatsApp Community is mandatory after registration, as all event communication takes place there. WhatsApp Community: https://chat.whatsapp.com/GFuzY2ahsa258q8hSiuV66 Eligibility Criteria Open to students, developers, startup founders, working professionals, and AI enthusiasts. Individual and team participation are allowed. Participants must be at least 16 years old. Teams can have up to 4 members. Hackathon Format Fully online, 7-day event. Build any AI-powered product, tool, agent, workflow, or application that solves a meaningful problem for India. No fixed problem statement&mdash;usefulness and impact are the primary focus. Access mentor sessions, founder talks, workshops, and partner resources throughout the event. Technical and Founder Sessions will be conducted on all seven days by partner founders and technology leaders. Tracks AI Agents. Voice AI. Indic and Regional Language AI. Healthcare. Agriculture. MSME Automation. Education. Government and Public Services. Financial Inclusion. Developer Tools. Timeline Day 1: Orientation and Kickoff. Day 2: Technical and Founder Session. Day 3: MVP + 4-Page Deck Submission. Day 4: Technical and Founder Session. Day 5: Technical and Founder Session. Day 6: Technical and Founder Session. Day 7: Final Project Submission. Sessions will be a maximum of 1.5 hours daily, with daily submissions and live judging. Submission Requirements Project demo video. Live product link or GitHub repository. Problem statement and solution overview. Presentation / Pitch Deck. Details of AI models, APIs, or tools used. Judging Criteria Usefulness and Impact for India &ndash; 40%. Execution and Working MVP &ndash; 30%. Innovation &ndash; 20%. Demo and Communication &ndash; 10%. Prizes and Recognition The Top 5 teams will share $35,000+ in credits and swags from partner platforms. API and Cloud Credits. Premium AI Tool Subscriptions. Exclusive Swags (T-shirts, stickers, and more). Incubation and Mentorship Opportunities. Hiring and Internship Opportunities. Certificates and Community Recognition. Perks & Benefits Mentorship from AI founders, operators, and industry experts. Technical workshops and product sessions. Access to partner API credits, cloud credits, and developer tools. Networking opportunities with startups, investors, and hiring partners. Internship, incubation, and collaboration opportunities for top teams. Confirmed Partners Slashy &ndash; AI Automation Partner. Keploy &ndash; API Testing Partner. Outlier &ndash; Education Partner. Alchemyst AI &ndash; Dev Tool Partner. Gnani.ai &ndash; Voice AI Partner. GenZDealZ.ai &ndash; Community Partner. Together, the partners are offering $35,000+ in credits and swags for the Top 5 winners. Frequently Asked Questions Is it free? Yes, participation is 100% free. Can beginners join? Yes, sessions and mentors will guide participants throughout the event. Can I participate individually or as a team? Both are allowed, with teams of up to 4 members. Is prior AI experience required? No, only curiosity and a willingness to build. Will participants receive a certificate? Yes, all participants will receive a certificate. Our Mission To build India''s highest-signal AI builder ecosystem by empowering builders to create impactful AI products that solve real-world problems and accelerate AI innovation across the country. Build. Ship. Solve for India. Contact Website: buildinai4india.com Email: hello@buildinai4india.com', '2026-06-25T19:00:37+05:30', '2026-07-06T17:30:47+05:30', 'Online', 'online', 'Top 5 winners (no fixed ranks) each receive: - Sla', 'https://unstop.com/hackathons/build-in-ai-for-india-build-in-ai-for-india-1704081', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704134', 'Port Mortem 2026 | Code Resurrection Hackathon', 'About the Hackathon: Port Mortem 2026 is a 72-hour online hackathon focused on AI-assisted software migration and cross-language code porting. Participants will rewrite a real open-source project from one programming language to another while preserving its functionality, correctness, and engineering quality. Rather than simply generating code, teams are expected to demonstrate behavioral equivalence through testing, benchmarking, and documentation. The challenge emphasizes engineering discipline, software quality, and production-ready implementations. Event website: https://coderesurrection.com/2026 Stay Updated: Join the official Hackathon Raptors Discord server for all announcements, rule clarifications, repository releases, submission instructions, FAQs, and live event support. Important updates will be communicated exclusively through Discord. You can find the Discord invite on our website: https://raptors.dev. Eligibility: Open to students, professionals, researchers, and software developers worldwide. Participants from any college, university, organization, or country are welcome. Solo participation is allowed. Teams may consist of 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization and cross-disciplinary teams are allowed. Event Format: Registration Phase: Register individually or as a team. Join the official Discord server for announcements, discussions, and support. Repository Selection: At hackathon kickoff, participants will choose a repository from a curated pool of eligible open-source projects or submit an alternative repository for approval (subject to organizer guidelines). Development Phase (72 Hours): Teams will: Port the selected project into the target programming language. Preserve the original behavior and functionality. Validate correctness using the original test suite whenever possible. Benchmark the implementation. Document architectural decisions and implementation trade-offs. Submission: Each team must submit: Public GitHub repository Build instructions Working implementation Benchmark report DECISIONS.md Differential testing/fuzzing artifacts (if applicable) Demo video Tracks: Participants may choose one of the following migration tracks: C &rarr; Rust Zig &rarr; Rust TypeScript &rarr; Go Python &rarr; Rust Go &rarr; Rust JavaScript &rarr; Go or Rust C &rarr; Zig Open Pair (Any Language &rarr; Any Language) Judging Criteria: Projects will be evaluated on: Functionality & Reliability (40%) Build quality, successful execution, and test suite compatibility. Behavioral Equivalence (30%) Accuracy of the migration, differential testing, benchmarking, and performance analysis. Code Quality (20%) Idiomatic implementation, maintainability, engineering practices, and documentation. Innovation (10%) Creative solutions, architectural improvements, and valuable enhancements. Bonus points may be awarded for: Differential fuzzing Minimal unsafe code Discovering bugs in the original project Exceptional engineering documentation Rules: Team size: 1&ndash;4 members. All development must be completed during the official 72-hour hackathon period. AI coding assistants and developer tools are permitted. The submitted repository must be public at submission time. The project must build using a single documented command. Source-language runtime wrappers or proxy implementations are not permitted. Teams should preserve the original test suite wherever feasible. Any modifications must be documented. Participants must comply with all open-source licensing requirements. Plagiarism or submission of pre-existing ports may result in disqualification. Timeline: Registration Opens: 29 June 2026 Hackathon Begins: 31 July 2026 Submission Deadline: 3 August 2026 Judging: 3&ndash;13 August 2026 Winner Announcement: 14 August 2026', '2026-06-25T00:00:00+05:30', '2026-07-31T18:00:00+05:30', 'Online', 'online', '₹ 800', 'https://unstop.com/hackathons/port-mortem-2026-code-resurrection-hackathon-hackathon-raptors-1704134', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704089', 'Anakin Blitz: Second version', '​Anakin Blitz is a fast-paced virtual hackathon designed for builders who want to ship, not just plan. In just six hours, participants will use the Wire API and Anakin Universal Scraper to create something functional, creative, and real. No fluff, no filler, just focused building. ​This isn''t a multi-day marathon with endless brainstorming sessions. It''s a tight, high-energy sprint where the constraint is the feature: six hours to go from idea to working product. Whether you''re prototyping a tool, automating a workflow, or building something nobody''s tried before, Blitz is about momentum and execution. ​The details: ​When: June 28, 2026 (Sunday), 12:00 PM to 6:00 PM IST ​What you''ll build with: Wire API and Anakin Universal Scraper Where: Discord (https://discord.gg/tDTvFPE2fw) ​The stakes: ​1st Place: Sony Headphones ​2nd and 3rd Place: 2,000 Anakin credits each ​Whether you''re a solo builder or teaming up, Anakin Blitz is your chance to test your speed, creativity, and problem-solving under pressure, and walk away with something to show for it. ​Register now and get ready to build.', '2026-06-25T17:30:00+05:30', '2026-06-28T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/anakin-blitz-second-version-anakin-skywalker-pvt-ltd-1704089', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704073', 'Ascent Quest 2026: The Ultimate Coding Challenge', 'Ascent Quest 2026 &ndash; National Level Coding Competition Think Fast. Code Smarter. Rise Higher. Ready to put your coding skills to the test? Join Ascent Quest 2026, a national-level online coding competition organized by The Ascent Circle as Episode 06 of the Summer of Skills series. Designed for aspiring programmers, competitive coders, and technology enthusiasts, this event offers an exciting opportunity to solve real coding challenges, compete with participants from across India, and earn a verified certificate while battling for exciting prizes. Whether you''re just beginning your coding journey or already experienced in competitive programming, Ascent Quest 2026 provides the perfect platform to challenge yourself, sharpen your problem-solving skills, and showcase your talent. Event Details Event: Ascent Quest 2026 Series: Summer of Skills &ndash; Episode 06 Mode: Online Platform: HackerRank Date: 5 July 2026 Time: 10:00 AM &ndash; 8:00 PM IST Participation Fee: Free Who Can Participate? School Students College Students Working Professionals Coding Enthusiasts Participants from all educational backgrounds and skill levels are welcome. Competition Format Solve coding challenges on HackerRank Multiple programming problems Difficulty Level: Beginner to Intermediate Multiple programming languages supported Live leaderboard throughout the competition Rankings based on score, accuracy, and submission time Why Participate? Compete in a national-level coding competition Solve practical programming challenges Enhance your logical thinking and coding skills Gain competitive programming experience Build your resume with a verified participation certificate Benchmark your performance against coders across India Perks & Rewards Exciting prizes for top performers Digital Certificate for every participant National-level recognition Valuable coding experience Opportunity to improve problem-solving abilities Rules Individual participation only. A stable internet connection is required. Any form of plagiarism, cheating, or unfair practices will result in immediate disqualification. The decision of the organizing team shall be final and binding. One Challenge. Countless Possibilities. Think Fast. Code Smarter. Rise Higher. Are You Ready to Take the Quest?', '2026-06-25T00:00:00+05:30', '2026-07-09T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ascent-quest-2026-the-ultimate-coding-challenge-chandigarh-university-cu-ajitgarh-punjab-1704073', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702857', 'InnoGenesis 2026 - National Level Hackathon', 'InnoGenesis 2026 is a National Level Hackathon organized by Dr. RVR NRI Institute of Technology. The event is scheduled to be held on 7&ndash;8 August 2026 and features 24 hours of non-stop innovation, bringing together talented students to build, innovate, and create impactful solutions. Event Tracks: Track 1: 24-Hour Hackathon Artificial Intelligence Machine Learning Agentic AI Robotics IoT Healthcare Sustainability Smart Energy Open Innovation Problem statements will be provided on the event day. Track 2: Prototype Exhibition & Demo Sessions Hardware Innovations AI-Based Solutions Healthcare Innovations Participants will present their own ideas and prototypes. Team Size: 2&ndash;4 members per team. Registration Fee: ₹500 per participant. Rewards & Benefits: Cash prizes worth up to ₹5 Lakhs. Certificates. Mentorship opportunities. Networking opportunities. Accommodation. Food and refreshments. Additional Highlights: Networking activities. Music sessions. Fun games. Why Participate? Gain hands-on experience through innovation and problem-solving. Collaborate with talented students from across the country. Build impactful and practical solutions. Earn national-level recognition. Connect with mentors, innovators, and industry professionals. NOTE: Kindly register through the above link only. No Need of filling all the details through unstop...', '2026-06-23T10:00:00+05:30', '2026-07-23T11:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innogenesis-2026-national-level-hackathon-dr-rvr-nri-institute-of-technology-deemed-to-be-university-1702857', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703899', 'FutureX', 'FutureX is a national-level innovation hackathon designed to challenge participants to envision life in the year 2040 through creativity, innovation, and strategic thinking. Participants will take on the role of futurists, innovators, and product visionaries to design practical, technology-driven solutions that address future challenges and improve everyday life. Objective: Encourage futuristic thinking and innovation. Develop creative problem-solving skills for real-world challenges. Explore the role of emerging technologies in shaping the future. Enhance strategic thinking, product ideation, and presentation skills. Promote sustainable and human-centric innovation. Eligibility: Open to all undergraduate students. Individual participation only. No technical or coding background is required. Competition Format: Single-round innovation hackathon. Participants will receive a future-focused problem statement at the start of the competition. Problem statements may cover areas such as: Schools & Education in 2040 Healthcare in 2040 Smart Cities of the Future Shopping & Retail in 2040 Workplaces & Offices in 2040 Transportation & Mobility Sustainable Living Solutions AI-Powered Everyday Experiences Participants will have 24 hours to analyze the problem statement and develop an innovative solution for the year 2040. Detailed problem statements and submission guidelines will be shared on the day of the competition. Important Dates: Registration Deadline: 6th June 2026, 8:00 PM Competition Start: 6th June 2026, 9:00 PM Submission Deadline: 7th June 2026, 9:00 PM Submission Details: Submission format: PPT or PDF (6&ndash;10 slides recommended). Participants must clearly present: Problem understanding Future vision and assumptions Proposed solution Technologies involved Product concept or service model User journey or workflow Expected impact and feasibility Optional prototype, mockup, storyboard, or wireframe may be included. Final submission guidelines will be shared on the day of the competition. Rules & Guidelines: Individual participation only. Original work is mandatory; plagiarism will result in disqualification. AI tools are permitted; however, solutions must reflect the participant''s own creativity, analysis, and strategic thinking. Late submissions will not be accepted. Participants must ensure clarity, practicality, and proper justification of their future vision and proposed solution. The decision of the organizing team will be final and binding.', '2026-06-25T00:00:00+05:30', '2026-07-05T20:00:00+05:30', 'Online', 'online', 'Opportunity to work with AI Academia', 'https://unstop.com/hackathons/futurex-ai-academia-1703899', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702474', 'Women Who Master', 'Women Who Master 2026 is a national-level all-women hackathon designed to bring together aspiring innovators, problem-solvers, and future technology leaders from across India. The hackathon provides participants with an opportunity to showcase their creativity, collaborate with peers, solve challenging problems, and compete for exciting rewards, mentorship opportunities, and national recognition. Whether you''re a beginner or an experienced builder, this platform is open to women from all academic disciplines who are ready to innovate and make an impact. Eligibility: Women students across all disciplines and academic backgrounds, including 2026 graduates, are eligible to participate. Participants must register individually during the registration phase. Rules and Guidelines: Only candidates who complete the registration form will be eligible to attempt the assessment on 25th July 2026. Post the MCQ round, shortlisted candidates will be grouped into teams of 5 members for the subsequent rounds. Team formation will be done college-wise based on participants&rsquo; accuracy and speed in the MCQ Assessment. In cases where there are insufficient participants from a particular college, teams will be formed zone-wise. Participants will not be allowed to create or modify teams. All decisions pertaining to eligibility, shortlisting, team formation, and progression in the competition will be made by Aspire For Her and Unstop, and their decision shall be final and binding.* The MCQ assessment will be available on the scheduled date and time. Participants are encouraged to attempt the assessment within this window, as access to the platform is subject to system conditions and may not remain uniformly available for all users throughout the duration. Competition Structure: Round 1: Registration: This is the first step in your Aspire For Her journey! Complete your registration by 21st July 2026 to secure your participation. Only candidates with completed registrations will be eligible to take the assessment on 25th July 2026. Round 2: Online MCQ Assessment: Participants will be required to attempt 30 MCQs in 30 minutes. The assessment will cover Artificial Intelligence (AI) and Machine Learning (ML)   You don''t need prior experience in AI/ML to participate; curiosity, creativity, and a growth mindset are all you need. Round 3: Zonal Rounds: Based on performance in the MCQ assessment, shortlisted participants will qualify for the zonal rounds. Hackathon problem statements will be shared 48 hours in advance. Teams can use this time to collaborate, research, and develop their initial solutions. On the day of the event, they will have the opportunity to reassess their approach, consult with mentors, and refine their submissions based on the feedback and guidance from the mentors.  Participants will become part of the Women Who Master community, with access to ongoing learning resources including hackathon prep materials, hackathon mini challenges, mentorship, career opportunities, and community support beyond the hackathon: https://aspireforher.com/community/women-who-master/ Zonal Round Format: Participants will be grouped into teams of 5 members. Teams will compete across different zones - North (Delhi), South (Bengaluru), East (Kolkata), and West (Mumbai). Each team will receive the problem statement at least 48 hours prior to their respective zonal round. Teams will have to curate their solution and present it before the Aspire for Her Jury during the in-person Zonal Rounds. Note: For the Zonal Round, participants will be assigned to the zone closest to their location and will be responsible for arranging their own travel. Round 4: Grand Finale: The top-performing teams from the Zonal Rounds will advance to the Grand Finale at the Logitech Headquarters in Chennai, where they will work on a new problem statement, receive mentorship from industry experts, and present their solutions before a distinguished jury. The Grand Finale will be held at the Logitech office in Chennai. A new problem statement will be shared with qualifying teams 48 hours before the event. Teams will have the opportunity to refine their solutions with guidance and mentorship from industry experts. Final presentations will be evaluated by a prestigious jury comprising leaders from Logitech and Aspire For Her (AFH). A fixed allowance will be provided to all Grand Finale participants attending the finale. Rewards and Prizes: Pre-Placement interview opportunities with Logitech The Winning team will receive a prize worth INR 1,00,000/-* The First Runners-Up team will receive a prize worth INR 75,000/-* The Second Runners-Up team will receive a prize worth INR 50,000/-* Chance to connect with Logitech''s Talent Acquisition team and explore exciting future career opportunities. Exclusive mentorship from the Logitech leaders Participation Certificates will be awarded to all participants who appeared for the MCQ Round Merit Certificates for all winners, grand finale participants and zonal participants Fixed allowance for all Grand Finale participants Opportunity to showcase AI-powered solutions on a national stage at Logitech HQ, Chennai along with recognition by Logitech leaders Please refer to the FAQs for more details, including the T&Cs applicable to the program.', '2026-06-22T14:00:00+05:30', '2026-09-10T17:30:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/crp-women-who-master-aspire-for-her-x-logitech-1702474', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703568', 'AI Alliance Forge 2026', 'About AI Alliance Forge 2026 AI Alliance Forge 2026 is an online coding challenge hosted by the Apex Institute of Technology, Chandigarh University. The event is designed to bring together bright minds to explore and innovate within the rapidly evolving field of Artificial Intelligence. Participants will engage in a dynamic online environment, showcasing their coding prowess and problem-solving skills. This challenge offers a unique platform to contribute to the AI landscape and gain valuable experience in a collaborative setting. Themes / Problem Statements Exact problem statements will be revealed to participants during the event. The challenge focuses on: Innovation in Artificial Intelligence. Eligibility and Registration Open to participants engaging in team participation. Competition Structure No specific competition structure details were provided. Rewards and Prizes No specific prize details were provided. Why Participate? Explore emerging opportunities in Artificial Intelligence. Showcase coding and problem-solving skills. Gain hands-on experience in a collaborative online environment. Contribute to shaping the future of AI. Organized By Apex Institute of Technology, Chandigarh University. Closing Note Join AI Alliance Forge 2026 and be a part of shaping the future of AI.', '2026-06-24T16:00:00+05:30', '2026-07-31T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-alliance-forge-2026-apex-institute-of-technology-chandigarh-university-1703568', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703493', 'Heritage to Horizon: A 24hrs Ideathon', 'A 24-hour ideathon inspired by groundbreaking historical inventions created by women. Participants draw inspiration from these inventions and transform their core ideas into innovative, technology-driven solutions for today&rsquo;s challenges through creativity and innovation. Event Details: Date: 3rd&ndash;4th July 2026 Mode: Online Duration: 24 Hours Participation Size: 1&ndash;4 members Eligibility: Open to all students Timeline: 3rd July, 3:00 PM: Problem statements/tracks released and ideation begins 4th July, 1:00 PM: PPT submission deadline 4th July, 1:30 PM onwards: Final presentations and judging Themes/Problem Statement: Participants will be provided with tracks inspired by groundbreaking inventions created by women Teams must transform the core idea behind these inventions into innovative, technology-driven solutions addressing modern-day challenges. Problem statements will be released soon. Guidelines: Each team must consist of 1&ndash;4 members At least one female participant is mandatory in every team All submissions must be original and free from plagiarism', '2026-06-24T00:00:00+05:30', '2026-07-04T15:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exci', 'https://unstop.com/hackathons/heritage-to-horizon-wie-week-20-guru-tegh-bahadur-institute-of-technology-gtbit-new-delhi-1703493', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703362', 'IKIGAI 2026', 'IKIGAI 2026 &ndash; National Level Hackathon IKIGAI 2026 is a premier national-level hackathon designed to bring together innovative minds, developers, designers, and problem-solvers from across the country to collaborate, innovate, and build impactful technology-driven solutions. The event aims to foster creativity, inclusivity, and the practical application of emerging technologies while encouraging participants to solve real-world challenges through innovation and teamwork. Eligibility Guidelines Open to all Undergraduate, Postgraduate, Diploma students, and recent graduates from recognized institutions. Participants from all academic disciplines are welcome. Inter-college teams are allowed. Inter-specialization teams are allowed. Team Size: 2&ndash;4 Members Each team must mandatorily include at least one female participant. A participant can be a member of only one team. Hackathon Tracks Participants may build projects under any of the following tracks: Sports Analytics & Artificial Intelligence CPS Powered Smart Agriculture Cyber Security & Privacy Industry 5.0 & Intelligent Automation Smart Healthcare Social Innovation & Digital Governance Hackathon Format Round 1: Online Idea Submission & Evaluation All registered teams will participate in the online evaluation round. Teams will be required to submit: Problem Statement Proposed Solution Technology Stack Project Overview Submissions will be evaluated based on innovation, feasibility, impact, and alignment with the selected track. Screening & Shortlisting Following the online evaluation, submissions will undergo a screening process by industry experts and mentors. Teams demonstrating strong problem-solving capabilities, innovation, and execution potential will be shortlisted for the Offline Grand Finale. Round 2: Offline Grand Finale Duration: 36 Hours Dates: 21&ndash;23 August 2026 Shortlisted teams will participate in an intensive 36-hour hackathon where they will design, develop, and present their solutions before a panel of judges and industry experts. Prize Pool Total Prize Pool: ₹1,03,000 Exciting cash prizes, certificates, recognition, and networking opportunities await the top-performing teams. Submission Requirements Teams must submit: Source Code Repository (GitHub or equivalent) Project Documentation Project Presentation/Pitch Deck Demo Video (if applicable) Deployed Application Link (if applicable) Judging Criteria Projects will be evaluated on: Innovation & Creativity Technical Excellence Problem Relevance Scalability & Feasibility User Experience & Design Presentation & Demonstration Overall Impact Participant Guidelines Every participant must carry: Valid College ID Card Government-Issued Photo ID Personal Laptop Laptop Charger Extension Board (Recommended) Headphones/Earphones (Recommended) Participants are responsible for bringing all hardware and accessories required for development. Rules & Regulations Teams must primarily build their solution during the hackathon duration. Open-source libraries, frameworks, APIs, and AI tools may be used. Plagiarism or submission of previously developed projects will lead to immediate disqualification. Participants must maintain professional conduct throughout the event. Any form of harassment, discrimination, or misconduct will result in immediate removal from the hackathon. Decisions made by the organizing committee and judging panel shall be final and binding. Organizers reserve the right to modify schedules, rules, or judging criteria if required due to unforeseen circumstances. By participating, teams consent to photography, videography, and promotional use of event media. Registration fees are non-refundable if your team is not shortlisted after Round 1 (Online Idea Submission & Evaluation). Why Participate? Compete with talented innovators from across the country. Gain mentorship from industry professionals. Build impactful solutions for real-world challenges. Network with developers, founders, and technology enthusiasts. Showcase your skills on a national platform. Win exciting prizes and recognition. Our Mission IKIGAI 2026 is more than just a hackathon&mdash;it is a platform where innovation meets purpose. We aim to empower the next generation of creators, thinkers, and builders by providing an environment that encourages collaboration, learning, and impactful problem-solving. Website Link: https://ikigai-csit.netlify.app WhatsApp Community: https://chat.whatsapp.com/JEQE5xMKb2pIP7JErhurhK?s=cl&p=a&ilr=2 Instagram Handle: https://instagram.com/ikigai_aitr Participants are strongly encouraged to join the official WhatsApp community to receive important announcements, event updates, queries, schedules, and support throughout the hackathon. For complete event details, registration updates, timelines, and announcements, please visit the official IKIGAI 2026 website. For any queries or support, you can email us at: acroikigai@acropolis.in You can also join our official WhatsApp Community and post your query there. Our team will be happy to assist you. Build. Innovate. Transform.', '2026-06-24T00:00:00+05:30', '2026-08-23T00:00:00+05:30', 'Online', 'online', '₹ 1,03,000', 'https://unstop.com/hackathons/ikigai-2026-acropolis-institute-of-technology-and-research-indore-1703362', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703244', 'Agent-A-Thon NCR Marketing Challenge', 'About the Challenge The Agent-A-Thon NCR Marketing Challenge is a two-day competition by Nerds Room designed to identify and reward creators, storytellers, community builders, and growth enthusiasts who can effectively spread awareness about Agent-A-Thon NCR and the mission behind Nerds Room. Over two rounds, participants will create and publish content across platforms such as LinkedIn, Reddit, and Quora, competing to generate the highest engagement, spark meaningful conversations, and bring new people into the community. This challenge is not about who has the biggest audience&mdash;it&rsquo;s about who can create the most impact through creativity, storytelling, and authentic community engagement. Round 1: Agent-A-Thon Awareness Challenge Date: 24 June Time: 12:00 AM &ndash; 11:59 PM IST Your mission is to introduce Agent-A-Thon NCR to the world. Create content that explains: What the event is. Why people should participate. What attendees can expect. Why AI builders, students, developers, and innovators should be excited about it. Participants are encouraged to: Share the registration link. Engage with other creators. Help amplify the reach of the challenge through meaningful interactions. Round 2: Nerds Room Storytelling Challenge Date: 25 June Time: 12:00 AM &ndash; 11:59 PM IST Great communities are built through stories. In this round, participants will: Showcase the vision, impact, and opportunities created by Nerds Room. Share what makes the community unique. Highlight its initiatives. Discuss upcoming programs and hackathons. Connect the larger mission of Nerds Room with Agent-A-Thon NCR and future community-led innovation. Allowed Platforms LinkedIn Reddit Quora Submission Platform Unstop Community Group Join the challenge WhatsApp group for updates, announcements, networking, and discussions. Participants must submit the links to their published posts along with screenshots of engagement and analytics through Unstop before the submission deadline for each round. What We''re Looking For Creative storytelling High-quality content Meaningful engagement Community building efforts Organic reach and impact Collaboration with fellow participants Rewards Top 3 Winners will receive: ₹500 Cash Prize each Official Certificate of Achievement Letter of Recommendation from Nerds Room Who Should Participate? Content Creators Marketers Student Leaders Founders Builders Anyone passionate about growing communities Why Participate? Demonstrate your ability to create impact at scale. Build your personal brand. Tell compelling stories. Create meaningful engagement. Help make Agent-A-Thon NCR one of the most talked-about community-driven AI events in the region.', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agent-a-thon-ncr-marketing-challenge-vishveshwarya-group-of-institutions-vgi-greater-noida-uttar-pradesh-1703244', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695117', 'The Black-Box Protocol: Stage 01 - "System Escalation"', 'Phase 1 // Stage 01: SYSTEM ESCALATION The Black-Box Protocol &mdash; Gwalior ️ THE "48-HOUR HACKATHON MIRAGE" IS DEAD. Every single day, dozens of conventional hackathons take place across the country. Thousands of developers write rushed, unstructured code over a weekend, claim prizes, pack up, and abandon their repositories forever. This is the Mirage. High-value cloud resources are burned, sponsor APIs are temporarily activated, and developer retention drops to absolute zero. An estimate 98% of hackathon projects are abandoned immediately after the closing ceremony. The Black-Box Protocol is explicitly engineered to smash this cycle. We are introducing an interconnected, campaign-driven technical universe where products don''t die&mdash;they undergo structural incubation. Just like a cinematic universe, your progress in Stage 01 carries directly into subsequent stages, culminating in the Singularity Protocol (Stage 05) and final market scaling. Welcome to Stage 01 // "System Escalation"&mdash;the genesis node focusing on the absolute convergence of autonomous AI agents and decentralized Web3 ledger technology. Are you ready to build systems that survive? For More Updates, join WhatsApp group ️ THE 2-ROUND HYBRID ARCHITECTURE & EXECUTION MODEL To ensure an uncompromised signal-to-noise ratio, we are implementing a strict, multi-stage gatekeeper pipeline. To survive the protocol and reach the Gwalior finale, your team must clear both phases.  ROUND 01 // REGISTRATION & SYSTEM ARCHITECTURE SCREENING (ONLINE) Round 1 Timeline: June 05 &ndash; July 12, 2026 Registration Window: June 15 &ndash; July 5, 2026 System Blueprint Submission (PPT/Abstract): Open until July 5, 2026 The HiDevs Skill Test Window: July 6 &ndash; July 10, 2026 Results Declaration & Access Codes Release: July 12, 2026 Round 01 Execution Model (Step-by-Step): The Portal Onboarding (Open until July 5, 2026) Register your team (consisting of 2-4 developers) on Luma. Provide active GitHub profiles and select your core technical domains (AI orchestration, smart contracts, or UI/system architecture). The Blueprint Design (Due July 5, 2026) Shortlisted teams will gain access to the submission portal. You must submit a rigorous $6$-slide system architecture blueprint (PPT/PDF) detailing the following: Problem Statement & Proposed Use Case. Technical architecture diagram mapping the precise data flow between your autonomous AI agent and the layer-1 blockchain. Proposed sponsor tool integration and API/SDK deployment logic. The HiDevs Skill Gatekeeper (July 6 &ndash; July 10, 2026) All registered team developers must complete a mandatory 60-minute technical challenge hosted directly on the HiDevs Platform to evaluate actual coding competence, backend structuring, and deployment capability. Core Syllabus Tracks: Gen AI Products, Reliability & Monitoring, Cost & Latency Optimization. Focus Areas: System Design Questions, Scenario-Based Problem Solving, Architecture Analysis, GenAI Infrastructure Concepts, and Production Deployment Challenges. Objective: To verify each participant''s ability to design, optimize, monitor, and scale real-world GenAI applications beyond simple prototypes. Performance scores will contribute directly to the Round 01 selection process. The Core Filter (July 10 &ndash; July 11, 2026) Our technical division will audit every blueprint submission and challenge score. We evaluate: Originality Logic Validity Technical Depth System Design Quality Execution Potential Note: Plagiarized projects, low-intent AI wrappers, or technically invalid architectures will be eliminated immediately. Access Codes Release (July 12, 2026) Only the top 50-60 teams will receive physical terminal clearance codes to enter the Gwalior build arena.  ROUND 02 // THE TERMINAL LOCKDOWN (12-HOUR OFFLINE FINALE) Round 2 Date: July 26, 2026 Location: Gwalior, Madhya Pradesh (with synchronized hybrid/remote channels for global teams) Format: A strict, non-stop $12$-hour continuous physical hacking sprint. Round 02 Execution Model (Step-by-Step): Hour 00: Deployment & Gating Selected teams arrive at the Gwalior physical hub. Outstation participants gain access to designated storage and preparation areas for their equipment and belongings. Hour 01: The Network Ignition Teams connect to the central coding arena. Each team receives dedicated power access and uninterrupted high-speed connectivity. Hours 01-06: The Terminal Lockdown A continuous, high-pressure hacking window. Teams must live-code, test, and deploy their MVPs. No Slide Preparation Allowed. Teams must focus entirely on building, testing, and deployment. Mandatory Stack Integration: Projects must actively execute sponsor APIs, AI workflows, cloud infrastructure, or blockchain smart contracts. Hour 06: The System Recharge Dedicated lunch, snacks, beverages, and hydration stations will remain available to sustain active builders. Hour 08: The Submission Protocol (Final Hour) All teams must submit their final working repositories. Submissions require: GitHub Repository with verified commit history. Live Demo Link. Technical Documentation. Sponsor Integration Details. Hour 09-11: The Live-Execution Jury No dry pitching. Evaluation is based strictly on live execution. Teams must demonstrate a functional MVP, autonomous AI workflows, smart contract executions, and real-time transaction logs.  THE VALUE MATRIX (WHAT IS IN THE BOX?) Incentive Pool: Up to 50K+ in developer bounty pools, cash prizes, sponsor rewards, and hardware incentives. Continuous Incubation: Access to a 6-12 month post-event support pipeline connecting viable projects directly with mentors, accelerators, investors, and ecosystem partners. Expert Mentorship: Real-time architecture reviews, technical guidance, and execution-focused triage support from industry specialists during the live build.  REGISTRATION COMPLIANCE RULES Repository Integrity: All code must be initialized and systematically committed during active round windows. Pre-existing, copy-pasted, or white-labeled projects will trigger immediate disqualification. Mandatory Convergence: Projects must functionalize both domains. An AI wrapper without Web3 trust, or a Web3 contract without autonomous AI capabilities, will not pass Round 01. Strict Gatekeeping: Registrations are limited and subject to manual review. Ensure all submitted team details and profile links are completely accurate. Stop building throwaway apps. Start building persistent systems. Welcome to the Black-Box Protocol.   Presented by TECHhelp4U&mdash;Where Creativity Meets Talent, Founder Vedansh Goyal Central India''s ultimate launchpad where code meets culture and students evolve into creators. By fueling experiential learning and real-world challenges, we empower the next generation of tech disruptors to architect the future.', '2026-06-06T00:00:00+05:30', '2026-07-25T22:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/the-black-box-protocol-stage-01-samrat-ashok-technological-institute-sati-vidisha-1695117', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703222', 'Code. Innovate. Impact', 'What You''ll Gain: Certificates for Participants & Winners Knowledge Enhancement Networking with Like-Minded Students Skill Development & Recognition Opportunity to Join the CodeForge Community Event Highlights: Multiple-choice quiz format Beginner-friendly Open to all students Time-based competition Fair evaluation process', '2026-06-23T00:00:00+05:30', '2026-08-09T23:59:00+05:30', 'Online', 'online', 'Certificate of Excellence, Featured on CodeForge''', 'https://unstop.com/hackathons/code-innovate-impact-iit-bombay-1703222', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703153', 'The Closer Challenge - Pitch. Convince. Win.', 'Think you can sell ice to a penguin? Welcome to The Closer Challenge&trade;, a real-world sales simulation designed to test your communication, negotiation, persuasion, and problem-solving skills. Participants will be assigned different products and customer personas. Your mission is simple: understand the customer''s needs, overcome objections, negotiate effectively, and close the sale. This isn''t about memorizing scripts. It''s about thinking on your feet, building trust, and creating value through powerful conversations. What You''ll Experience: Live Sales Simulations Customer Handling & Objection Management Negotiation & Persuasion Challenges Real-Time Sales Targets Leaderboards & Performance Rankings Challenge Format: Participants will pitch products to multiple customers. Each successful sale contributes toward their sales score. Different customers will have different requirements, objections, and budgets. Participants must use their convincing and negotiation skills to achieve sales targets. The Goal: Reach the required sales threshold and prove that you can close deals like a professional. Rewards: Internship Opportunities Full-Time Job Offers (for exceptional performers) Certificate of Achievement Direct Exposure to Industry Professionals', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/the-closer-challenge-pitch-convince-win-yai-infraventure-1703153', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702893', 'Agentic AI Hackahton', 'This is a build-focused AI hackathon designed for makers, developers, students, and professionals who want to create and launch a real AI-powered product within a weekend. What You''ll Build: Over two intensive days, participants will transform an idea into a working AI application by: Discovering and validating a real-world problem. Designing the product and technical workflow. Building AI-powered features using modern tools and frameworks. Integrating APIs, agents, and external services. Testing, refining, and presenting a functional solution. The challenge is centered around Agentic AI Systems that can: Reason and make decisions. Use tools and external resources. Automate workflows and complete tasks. Operate with minimal human intervention. By the end of the Buildathon, you''ll have a working project that can be showcased in your portfolio, demonstrated during interviews, or further developed into a real product. Who Can Participate? Individuals and teams are welcome. Recommended team size: Up to 2 members. Beginners and experienced builders can participate. Participants may use AI tools, APIs, SDKs, and open-source frameworks. Project Requirements: Every team must: Build their solution during the event duration. Maintain clear documentation of their development process. Explain the problem statement, approach, architecture, and implementation. Submit a functional prototype or live product demonstration. Submission Checklist: To complete your submission, provide: A live demo or recorded product walkthrough. Source code repository (GitHub or equivalent). Brief project overview and architecture explanation. Details about the tools, models, and technologies used. Rules & Judging Criteria: Event Rules: Pre-built end-to-end projects are not permitted. Starter templates, boilerplates, and open-source libraries are allowed. Any form of plagiarism or unauthorized copying will result in immediate disqualification. Teams must disclose the use of AI-generated code, content, or assets. Only fully functional submissions will be considered for evaluation. All entries must be submitted before the official deadline. Evaluation Areas: Projects will be assessed based on: Innovation and originality. Problem-solving impact. Technical implementation. Product usability and user experience. Quality of the AI agent workflow. Completeness of the final solution. Build fast, experiment boldly, and turn your idea into a real AI product.', '2026-06-23T00:00:00+05:30', '2026-07-12T14:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agentic-ai-hackahton-gradient-1702893', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701580', 'TNX Codathon', 'Overview: TNX Codathon 2K26 is a 24-hour national-level offline hackathon organized by TechNeekX, bringing together developers, innovators, designers, AI enthusiasts, and startup builders from across India to solve real-world challenges through technology and innovation. Participants will collaborate in teams to build impactful solutions across multiple domains while receiving mentorship, technical guidance, networking opportunities, and evaluation support from industry experts and experienced professionals. Eligibility: Open to undergraduate, postgraduate, and diploma students from recognized institutions. Students from all academic disciplines are eligible. Inter-college teams are allowed. Cross-specialization teams are allowed. Participants must carry a valid student ID during the event. Team Size: Minimum: 1 Members Maximum: 5 Members Solo participation is not permitted.Join Participation Group: click here to join TRACKS & PPT TEMPLATE : Click here to download Hackathon Tracks: Participants may choose from the following tracks: Artificial Intelligence & Machine Learning Healthcare Technology FinTech & Smart Automation Sustainability & Green Innovation Smart City Solutions Cybersecurity Web & Mobile Applications Open Innovation Competition Format: Round 1: Shortlisting & PPT Round Applications may undergo screening based on team profile, idea quality, innovation potential, and technical feasibility. Round 2 : Shortlisting & Online Hackathon Applications may undergo screening based on team profile, idea quality, innovation potential, and technical feasibility. Final Round : Offline Hackathon Selected teams will participate in a 24-hour offline hackathon where they will build and present their solutions. Activities include: Opening Ceremony Team Workspace Allocation Mentorship Sessions Mid-Evaluation Checkpoints Technical Reviews Final Submission Live Demonstrations Jury Evaluation Closing Ceremony & Results Judging Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Implementation Problem-Solution Fit Scalability User Experience Business & Social Impact Presentation & Demonstration Quality Rules: All submitted work must be developed during the hackathon period. Plagiarism will result in immediate disqualification. Teams must comply with event guidelines and code of conduct. Open-source libraries and APIs may be used where permitted. Participants are responsible for their own devices and equipment. Any form of misconduct, cheating, or unethical behavior will lead to disqualification. Judges'' decisions will be final and binding. Organizers reserve the right to modify schedules or rules if required. Participants must submit all required deliverables before the deadline. Team members must remain registered with their original team throughout the competition. What Participants Get: National-Level Exposure Industry Mentorship Networking Opportunities Certificates of Participation Exciting Prizes & Rewards Internship Opportunities Recognition Across the Innovation Ecosystem Access to the TechNeekX Community Event Duration: 24-Hour Offline Hackathon', '2026-06-23T00:00:00+05:30', '2026-08-09T17:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/tnx-codathon-techneekx-1701580', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703194', 'The Cypher Trail', 'An immersive, Among Us themed technical challenge where participants step into the role of crewmates aboard a sabotaged spaceship. Through missions involving Artificial Intelligence, Cybersecurity, Programming, Networking, and Digital Investigation, they must solve challenges, uncover hidden clues, identify the impostor, and restore the ship&rsquo;s systems.  Event Details: Date: 1st July, 2026 Time: 4PM-6PM Duration: 2hrs Mode: Online Team size: Individual Number of rounds: 5 Eligibility: Open to all  Coding Languages: Python, Java, C/C++ Laptops are mandatory. Rules: No AI, No Cheating: Use of AI tools or help from others is prohibited. Level by Level: You must solve each level to move to the next. Race Against Time: The fastest participant to finish wins.', '2026-06-23T00:00:00+05:30', '2026-06-30T20:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exci', 'https://unstop.com/hackathons/the-cipher-trail-wie-week-20-institute-of-electrical-and-electronics-engineers-gtbit-1703194', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703189', 'Creative Lens', 'A creative advertising challenge where participants transform an already existing product with an innovative technological feature and present it through either an advertisement poster or a promotional video, showcasing creativity, storytelling, and marketing skills. Event Details: Date: 2nd July 2026 Time: 12:00 PM &ndash; 4:00 PM Duration: 4 Hours Mode: Online Participation Size: Individual Participation Eligibility: Open to All Students Domains: Women&rsquo;s Health & FemTech Safety & Personal Security Smart Wearables Career & Productivity Tech Lifestyle Innovation Guidelines: The submitted video must be 30&ndash;60 seconds in duration. Accepted Formats: Video &ndash; MP4 | Poster &ndash; PDF, PNG, JPG/JPEG. AI-generated videos or AI-generated artwork are strictly prohibited and will lead to immediate disqualification. Ensure that the submission is clear, original, and adheres to the event theme and rules. Any submission found to violate the guidelines may be rejected at the discretion of the organizing team.', '2026-06-23T00:00:00+05:30', '2026-07-01T20:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exci', 'https://unstop.com/hackathons/creative-lens-wie-week-20-guru-tegh-bahadur-institute-of-technology-gtbit-new-delhi-1703189', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702966', 'BrandVerse 2026: India''s Startup Branding & AI Innovation Challenge', 'About the Challenge: BrandVerse 2026 is a national-level innovation hackathon designed to bring together creative minds, problem solvers, aspiring entrepreneurs, developers, designers, marketers, and technology enthusiasts from across India. The challenge aims to encourage participants to develop innovative solutions that address real-world business, branding, technology, sustainability, education, and artificial intelligence challenges. Participants will have the opportunity to showcase their creativity, technical expertise, strategic thinking, and entrepreneurial mindset while competing with talented students from leading institutions. This competition provides a platform for students to gain practical experience, enhance their problem-solving abilities, collaborate with like-minded peers, and present impactful ideas that can create meaningful change. Themes: Participants can choose to build solutions in any of the following domains: Artificial Intelligence & Machine Learning AI-powered assistants Computer vision applications Natural language processing solutions Predictive analytics systems Automation tools Branding & Marketing Innovation Customer engagement platforms Digital branding solutions Marketing automation tools Community growth platforms Creator economy solutions Startup & Business Solutions Business process automation CRM and productivity systems SaaS products Customer acquisition solutions Sales intelligence tools Education Technology Learning management systems Student productivity applications Skill development platforms Career guidance solutions Sustainability & Social Impact Environmental solutions Waste management innovations Renewable energy technologies Community development initiatives Open Innovation Participants are free to submit innovative projects outside the listed categories if they solve a significant real-world problem. Eligibility: Open to all undergraduate and postgraduate students across India. Students from any stream, specialization, or academic discipline may participate. Individual participation is allowed. Team participation is allowed. Team size: 1 to 4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. Competition Format: Round 1: Idea Submission Participants must submit: Problem Statement Proposed Solution Unique Value Proposition Expected Impact Brief Implementation Plan Shortlisted teams will move to the next round. Round 2: Prototype Development Qualified participants must develop and submit: Working Prototype or MVP Project Presentation Deck Solution Documentation Demo Video (Optional) Round 3: Final Evaluation Finalists will present their projects before the evaluation panel. The presentation should include: Problem Identification Solution Overview Technical Architecture Business Impact Future Scope Live Demonstration (if applicable) Evaluation Criteria: Projects will be evaluated based on: Criteria Weightage Innovation & Creativity 25% Problem Solving Ability 25% Technical Implementation 20% Business & Social Impact 15% Presentation & Communication 15% Submission Guidelines: Participants must ensure that: All submitted work is original. Solutions should address a clearly defined problem. Projects must include adequate documentation. Teams should clearly explain the practical impact of their solution. Submissions must be completed before the deadline. Participants may use any technology stack, programming language, framework, or design tool. Rewards & Recognition: Winner: Certificate of Excellence Winner Recognition Runner-Up: Certificate of Achievement Runner-Up Recognition All Participants: Digital Participation Certificate Networking Opportunities Industry Exposure Skill Development Experience Important Dates: Participants are advised to complete registration before the deadline and regularly check the platform for updates regarding submissions, evaluations, and announcements. Rules & Regulations: The competition is open only to currently enrolled students. Participants may register individually or as a team. Team size cannot exceed four members. Inter-college and inter-specialization teams are permitted. All submissions must be original and created by the participants. Any form of plagiarism will result in immediate disqualification. Multiple submissions of the same project are not allowed. Organizers reserve the right to verify participant information. The decision of the evaluation panel shall be final and binding. Organizers reserve the right to modify schedules, timelines, and evaluation procedures if required. Why Participate? Showcase your skills on a national platform Build innovative solutions for real-world problems Gain recognition among peers and industry professionals Strengthen your portfolio and resume Collaborate with talented students from across India Enhance your problem-solving, technical, and entrepreneurial abilities Join BrandVerse 2026 and transform your ideas into impactful innovations!', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/brandverse-2026-indias-startup-branding-ai-innovation-challenge-printila-services-private-limited-1702966', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702501', 'Nexus: Where Prompts Become Products', 'Promptathon 2026 is a national-level AI Prompt Engineering Challenge where participants transform innovative ideas into AI-generated prototypes using the power of prompt engineering. Participants are required to submit both the prompt(s) used and the AI-generated prototype image(s) showcasing their solution. The challenge evaluates creativity, prompt design, problem-solving ability, and the effectiveness of AI-generated outputs. Whether you''re building a futuristic product, solving a real-world problem, or designing the next big innovation, Promptathon provides the perfect platform to demonstrate your AI creativity and technical thinking. Submission Requirements AI-generated Prototype Image(s) -- Minimum 3 images of the prototypeComplete Prompt(s) Used to Generate the PrototypeBrief Description of the Idea  Judging Criteria Prompt Quality & Creativity Innovation & Originality Prototype Design & Visual Impact Problem-Solving Approach Feasibility & Practical Application Prompt Today. Innovate Tomorrow.', '2026-06-22T00:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate of Recognition for top 3 submission', 'https://unstop.com/hackathons/nexus-where-prompts-become-products-techverse-solutions-1702501', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702687', 'Forge 6', 'Date: 18 August 2026Venue: NMG Technologies, GurugramFormat: Solo or Team of up to 3 The next wave of AI will not be built for chatbots. It will be built for factories. Forge 6 is an Industrial AI Hackathon organized by NMG Labs in association with Maruti Suzuki, bringing together students, engineers, AI builders, and innovators to solve real manufacturing challenges using Artificial Intelligence. Manufacturing, automotive, supply chain, quality control, procurement, logistics, and industrial operations are undergoing one of the biggest technology transformations in decades. Organizations are actively searching for AI systems that can reduce defects, improve quality, optimize inventory, automate compliance, predict disruptions, and increase productivity on the shopfloor. This is your opportunity to build those systems. Participants will develop working AI prototypes inspired by high-impact industrial use cases prioritized by the manufacturing sector. The best solutions will demonstrate how AI can create measurable business value across automotive and industrial operations. Challenge Tracks: Choose from multiple industrial AI problem statements, including: AI-powered Defect Detection & Quality Inspection Quality Documentation Co-Pilots Cost Estimation & Localization Intelligence Workplace Safety & Vision Analytics Inventory & Supply Chain Optimization Supplier Risk Prediction Sustainability & Carbon Intelligence Agentic AI for Manufacturing Operations Technology Areas: Computer Vision Machine Learning Generative AI Agentic AI Systems Predictive Analytics Industrial Automation RAG & Knowledge Systems Supply Chain Intelligence Why Forge 6? Build AI solutions inspired by real manufacturing challenges Gain exposure to industrial and automotive workflows Learn how AI is transforming factory operations Showcase your work to industry leaders and engineering professionals Build a portfolio project with real-world business relevance Earn recognition, prizes, and career opportunities through NMG Labs Judging Criteria: Working Prototype Industrial Impact AI & Technical Excellence Real-World Applicability Production Readiness Presentation & Storytelling Eligibility: Open to students and recent graduates from Engineering, Computer Science, Artificial Intelligence, Data Science, Mechanical, Production, Manufacturing, Mechatronics, Industrial Engineering, and related disciplines. Team Size: Individual Participation Teams of up to 3 Members Theme: Participants will receive challenge statements and datasets on sprint day and will have approximately 6&ndash;7 hours to build and demonstrate their solution. The future of manufacturing will be powered by AI. Forge 6 is where builders take the first step toward creating it.', '2026-06-22T00:00:00+05:30', '2026-08-15T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-6-nmg-technologies-1702687', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702556', 'Forge 3', 'Forge 3 is India''s first AI-powered creative production sprint designed for creators, designers, filmmakers, motion artists, social media creators, advertisers, and digital storytellers. While traditional hackathons focus on building software, Forge 3 challenges participants to build creative experiences. In just six hours, you''ll operate a complete creative studio from your laptop, using cutting-edge AI tools to produce a portfolio-grade creative asset. Participants can compete individually or in teams of up to three members and choose from seven challenge tracks, including AI Brand Films, UI/UX Prototyping, Social Media Campaigns, Ad Creative Production, VFX Innovation, AI Brand Avatars, and Integrated Multi-Channel Campaigns. The exact client brief will be revealed on sprint day. Your mission is to transform that brief into a finished creative deliverable using modern AI tools such as Higgsfield, Google Flow (Veo + Nano Banana), Figma, Runway, Midjourney, ElevenLabs, Suno, Adobe Firefly, Meta Edits, and more. What You''ll Build: Cinematic AI-generated brand films Clickable product prototypes Social media campaigns High-converting ad creatives Advanced VFX shots AI spokesperson avatars Integrated cross-platform creative campaigns Judging Criteria: Creativity & Originality (25%) Craft & Technical Execution (20%) Storytelling & Communication (15%) Effective Use of AI Tools (15%) Brand Fit & Brief Relevance (15%) Presentation & Process (10%) Why Participate? Create a real portfolio-worthy project in a single day Learn industry-leading creative AI workflows Network with creators, mentors, and industry professionals Compete for cash prizes, certificates, and exclusive opportunities Earn consideration for creative roles and internships at NMG Eligibility: Open to students and recent graduates from design, animation, VFX, advertising, visual communication, media, creative technology, and related disciplines. Exceptional creators from other backgrounds are also encouraged to apply. Team Size: Solo Participation Theme: The official creative brief and assets will be disclosed at the start of the sprint. Whether you''re a designer, filmmaker, editor, motion artist, social creator, or AI-powered creative builder, Forge 3 is your opportunity to prove that creativity, speed, and AI mastery can produce extraordinary work.', '2026-06-22T00:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-3-nmg-technologies-1702556', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702568', 'U-19 AI Olympics', 'An intensive, project-driven development tournament where elite incoming students compete to build, deploy, and launch production-ready products from scratch. The competition is designed and judged by Manas Kumar Verma, ranked among the Top 15 Programmers in India and a Meta Hacker Cup Winner.The Challenge Blueprint: Over the course of the competition, participants must rapidly architect, code, and deploy 6+ live, real-world projects to climb the leaderboard. The submission portfolio includes: Live News Tracker &ndash; Real-time data streaming and monitoring. Newspaper-Style Web App &ndash; Dynamic content layouts and publishing architecture. Character-Themed Animated UI &ndash; Advanced front-end motion graphics and styling. Document Explorer &ndash; Complex data filtering and search systems. E-Commerce Landing Page &ndash; High-conversion user experience and responsive design. Interactive Browser Piano &ndash; Audio API integration and real-time event handling. Platform: Unstop Timeline & Intensity: Duration: 2 Days of high-intensity, non-stop building and deployment sprints. Eligibility & Rules: Target Audience: Open to students who have successfully passed the 12th grade, including gap-year students (&ldquo;droppers&rdquo;), who are entering engineering colleges. Prerequisites: Zero prior coding experience is required&mdash;your drive to learn, build, and adapt under pressure is what matters. The Golden Rule: This is a pure building competition. Active participation, daily milestone submissions, and completely functional, live-deployed URLs are strictly required to remain in the running.', '2026-06-10T18:11:26+05:30', '2026-08-30T10:44:29+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/u-19-ai-olympics-algo-university-1702568', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695290', 'Hack Better Than Me (HBTM)', 'Guidelines Event Name: hack better than me (hbtm) &mdash; IABTM x IIIT Pune Theme: Agentic AI for Human Potential Format: Two-Round Competition &mdash; Online Qualifier followed by In-Person 24-Hour Hackathon Final Round Date: 1&ndash;2 August 2026 Venue: IIIT Pune Campus, Pune, Maharashtra Eligibility Open to all undergraduate and postgraduate students currently enrolled in any recognised college or university across India. Participants must register through the Unstop platform. No minimum GPA or prior AI/ML experience required. A strong interest in agentic AI and problem-solving is sufficient. Teams must have at least one member with basic proficiency in programming and system design. All participants must carry a valid college ID card for verification during the final round. Participants from non-technical backgrounds (design, management, humanities) are welcome as long as the team collectively covers both technical and user-centric aspects. Team Size Minimum 2 members and maximum 4 members per team. Teams must be exactly 2 or 4 members. Solo participation is not allowed. 3-member teams are also not permitted. One member must be designated as the Team Leader at the time of registration. Inter-College Teams Students from different colleges may participate. Inter-Specialization Teams Allowed and strongly encouraged. Teams may consist of participants from different academic specializations &mdash; engineering, design, management, sciences, arts, or any other discipline. Registration Requirements To complete your registration, every team must fulfil all three of the following steps: Step 1 &mdash; Register on Unstop Fill in the registration form on Unstop with your full details. The Problem Statement email will be sent to the Team Leader. Step 2 &mdash; Create an IABTM Account Every team member must create an account on the IABTM platform at: iambetterthanme.com Note down your IABTM username. All team members must share their IABTM usernames in the registration form. Step 3 &mdash; Upload an Intro Video on LinkedIn Each team must upload a short introduction video on LinkedIn, tag all three pages below, and share the LinkedIn post URL in the registration form. Pages to tag: IABTM &mdash; https://www.linkedin.com/company/iabtm-i-am-better-than-me/m/company/iabtm-i-am-better-than-me IIIT Pune &mdash;  https://www.linkedin.com/school/iiitpune/ Your video must cover: A introduction of yourself and your team. Clearly mention who the Team Leader is. Projects or achievements you have accomplished so far. Why you want to participate in hack better than me (HBTM). Share the LinkedIn post URL in the registration form after uploading. Round Details Round 1 &mdash; Online Qualifier Registrations close on 11th July 2026. After registrations close, the Problem Statement will be sent via email to the Team Leader. Teams will have 2&ndash;3 days to work on the problem and submit their solution. Submission format: A PowerPoint presentation (mandatory) and an optional 2&ndash;3 minute video walkthrough. Full submission instructions will be shared in the same email as the Problem Statement. Shortlisting for Round 2 will be based on innovation, feasibility, clarity of vision, and alignment with the theme. Round 2 &mdash; In-Person 24-Hour Hackathon Shortlisted teams must appear physically at IIIT Pune on 1&ndash;2 August 2026. Teams will work on building a working prototype during a continuous 24-hour development sprint. Food and all necessary arrangements will be provided by the organisers. Final evaluation will be based on project demonstrations and presentations to the judging panel. Problem Statements Number of Problem Statements: 1 The Problem Statement will be shared with all registered teams via email after registrations close on 16th July 2026. The email will be sent to the Team Leader. Teams will have 2&ndash;3 days to submit their solution after receiving the Problem Statement. Duration of the Competition Round 1: 2&ndash;3 days online submission window after the PS email is sent. Round 2: 24 hours of continuous development at IIIT Pune, conducted over two days (1&ndash;2 August 2026). Submission Requirements Round 1 PowerPoint presentation covering: problem understanding, proposed architecture, technology stack, user journey, personalisation logic, feasibility, and expected outcomes. IABTM usernames of all team members must be included in the submission. Optional: A 2&ndash;3 minute video walkthrough of the proposed solution. Round 2 (Offline at IIIT PUNE) Working prototype or live demo. 3&ndash;5 minute demo presentation to the judging panel. Explanation of system architecture and agent design decisions. Sample user journey showcasing personalisation logic. Code repository (GitHub or similar). Evaluation Criteria Round 1 &mdash; Online Qualifier Clarity of Problem Understanding &ndash; 20% Innovation in Proposed Solution &ndash; 25% Technical Feasibility &ndash; 20% Presentation and Communication &ndash; 20% Alignment with Theme &ndash; 15% Round 2 &mdash; On-Campus Final at IIIT PUNE Innovation and Creativity &ndash; 25% Technical Execution and Completeness &ndash; 25% User Experience and Design &ndash; 20% Scalability and Growth Potential &ndash; 15% Alignment with Challenge Objective and Theme &ndash; 15% Registration Registrations will be conducted through Unstop. The registration form will collect: team details, IABTM usernames of all members, designation of Team Leader, email addresses of all members, and the LinkedIn post URL of the intro video. Prizes The prize pool includes cash prizes for the top 3 finalists: 1st Place: Cash Prize 2nd Place: Cash Prize 3rd Place: Cash Prize Goodies for all participants and finalists: Stickers Keychains Tote Bags Additional Opportunities Outstanding projects may be considered for future platform integration. Internship and collaboration opportunities may be offered to exceptional teams. Rules Participants must register in teams of 2 or 4 members only. Solo entries and 3-member teams are not permitted. One team member must be designated as the Team Leader at the time of registration. All teams must submit their project before the deadline communicated in the Problem Statement email. Teams must present their solution during the final judging session at IIIT Pune. Participants must adhere to the event''s Code of Conduct throughout the hackathon. All finalists must review and sign the Hackathon Participant Agreement before the event begins. Projects submitted during the hackathon must be original work created by the participating team. Participants agree that project repositories and intellectual property developed during the hackathon may be shared with the organisers as specified in the Participant Agreement. Organisers reserve the right to use submitted work for evaluation, further development, demonstration, or integration purposes. Any violation of event rules, misconduct, plagiarism, unfair practices, or failure to comply with organiser instructions may result in disqualification. The decision of the judges and organisers shall be final and binding in all matters related to the competition. Organisers reserve the right to modify event schedules, rules, judging criteria, or participation requirements if necessary.', '2026-06-22T17:00:00+05:30', '2026-07-15T23:55:50+05:30', 'Online', 'online', 'Cash prize (Amount Disclose soon), Certificate, Go', 'https://unstop.com/hackathons/hack-better-than-me-hbtm-indian-institute-of-information-technology-iiit-pune-1695290', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702397', 'X-Play Aaruush ''26', 'Introduction: X-Play is a national-level game development challenge that brings together creativity, innovation, and technical expertise to transform original ideas into engaging gaming experiences. Participants will progress through stages of ideation and prototype development, showcasing their ability to design, develop, and deliver compelling interactive worlds. Objectives: Encourage the development of innovative and impactful gaming experiences. Provide participants with practical exposure to the game development lifecycle. Promote creativity in game design, storytelling, mechanics, and user engagement. Foster problem-solving, technical proficiency, and interdisciplinary collaboration. Create a platform for aspiring developers to showcase their skills before industry professionals and peers.', '2026-06-22T00:00:00+05:30', '2026-07-15T23:59:00+05:30', 'Online', 'online', '₹ 35,000', 'https://unstop.com/hackathons/x-play-aaruush-26-srm-institute-of-science-and-technology-kattankulathur-chennai-1702397', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702266', 'Open Source Hackathon', 'The Open Source Hackathon 2026 is a nationwide coding challenge designed to encourage developers to contribute to real-world open-source projects, collaborate with fellow innovators, and enhance their practical development skills. Powered by Unstop and supported by students and communities from IITs and NITs, this hackathon provides participants with an opportunity to work on live repositories, solve meaningful issues, and compete for exciting rewards. Eligibility: Open to all students and professionals across India. Participants must have basic knowledge of Git, GitHub, and software development workflows. Individual participation only. Participants must have an active GitHub account. Multiple registrations from the same participant are not permitted. Hackathon Format Round 1: Screening Round All registered participants will undergo an initial screening process. Participants may be evaluated based on their GitHub profile, technical background, and responses submitted during registration. Selected participants will proceed to the main hackathon round. Round 2: Open Source Contribution Round Shortlisted participants will receive repository access details through their registered email addresses. Participants will be assigned repositories and issues/tasks. They must work on the assigned tasks and submit their contributions through GitHub Pull Requests. Contributions must follow standard GitHub practices and repository guidelines. Successfully completed changes should be merged into the repository after review. Evaluation Criteria: Participants will be evaluated based on: Quality of code and implementation Innovation and problem-solving approach Impact of contribution Documentation quality Code readability and maintainability Successful merging of Pull Requests Adherence to project guidelines Rewards & Recognition Prize Pool: ₹20,000 1st Rank: ₹10,000 2nd Rank: ₹6,000 3rd Rank: ₹4,000 In addition: Participation Certificates will be provided to eligible participants. Certificates of Excellence will be awarded to top performers. Outstanding contributors may receive recognition for their open-source contributions. Rules: All submissions must be original work. Participants must only work on the repositories and tasks assigned to them. Use of plagiarized code will result in immediate disqualification. Participants must maintain professional conduct throughout the event. Any attempt to manipulate repository history, submissions, or evaluation criteria may lead to disqualification. Decisions made by the organizing team and judges will be final and binding. Late submissions will not be considered unless officially communicated. Participants are responsible for maintaining the confidentiality of any repository access provided. Submission Process: Complete registration. Qualify through the screening round. Receive repository details via email. Fork/clone the assigned repository. Implement the required changes. Create and submit Pull Requests. Wait for review and merge confirmation. Final evaluation and winner announcement. Complete hackathon is on Unstop. Why Participate? Gain practical open-source experience. Strengthen your GitHub profile. Learn industry-standard collaboration workflows. Compete for a ₹20,000 prize pool. Receive certificates and recognition. Connect with a community of developers from across India. Build. Collaborate. Contribute. Create Impact.', '2026-06-21T00:00:00+05:30', '2026-07-05T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/open-source-hackathon-iit-bombay-1702266', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701779', 'Hacknite: 12 Hour Hackathon', 'Eligibility Guidelines Hacknite is open to all undergraduate, postgraduate, diploma students, and recent graduates from any recognized institution. Participants from all disciplines are welcome. Individual registrations are allowed. Team size: 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. A participant can be a member of only one team. Tracks: Participants can build projects under any one of the following tracks: Artificial Intelligence & Machine Learning Open Innovation Cyber Security Internet of Things (IoT) Blockchain & Web3 Gaming & XR Communication & Announcements All important announcements, updates, result notifications, schedule changes, and event-related communication will be shared through the official WhatsApp group. Official WhatsApp Group:https://chat.whatsapp.com/KcPvJQpSPBT1NJaTVgiNmJ Participants are strongly encouraged to join the group to stay informed about the latest updates. Problem Statements Participants may choose from the official problem statements released before the event or build an open innovation project aligned with one of the hackathon tracks. Teams are encouraged to solve real-world problems with practical and scalable solutions. Selection Process Hacknite &ndash; Code Royale 2026 follows a two-phase registration and selection process. These phases are independent registration opportunities and not elimination rounds. Teams may participate only once during the event. Phase 1 (Expected) Registration Window: 21 June 2026 &ndash; 05 July 2026 Eligibility: Open to all eligible students. Team Size Minimum: 2 Members Maximum: 4 Members Expected Result Declaration: 06 July 2026 &ndash; 10 July 2026 Phase 2 (Expected) Registration Window: 11 July 2026 &ndash; 22 July 2026 Purpose Phase 2 is intended for new teams who were unable to register during Phase 1. It serves as an additional registration opportunity and is not a continuation or elimination round of Phase 1. Important Rule Teams that have already registered or participated in Phase 1 will not be eligible to register in Phase 2. Any duplicate registrations may be disqualified. Expected Result Declaration: 23 July 2026 &ndash; 25 July 2026 Final Shortlisting (Expected) Based on the evaluation process across both phases, approximately 250&ndash;300 participants are expected to be shortlisted for the Offline Grand Finale. Submission: Teams must submit by Google Form: Source Code Repository (GitHub or equivalent) Project Demo Brief Documentation Project Deployed Link Judging Criteria: Projects will be evaluated on: Innovation & Creativity Technical Implementation Problem Relevance Scalability & Feasibility Presentation & Demo Overall Impact Mentorship Industry mentors will be available throughout the hackathon to guide participants on technical challenges, product development, and pitching. Rules Every participant must carry a valid college ID and government-issued ID for verification. Participants must report to the venue before the reporting time. Teams must develop their solution primarily during the hackathon duration. Pre-existing libraries, frameworks, and open-source tools may be used; however, the core project must be built during the event. Plagiarism or submission of previously developed projects will lead to immediate disqualification. AI tools are permitted unless explicitly restricted in a specific problem statement. Teams are responsible for bringing their own laptops, chargers, and other required equipment. Internet access and basic infrastructure will be provided by the organizers. Participants are expected to maintain professional conduct throughout the event. Any form of harassment, discrimination, or misconduct will result in immediate removal from the hackathon. Decisions made by the organizing committee and judging panel shall be final and binding. Organizers reserve the right to modify the schedule, rules, or judging process if required due to unforeseen circumstances. By participating, teams consent to photography, videography, and promotional use of media captured during the event. We look forward to welcoming you to Hacknite: Code Royale&mdash;Build. Innovate. Survive.', '2026-06-20T00:00:00+05:30', '2026-08-10T20:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hacknite-12-hour-hackathon-hackers-cult-1701779', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702203', 'AI Product Hackathon', 'Overview Dates: 11th & 12th July, 2026 Registrations: Now Open Kickoff Session: 11th July (Saturday) This is a hands-on, build-first hackathon created for individuals who want to launch a real AI product, not just present ideas or mockups. What You&rsquo;ll Do During these two days, participants will: Conceptualize, build, and launch a complete agentic AI solution Work on practical, real-world challenges Go through the entire product journey: Identifying the problem Designing system architecture Integrating tools and APIs Delivering a functional end product The core focus is on building AI agents ready for real-world use that can: Think and make decisions. Interact with tools. Execute tasks independently. By the end, you&rsquo;ll walk away with a working AI product that can be: Added to your portfolio. Demonstrated in interviews. Expanded into real-world use cases. Participation Guidelines You can join individually or in teams (up to 2 members recommended). All development must happen within the hackathon timeframe. You are free to use AI tools, APIs, and frameworks. Participants must clearly document their process (problem &rarr; solution &rarr; architecture). A functional prototype or live demo is required. Submission Requirements A demo video or live working product. Access to the codebase (GitHub or equivalent). A brief explanation of your solution. Rules & Evaluation ️ Rules Fully pre-built solutions are not allowed (starter templates are acceptable). Any form of copying or plagiarism will result in disqualification. Teams must clearly specify their actual contribution vs AI-generated output. Submissions must be fully working products, not just designs or presentations. All entries must be submitted before the deadline.', '2026-06-21T10:00:00+05:30', '2026-07-12T23:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-product-hackathon-product-space-1702203', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701822', 'DropHack', 'Welcome to the ultimate tech battleground. DropHack is not your average hackathon; it is a high-stakes, high-velocity coding sprint designed strictly for elite student developers. There are no pre-built templates and no rehearsed pitches. Participants will be tested on their raw adaptability, logical thinking, and rapid execution because the exact problem statements are kept heavily guarded until "Zero-Hour." When the timer starts, the challenges drop, and teams have exactly 10 hours to architect, build, and ship a working prototype. The 5 Core Themes While the exact problem statements are a surprise, all challenges will fall under one of these five high-demand tech sectors: Artificial Intelligence (AI) Web3 & Blockchain Cybersecurity Fintech Healthcare Tech Eligibility & Team Formation Guidelines Target Audience (Tech Only): To maintain the highest quality of competition, participation is strictly limited to students pursuing technical degrees (B.Tech, BE, BCA, MCA, M.Tech, BSc IT, or equivalent tech backgrounds). Team Size: 2 to 4 members per team. Inter-College Teams: ALLOWED. You can form teams with developers from different tech institutions. Inter-Specialization (Within Tech): ALLOWED. We highly encourage balancing your team with different technical skill sets (e.g., combining a Frontend UI dev, a Backend architect, and an AI specialist). Solo Participation: Not allowed. A 10-hour sprint requires a coordinated team. The Process & Format (How It Works) Phase 1: Registration & Profile Screening Register your team on Unstop. Ensure all team members have updated their profiles with their technical degrees, primary tech stacks, and active GitHub/LinkedIn links. Phase 2: The Pre-Hackathon Online Assessment (Elimination Round) To ensure an elite playing field, all registered teams must pass a mandatory online technical assessment. Format: Online Quiz / Coding & Algorithmic Fundamentals. Duration: 45 Minutes. Goal: This round filters for strong coding fundamentals and logic to shortlist only the top 15% of teams for the main event. Phase 3: DropHack - The Main Offline Event The shortlisted elite teams will be invited to the official physical venue for the grand finale. Duration: A ruthless 10-Hour Offline Development Sprint. The Drop: Problem statements are revealed live on stage at exactly Zero-Hour. Teams must immediately pivot, divide tasks, and code a Minimum Viable Product (MVP) before the 10-hour clock runs out. Rules of the Competition No Pre-compiled Code: All projects must be built entirely during the 10-hour sprint. Bringing pre-written core logic will lead to instant disqualification. Open Source & APIs: Because time is incredibly tight, the use of open-source libraries, frameworks, and sponsor APIs is heavily encouraged to speed up development. Hardware: Participants must bring their own laptops, chargers, and any necessary adapters. Submission: Final submissions must include a working prototype (MVP), a code repository link (GitHub), and a quick technical walkthrough for the judges. Code of Conduct: Teams must maintain a professional and respectful environment at the offline venue. Any form of harassment or damage to venue property will result in strict action. Are you fast enough to survive the Drop? Register your team now.', '2026-06-21T00:00:00+05:30', '2026-08-29T19:00:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/drophack-siec-community-1701822', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702167', 'Build The Next Big UI', 'Build The Next Big UI  &ndash; Competition Guidelines Overview Frontend Battle 2026 is a single-round design and development challenge where participants are required to showcase their creativity, problem-solving skills, and frontend development expertise. Teams must submit a PDF presentation highlighting their project idea, user experience, interface design, and implementation approach. Participants may choose any domain or real-world problem, including but not limited to AI, Healthcare, Education, Finance, Sustainability, Productivity, Smart Cities, E-Commerce, and more. Submission Requirements Submission Format One PDF presentation (2&ndash;6 pages) Individual or Team Participation Frontend-focused solutions only Backend implementation is optional Required Sections Problem StatementClearly define the problem your solution aims to address. Explain its significance, target audience, and the challenges faced by users. Proposed SolutionDescribe your solution in detail, including key features, user flow, and how it effectively solves the identified problem. Tech Stack UsedMention the technologies, frameworks, libraries, design tools, and platforms used during development. Examples: React.js Next.js Vue.js Angular Tailwind CSS Bootstrap Figma Framer Motion AI Design Tools 4. Prototype  Include visual representations of your solution such as: Github repo link Vercel link 5. Expected Impact Explain the value your solution creates, including: Target Users Benefits Social or Business Impact Real-world Applications 6. Future Scope Highlight potential future enhancements, scalability opportunities, integrations, and advanced features planned for upcoming versions. Judging Criteria Submissions will be evaluated on the following parameters: UI/UX Design Quality: Visual appeal, design consistency, accessibility, and overall user experience. Innovation & Creativity: Originality of the idea and uniqueness of the proposed solution. Problem-Solving Ability: Relevance of the identified problem and effectiveness of the solution. Prototype Quality: Clarity, completeness, functionality, and presentation of the design. Impact & Feasibility: Potential real-world value, scalability, and practicality of implementation. Submission Guidelines Submit a single PDF file (2&ndash;6 pages). Figma designs, wireframes, mockups, and developed frontend screenshots are all accepted. Participants may use any frontend framework, design tool, or technology stack. AI-assisted tools for design and development are permitted. The submitted work must be original and created by the participating individual or team. Plagiarism or copied designs may lead to disqualification. Deliverable Mandatory Deliverable One PDF Presentation (2&ndash;6 Pages) The competition primarily focuses on: Design Thinking User Experience Frontend Development Creativity & Innovation Problem-Solving Approach A fully functional backend is not required. Case Study Themes Participants may choose any one of the following themes or create their own innovative problem statement. Healthcare & Wellness: Design a platform that helps users monitor health, book appointments, access medical records, or receive AI-powered wellness recommendations. Education & Learning: Build an interactive learning platform that enhances engagement through personalized learning paths, progress tracking, and skill development. Sustainability & Environment: Create solutions focused on waste management, carbon footprint tracking, environmental awareness, or sustainable lifestyle practices. Business & Productivity: Develop a platform that improves task management, team collaboration, workflow automation, and productivity. AI & Future Technologies: Design an AI-powered application that enhances productivity, decision-making, content creation, research, or everyday experiences. Smart Cities & Civic Innovation: Create solutions that improve public services, citizen engagement, issue reporting, and access to government services. Finance & FinTech: Build a user-friendly platform for budgeting, expense tracking, investment insights, and financial literacy. E-Commerce & Customer Experience: Design modern shopping experiences with personalized recommendations, seamless navigation, and intuitive interactions. Gaming & Entertainment: Develop platforms for gaming communities, content discovery, event participation, creator engagement, or digital entertainment. Open Innovation: Participants may choose any real-world problem beyond the listed themes and develop a frontend solution that demonstrates creativity, innovation, and impact.', '2026-06-21T12:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate of Achievement for winners for Top - 5', 'https://unstop.com/hackathons/build-the-next-big-ui-techverse-solutions-1702167', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693713', 'Business Leadership Simulator 2026', 'About the Competition: What if you were given control of a real business and asked to grow it? Business Leadership Simulator is not a business plan competition. It is not a case study competition. It is not a hackathon. This is a real-world business simulation designed to test your entrepreneurial thinking, leadership ability, decision-making skills, execution capability, and business acumen under realistic conditions. Participants will be assigned a live business scenario and will be expected to make strategic decisions, solve operational challenges, manage growth opportunities, and navigate real-world business situations. Your performance will be evaluated not on presentations or theoretical answers, but on your ability to think like an entrepreneur and lead like a business owner. What Makes This Different? Most competitions test how well you can create a business plan. This competition tests how well you can actually run a business. Participants will be required to: Make strategic business decisions Solve real business challenges Manage limited resources Develop growth strategies Handle customer and operational situations Demonstrate leadership and execution ability Adapt to changing market conditions Every decision you make will influence your overall performance in the simulation. Skills Evaluated: Entrepreneurship Leadership Decision Making Business Strategy Problem Solving Communication Team Management Crisis Handling Growth Thinking Execution Capability Competition Format: Round 1: Business Introduction & Market Understanding Participants will receive details of the business they will be managing and will be expected to understand its challenges, opportunities, and market dynamics. Round 2: Business Simulation Participants will make operational, strategic, and growth decisions while responding to real-world business scenarios. Round 3: Leadership & Execution Assessment Participants will be evaluated on how effectively they manage resources, solve problems, and grow the business. Rewards: Internship Opportunities for Top Performers The highest-performing participants will receive internship offers and opportunities to work on real business projects. Industry Recognition Gain practical experience that goes far beyond traditional academic competitions. Leadership Exposure Demonstrate your entrepreneurial and managerial abilities in a realistic business environment. Eligibility: Open to: Undergraduate Students Postgraduate Students Aspiring Entrepreneurs Future Business Leaders Anyone interested in entrepreneurship, management, and leadership Platform: The competition will be conducted entirely on YAI Infraventure''s proprietary platform. Participants will receive further instructions after successful registration. Think Like a Founder. Lead Like a CEO. Execute Like an Entrepreneur.', '2026-06-19T00:00:00+05:30', '2026-06-30T00:01:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/business-leadership-simulator-2026-yai-infraventure-1693713', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701194', 'ThreadCounty Web Development Hackathon 2026', 'About ThreadCounty: ThreadCounty is an AI-powered textile technology platform that helps textile manufacturers, students, researchers, and quality control professionals analyze fabric structures using Artificial Intelligence and Computer Vision. The platform aims to simplify textile inspection by allowing users to upload fabric images and receive automated thread density analysis, weave information, AI insights, and downloadable reports through a modern web application. Your challenge is to build the next-generation ThreadCounty platform with an exceptional user experience, production-ready architecture, and scalable backend. Problem Statement: Design and develop a complete full-stack web application for ThreadCounty. The application should look like a professional SaaS product and must include a modern UI, secure authentication, responsive design, efficient backend architecture, and database integration. Participants are free to use their creativity while maintaining the required functionality. The final product should be deployable and production-ready. Objective: Develop a professional website that enables users to: Learn about ThreadCounty. Create an account. Login securely. Manage their profile. Upload fabric images. View AI-generated analysis reports. Download reports. View previous uploads. Contact the organization. Purchase subscription plans. Access FAQs and documentation. Additionally, administrators should be able to manage users, uploaded images, and platform analytics through an Admin Dashboard. Website Pages (Mandatory): Landing Page Hero Section. Professional Navbar. Call-to-Action Buttons. Product Overview. Features Section. Benefits. Workflow Section. Testimonials. Statistics. FAQ. Contact Section. Footer. Authentication Sign Up. Login. Forgot Password. Email Verification. Logout. Remember Me. User Dashboard Welcome Section. User Information. Total Uploads. Recent Reports. Storage Usage. Activity Timeline. Quick Actions. Notifications. Image Upload Module Allow users to upload: JPG. PNG. JPEG. Features: Drag & Drop Upload. Image Preview. Upload Progress. Validation. File Size Restrictions. Delete Uploaded Images. AI Analysis Result Page Display: Uploaded Image. Thread Density. Warp Count. Weft Count. Fabric Type. Confidence Score. AI Suggestions. Download Report Button. Share Report Option. Mock AI results are acceptable if no AI model is integrated. History Page View Previous Analyses. Search Reports. Filter Reports. Delete Reports. Download Previous Reports. Pricing Page Free Plan. Student Plan. Professional Plan. Enterprise Plan. Display: Features. Pricing Cards. Subscribe Button. About Page Company Story. Mission. Vision. Technology Used. Team Section. Timeline. Contact Page Contact Form. Email. Social Media Links. Google Maps (Optional). FAQ Page Include common questions regarding: Platform. AI Analysis. Pricing. Upload Limits. Account. User Profile Update Profile. Upload Profile Picture. Change Password. Delete Account. View Activity. Admin Dashboard View Total Users. Manage Users. View Uploaded Images. Delete Reports. View Analytics. Manage Subscription Plans. Platform Statistics. Backend Requirements: Develop a scalable backend with proper architecture. Required APIs: Authentication API. User API. Upload API. Report API. Dashboard API. Admin API. Contact API. Use proper: Error Handling. Input Validation. Authentication Middleware. Authorization. Logging. Database: Use Supabase. Suggested Tables: Users. Profiles. Uploads. Reports. Subscriptions. Contact Messages. Notifications. Use proper relationships and security policies. UI/UX Requirements: Fully Responsive. Mobile Friendly. Modern UI. Attractive Animations. Smooth Transitions. Dark Mode. Light Mode. Accessible. Fast Loading. Bonus Features: AI Chatbot. Voice Search. Image Compression. OCR Integration. Multi-language Support. Progressive Web App (PWA). Real-time Notifications. Email Notifications. Analytics Dashboard. Fabric Comparison Tool. Blog Section. Community Forum. Admin Role Management. Infinite Scroll. Lazy Loading. Offline Support. Recommended Tech Stack: Frontend: React.js. Next.js. TypeScript. Tailwind CSS. Framer Motion. ShadCN UI. Backend: Python Database: Supabase. Authentication: Supabase Auth. Deployment: Vercel. Netlify. Render. Railway. Version Control: Git. GitHub. Deliverables: GitHub Repository. Live Hosted Website. README Documentation. Database Schema. API Documentation. Rules: Original work only. No plagiarism. Open-source libraries are allowed. AI tools are allowed. All code must be developed during the hackathon period. Website must be fully responsive. The project should be hosted on a public platform. GitHub repository must remain public until evaluation. Late submissions will not be accepted. Judges'' decision will be final.', '2026-06-18T00:00:00+05:30', '2026-06-30T21:47:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/threadcounty-web-development-hackathon-2026-dkte-societys-textile-engineering-institute-dktestei-ichalkaranji-1701194', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701427', 'Unlock''D', 'The New Build-A-Thon Concept: Unlock&rsquo;D is a fast-paced, 24-hour virtual Build-A-Thon designed around the principles of agile development and milestone-based execution.​The Progression: Instead of forcing you to conceptualize an idea from scratch, the core application structure and underlying blueprint will be provided directly to your team.​The Execution: Over a focused 24-hour timeline, your team will follow a progressive, milestone-driven sprint. You will be tasked with building and deploying specific features of the application one by one. Successfully unlocking and completing each feature sequentially will navigate your team to full application development by the end of the event.​Key Benefits & Perks: Zero Experience Required: This is a completely beginner-friendly sandbox. To ensure you can build confidently.​Resume & Portfolio Acceleration: Unlike standard hackathons, where ideas go unfinished, this milestone framework mirrors real-world production engineering, leaving you with a highly polished, GitHub-worthy full-stack project perfect for placement cycles.​Tangible Perks: Every single participant will receive an official Certificate of Participation to boost their credentials, along with the chance for top teams to claim rewards from our premier prize pool!​ Event Details: Mode: Online ​Dates: 3rd - 4th July 2026 ​Duration: 24 Hours ​Team Size: 1-3 Members ​Prize Pool: Announced Soon Ping us here for queries: Pushkar Chaudhary (9313073267) Jaagriti Sethia (7439454640) ​Alekhya Mazumdar (8777090142)', '2026-06-22T00:00:00+05:30', '2026-07-04T10:30:00+05:30', 'Online', 'online', '₹ 3,000', 'https://unstop.com/hackathons/unlockd-manipal-university-mu-jaipur-1701427', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694014', 'StoxraHack 2026 — India''s Student FinTech & AI Trading Hackathon', 'Build. Innovate. Compete. Win. Stoxra National Online Hackathon 2026 is one of India''s largest student innovation challenges, bringing together developers, designers, entrepreneurs, AI enthusiasts, and future innovators from across the country. Participants will solve real-world problems in Artificial Intelligence, FinTech, Trading Technology, Financial Literacy, Data Analytics, Automation, and Emerging Technologies while competing for prizes worth ₹3.5 Lakhs+. Whether you''re a beginner exploring innovation or an experienced builder ready to showcase your skills, this hackathon provides a platform to learn, collaborate, network, and create impactful solutions. fees -200 New Update: Join the STOXRA Hackathon 2026 for FREE! We''ve listened to your feedback! Many participants wanted a way to reduce or completely waive the ₹200 registration fee. To make the hackathon more accessible, we''ve introduced the STOXRA Earn Registration Credits Program. Now you can earn registration credits by: Referring Hackathon participants Sharing the official STOXRA Hackathon posts Inviting new STOXRA users Complete the required tasks and reduce your registration fee&mdash;or even join the hackathon for FREE! Want to Join the Hackathon for FREE? Join our Official WhatsApp Community and WhatsApp Channel to get the complete step-by-step guide on: How to earn registration credits How to complete each task How to verify your submissions How to reduce your registration fee How to unlock FREE Hackathon registration WhatsApp Community:https://chat.whatsapp.com/JDX5EOO8UcN4hmPvhLc1Dz WhatsApp Channel:https://whatsapp.com/channel/0029Vb8bgCX9hXFEib74FM1u Note: All referrals, social media posts, and invited users will be verified by the STOXRA team before registration credits are added to your account. Start completing your tasks today and join STOXRA Hackathon 2026 at the lowest possible cost&mdash;or even FREE! Prize Pool: ₹3,50,000+ Worth of Prizes Domains: Artificial Intelligence (AI) FinTech Innovation Trading Technology Financial Literacy Machine Learning Data Analytics Web Development Mobile Applications Automation & Productivity Tools Startup & Business Solutions Team Size: Minimum: 2 Members Maximum: 5 Members Event Mode: 100% Online Level Competition Structure: Level 1 &ndash; Idea Submission Last Date for PPT Submission:  Teams submit their innovative idea and problem statement. Level 2 &ndash; Prototype & Pitch Deck  : Shortlisted teams develop an initial prototype and pitch deck. Level 3 &ndash; Live Build Sprint (Semi-Finals) ( Selected teams receive mentorship and further develop their solutions. Level 4 &ndash; Grand Finale  Top teams present their projects before an expert jury panel. Eligibility: Open to all College Students across India Engineering, Management, Commerce, Design, and Technology students are welcome Students from any recognized institution can participate Evaluation Criteria: Innovation & Creativity Technical Implementation Problem Solving Scalability User Experience Business Potential Presentation & Pitch Quality Benefits: Certificates for All Participants Internship Opportunities at Stoxra Industry Expert Mentorship National-Level Recognition Networking with Students Across India Real-World Problem Statements Portfolio Building Opportunity Fast-Track Opportunities for Top Performers Duration: 48-Hour Online Innovation Challenge Why Participate? Build innovative solutions, gain industry exposure, connect with talented students nationwide, and compete for exciting rewards while solving meaningful real-world problems.', '2026-06-02T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', '₹ 2,00,000', 'https://unstop.com/hackathons/stoxrahack-2026-indias-student-fintech-ai-trading-hackathon-stoxra-hackathon-2026-iimt-university-iimtu-great-1694014', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701080', 'Infinity Hack 1.0', 'Code Beyond Limits &bull; Innovate Without Boundaries Code Infinite IT Training Service, Coimbatore proudly presents INFINITY HACK 1.0, an innovation-driven hackathon that brings together aspiring developers, innovators, and problem solvers to transform ideas into impactful solutions. Participation Process: Idea Submission Round 18 June 2026 &ndash; 22 June 2026 Teams are invited to submit their innovative ideas via WhatsApp. WhatsApp Number: +91 99764 99765 Only the Team Leader should contact and submit the idea. While submitting, the Team Leader must provide: Team Name Project Title Domain Team Leader Name Names of all Team Members College Name Contact Number Shortlisting Round 23 June 2026 Shortlisted teams will be notified after evaluation of the submitted ideas. Registration Confirmation Selected teams are required to confirm their participation by paying a registration fee of ₹100. Hackathon Day 26 June 2026 Time: 9:00 AM &ndash; 5:00 PM Location: Coimbatore Domains: Artificial Intelligence & Machine Learning Web Development Cybersecurity Data Science Cloud Computing IoT & Robotics What Participants Will Receive: Exciting Surprise Gifts E-Certificates for All Participants Internship and Career Opportunities Networking with Fellow Innovators Exposure to Real-World Problem Solving Bring your ideas to life and become part of a community that believes in innovation without limits. Think Infinite. Create Impact.', '2026-06-18T00:00:00+05:30', '2026-06-22T00:01:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/infinity-hack-10-sangam-soft-solutions-1701080', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700798', 'AI Product Challenge 2026', 'Build an AI Product. Solve a Real Problem. Compete with Builders Across India. The AI Product Challenge 2026 is a national-level innovation challenge for students, developers, creators, designers, and aspiring founders who want to build real AI-powered products and showcase their creativity. Participants will identify a real-world problem, design an innovative solution, and build an AI-powered product, tool, workflow, application, or platform. This is not about theory. This is about building. Challenge Theme: Build the Future with AI Create solutions in: Education Healthcare Productivity Finance Sustainability Agriculture Student Life Creator Economy Social Impact Any other domain where AI can create meaningful impact Challenge Rounds: Round 1: Idea Submission Submit: Problem Statement Proposed Solution AI Implementation Approach Round 2: Product Development Shortlisted participants build: AI Tools AI Agents SaaS Products Automation Workflows Mobile Applications Web Applications Productivity Solutions Round 3: Final Showcase Present your solution and demonstrate: Innovation Impact Execution Product Thinking Judging Criteria: Innovation & Creativity Problem Solving AI Integration Product Execution User Value Presentation Rewards & Opportunities: Scholarships & Special Recognition Internship Opportunities Founder Mentorship Builder Community Access Certificates Networking Opportunities Exclusive Opportunity: The Top 50 Participants will be shortlisted for an exclusive builder initiative where they will gain access to advanced opportunities, founder interactions, project support, community programs, and future innovation initiatives within the Dyndox ecosystem. Who Can Participate? School Students Undergraduate Students Postgraduate Students Developers Designers Creators Aspiring Founders AI Enthusiasts Individual Participation Allowed. Build. Compete. Launch.', '2026-06-18T00:00:00+05:30', '2026-07-02T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-product-challenge-2026-dyndox-1700798', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700796', 'AI Builders Hackathon 2026', 'Build Products. Launch Startups. Create the Future. The AI Builders Hackathon 2026 is a national-level innovation challenge for students, developers, creators, aspiring founders, and future builders who want to leverage AI to solve real-world problems and create meaningful products. Whether you''re building an AI tool, startup idea, automation workflow, SaaS product, mobile app, or innovative solution, this hackathon is designed to help you think, build, and execute. What You''ll Get: AI & Product Building Workshops Founder-Led Mentorship Sessions Startup & Innovation Frameworks Access to AI Resources & Toolkits Networking with Builders & Innovators Community Support & Collaboration Certificates of Participation Scholarships & Special Recognition The Builder Acceleration Cohort This hackathon is more than a competition. The Top 50 participants will be selected for an exclusive Builder Acceleration Cohort, where they will receive: 1 Week of Intensive Mentorship Product Building Guidance Startup Validation Sessions AI Implementation Workshops Founder Office Hours Community Access Demo Day Opportunities Career & Internship Opportunities Who Can Participate? School Students Undergraduate Students Postgraduate Students Developers Designers Creators Aspiring Founders AI Enthusiasts No prior startup experience is required. Judging Criteria: Innovation & Creativity Problem Solving AI Integration Feasibility Impact Potential Execution Ability Why Participate? The future belongs to people who can build. This hackathon is your opportunity to turn ideas into reality, connect with ambitious peers, learn from founders, and gain access to opportunities that extend far beyond the competition itself. Build. Launch. Grow.', '2026-06-18T00:00:00+05:30', '2026-07-02T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-builders-hackathon-2026-dyndox-1700796', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690425', 'AVANZARE V19.0 – 24-Hour National Level Hackathon', 'Ready to turn your ideas into reality? Join the 24-Hour National Level Hackathon at AVANZARE 2K26 and challenge yourself to innovate, code, collaborate, and build impactful solutions within 24 hours. Compete with talented teams, solve real-world problems, and showcase your creativity on a national platform. Event Date & Duration: Event Dates: 17.07.2026 &ndash; 18.07.2026 Hackathon Duration: 24 Hours (Continuous) The hackathon will commence on 17 July 2026 and conclude on 18 July 2026. All project development activities must be completed within the 24-hour hackathon period. Eligibility: Open to Undergraduate (UG) and Postgraduate (PG) students from recognized colleges and universities across India. Students from all engineering, technology, science, and allied disciplines are eligible to participate. Participants must carry a valid College ID card for verification. Team participation is mandatory. Problem Statements:  Hardware  1. IoT-Based NPK Soil Nutrient Monitoring System Problem Statement:Develop an IoT system to monitor soil Nitrogen (N), Phosphorus (P), and Potassium (K) levels in real time and provide fertilizer recommendations to farmers. Tech Stack: IoT, Sensors, Cloud, Mobile/Web App Outcome: Improved crop yield and optimized fertilizer usage.   2. Smart Weather Station for Agriculture Problem Statement:Build a smart weather station that monitors environmental parameters and provides localized weather insights for agricultural decision-making. Tech Stack: IoT, Sensors, Analytics Outcome: Better crop planning and reduced weather-related losses.   3. Geographic Location-Based Crop Disease Prediction Problem Statement:Develop an AI model that predicts crop diseases using location and climatic data and recommends preventive measures. Tech Stack: Machine Learning, GIS, Data Analytics Outcome: Early disease detection and reduced crop losses.   4. Soil Moisture-Based Automated Irrigation System Problem Statement:Design an automated irrigation system that controls water supply based on soil moisture levels. Tech Stack: IoT, Sensors, Embedded Systems Outcome: Water conservation and efficient irrigation.   5. Precision Farming Solution for Polyhouse Cultivation Problem Statement:Create a smart monitoring and control system for polyhouse environments to optimize crop growth. Tech Stack: IoT, AI, Automation Outcome: Increased productivity and resource efficiency.    Software   1. Burn-Ex: AI-Based Calorie Estimation System Problem Statement:Develop an AI model to estimate calories burned during physical activities using a self-generated dataset without relying on external APIs. Tech Stack: Computer Vision, Machine Learning Outcome: Accurate and privacy-preserving fitness analytics.   2. Enhancement of Existing IEEE Projects Problem Statement:Enhance an existing IEEE project by integrating advanced technologies to improve performance and real-world usability. Tech Stack: AI, IoT, Edge Computing Outcome: Scalable and deployable solution.   3. WhatsApp Lead Engagement System Problem Statement:Build a system that automatically sends WhatsApp messages to leads and prioritizes prospects based on interactions. Tech Stack: NLP, CRM, Automation Outcome: Improved customer engagement and conversion.   4. AI-Based Resume Screening System Problem Statement:Develop an AI solution that filters and ranks resumes according to job requirements and skills. Tech Stack: NLP, Machine Learning Outcome: Faster and more accurate hiring.   Team Formation: Each team must consist of 2 to 4 members. Inter-college teams are allowed. Inter-department/inter-specialization teams are allowed. A participant can be a member of only one team. Hackathon Format: The hackathon will be conducted in a single round. Teams are required to analyze the problem, design the solution, develop the prototype, and prepare the final presentation within the allotted time. At the end of the hackathon, each team must present and demonstrate their solution before the judging panel. Duration: Hackathon Duration: 24 Hours (Continuous) All project development activities must be completed within the 24-hour hackathon period. General Instructions: Team members must complete individual registration. After registration, payment must also be completed. Teams can be formed on the day of the event. A common community group will be created and shared via the registration confirmation mail for updates and announcements. Teams are free to select the problem statement from give list. The jury&rsquo;s decision will be final and binding. Dinner and Breakfast and refreshments will be provided for both days. Lunch will be not provided. Participants will not be permitted to leave the campus under any condition. Any team leaving the campus within the 24 hours will be eliminated immediately. Participants are advised to carry an extension box and other necessities as required. AC venues will be allocated for all participants. Participants must bring their own water bottles, water refill facilities will be provided. What Participants Gain: National-Level Competition Experience Opportunity to Build Real-World Solutions Networking with Developers and Innovators Participation and Winner Certificates Exciting Cash Prizes and Recognition Organized By: IEEE Student Branch, Kongu Engineering College Tagline: Code for 24 Hours. Create Solutions for Tomorrow.', '2026-06-06T14:59:00+05:30', '2026-07-15T06:29:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/avanzare-v190-24-hour-national-level-hackathon-kongu-engineering-college-1690425', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700757', 'ROBOVANTA ''26 Hackathon – Code & Build for ₹80,000 Prize Pool', 'ROBOVANTA ''26 HACKATHON &mdash; Code. Build. Innovate. Transform₹80,000 Prize Pool  Register here : https://robovanta.vercel.app Got an idea that solves a real problem? Bring it to life in 24 hours at ROBOVANTA ''26 &mdash; India''s most electric inter-college tech fest, hosted at AKV Vidyalaya, Dindigul. This year, Software and Hardware innovators compete together under one roof &mdash; one hackathon, two tracks, one shot at ₹80,000 in prizes. Why Join:₹80,000 prize pool across 7+ award categories &mdash; Winner, Runner-Up, Second Runner-Up, Best Innovation, Best UI/UX, Best Hardware Design, and Best Social Impact Solution. Be part of a 3-day fest with 1000+ participants and 20+ industry speakers. Live problem statements only (no pre-built projects) for a fair, skill-only fight, plus direct visibility in front of expert judges and recruiters. Choose Your Track Software Track &mdash; Build a working software prototype in AI/ML, Web Dev, Mobile Apps, Cybersecurity, Cloud Computing, IoT (software side), HealthTech, AgriTech, Smart Cities, EdTech, FinTech, or Social Impact. Use Python, Java, C/C++, JavaScript, Flutter, React, Node.js, PHP, .NET, SQL/NoSQL, open-source frameworks, and APIs. Hardware Track &mdash; Design and demo a working hardware prototype in Robotics, Automation, IoT, Embedded Systems, AI Hardware, Smart Agriculture, HealthTech, Renewable Energy, Smart Cities, Industrial Automation, or Assistive Tech. Bring your own Arduino/ESP32/Raspberry Pi, sensors, motors, batteries, and tools. FormatProblem statements released at the start of the event. 24-hour continuous build sprint &mdash; design, develop, test. Final demo: 5-minute presentation + 3-minute Q&A before judges. EligibilityTeams of 1&ndash;5 members, open to all college students. Interdisciplinary teams encouraged. One submission per team. No pre-built or previously completed projects &mdash; originality is strictly judged. Judged OnInnovation & Creativity, Technical Implementation, Working Prototype/Functionality, Problem-Solving Impact, Presentation & Demo, and Future Scalability (out of 100 marks). ImportantParticipants must bring their own laptops/development boards/components &mdash; organizers will not provide equipment. No on-spot registration. Teams must report 30 minutes before the event begins. Jul 3&ndash;5, 2026 | AKV Vidyalaya, Dindigul  Register here: robovanta.vercel.app/events(Registrations are open exclusively on our official website &mdash; not through Unstop.)', '2026-06-17T00:00:00+05:30', '2026-07-03T15:12:01+05:30', 'Online', 'online', '₹ 80,000', 'https://unstop.com/hackathons/robovanta-26-hackathon-code-build-for-rs80000-prize-pool-pixor-robotics-club-1700757', 'external', ARRAY['Design', 'Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700357', 'Google Gemini Music Night: Live AI Band Face-off', 'Guidelines, Rules & Rewards: Event Overview: Google Gemini Music Night: AI Band Face-off is a creative innovation challenge where participants will use Google Gemini and Lyria to create a unique virtual band, design a band poster, and generate an original music track inspired by their campus, experiences, culture, stories, and student life Participants may compete individually or in teams of up to 3 members Challenge Flow: Form a team of 1&ndash;3 members Create your band''s identity, including its name, theme, and aesthetic Use Google Gemini to generate and design your band''s official poster Use Lyria to create an original music track that represents your campus, experiences, stories, traditions, culture, or student life Submit the required deliverables before the submission deadline Entries will be showcased and voted upon by participants and the community Submission Requirements: Each team must submit: AI-generated Band Poster Lyria Music Track (shareable link) Team Details Google Gemini chat links/prompts used during creation Completed Feedback Form Rules: Team size must be between 1 and 3 members All submissions must be original and created specifically for this challenge Google Gemini must be used for poster creation Lyria must be used for music generation Copyrighted, plagiarized, or previously published content is strictly prohibited Participants may submit only one final entry per team Any inappropriate, offensive, or misleading content will result in disqualification Organizers reserve the right to verify submissions and request supporting evidence if required The decision of the organizers and judges shall be final Voting & Evaluation: Community voting will be conducted after submissions are received The team receiving the highest number of valid votes will be recognized as the Top Creator of the event Entries may also be reviewed for originality, creativity, storytelling, and effective use of AI tools Rewards & Recognition: National Winner: Google Pixel Buds 2A Top Creator Certificate: Awarded to the participant/team receiving the highest number of valid votes Participation Certificates: Awarded to eligible participants who: Submit all required deliverables Complete the official feedback form Provide the required Google Gemini chat links/prompts used during the challenge Certificates will only be issued after successful verification of submissions and completion of the feedback process', '2026-06-17T00:00:00+05:30', '2026-06-20T21:00:00+05:30', 'Online', 'online', 'Nomination for Google Pixel Buds 2a and Top Prompt', 'https://unstop.com/events/google-gemini-music-night-live-ai-band-face-off-google-student-ambassador-1700357', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700643', 'SRCAS Hackathon 3.0 - What''s the next big idea?', 'SRCAS Hackathon 3.0: SRCAS Hackathon 3.0 is a national-level innovation challenge organized by the Programming Club of Sri Ramakrishna College of Arts & Science (SRCAS), Coimbatore, in association with iGenius, an authorized partner of Microsoft The hackathon focuses on developing innovative solutions aligned with the United Nations Sustainable Development Goals (SDGs) Open Statements (Choose a problem statement by your own) It encourages students to create technology-driven solutions for real-world problems Submit your ideas and register your team  Eligibility: Open to all UG, PG and Engineering students across India Participants must register as a team Teams should consist of 2 to 4 members Members may be from the same or different disciplines, but all members need to be from same college A valid college ID card is mandatory for all participants during the event Registration: Registration Fee: Free Registration Opens: 12 June 2026 Registration Closes: 25 July 2026 Teams must complete the online registration form and submit their project idea before the deadline', '2026-06-17T00:00:00+05:30', '2026-08-15T10:00:00+05:30', 'Online', 'online', '₹ 1,80,000', 'https://unstop.com/hackathons/srcas-hackathon-30-whats-the-next-big-idea-sri-ramakrishna-college-of-arts-science-srcas-1700643', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700622', 'Full Stack Hackathon', 'Hackathon Overview Step into the PaperBuddy Web Hackathon! We are calling on creators, programmers, and critical thinkers to engineer groundbreaking web platforms that will redefine educational technology. Share your most creative concepts and contribute to developing future EdTech solutions designed to optimize and simplify school management. Participation Guidelines Who Can Enter: This event is accessible to every student. We highly welcome and permit collaborative groups formed across different colleges and fields of study. Group Capacity: You may compete individually or assemble a squad of up to four people (1 to 4 participants). Technology Permitted: Completely unrestricted! You have the full liberty to utilize any frameworks, coding languages, cloud platforms, or databases you are comfortable with. Challenges: After registration, participants will be emailed a specific list of challenges. Every group is required to select and tackle just one of these provided issues. Event Structure & Stages The competition is divided into two primary stages: Stage 1 (Concept Pitch): Groups are required to hand in a comprehensive plan that describes their main concept and the technological strategy they intend to use for their selected challenge. Stage 2 (Prototype Creation): Teams that advance past the first stage will move on to construct their web application and hand in a functional, final model. Official Rules Original Code: All programming for the second stage must be authored specifically during the competition window. Turning in previously completed applications will result in immediate removal from the event. Submission Requirements: To complete the final round, groups need to share a public GitHub link featuring their code, coupled with either a live demonstration link or a brief video walkthrough of their creation. Permitted Tools: You are allowed to leverage AI coding aids, open-source resources, and external APIs, as long as they are woven into a unique, custom-built application. Academic Integrity: Copying someone else''s work, whether in the initial concept pitch or the final software, is entirely forbidden. Judging Finality: All verdicts made by the evaluators concerning scoring, advancements, and the ultimate champions are absolute and cannot be contested.', '2026-06-17T00:00:00+05:30', '2026-07-04T17:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/full-stack-hackathon-deenbandhu-chhotu-ram-university-of-science-and-technology-dcrust-murthal-haryana-1700622', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700632', 'Anakin Blitz', 'About Anakin Blitz: Anakin Blitz is a fast-paced virtual hackathon designed for builders who want to ship, not just plan In just six hours, participants will use the Wire API and Anakin Universal Scraper to create something functional, creative, and real No fluff, no filler, just focused building Overview: This isn''t a multi-day marathon with endless brainstorming sessions It''s a tight, high-energy sprint where the constraint is the feature: six hours to go from idea to working product Whether you''re prototyping a tool, automating a workflow, or building something nobody''s tried before, Blitz is about momentum and execution Event Details: When: June 20, 2026, 12:00 PM to 6:00 PM IST Where: Discord (https://discord.gg/5eyFsVPj) What you''ll build with: Wire API and Anakin Universal Scraper Prizes: 1st Place: Keychron Mechanical Keyboard 2nd and 3rd Place: 2,000 Anakin credits each Why Participate: Whether you''re a solo builder or teaming up, Anakin Blitz is your chance to test your speed, creativity, and problem-solving under pressure Walk away with something to show for it Call to Action: Register now and get ready to build', '2026-06-17T00:00:00+05:30', '2026-06-21T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/anakin-blitz-anakin-skywalker-pvt-ltd-1700632', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700212', 'WebChamp', 'WebChamp 2026 is an online web development competition designed to encourage creativity, innovation, and technical excellence in website design and development. Participants are required to design and develop a fully functional website based on the competition theme and submit their work for evaluation by the judging panel. Eligibility Open to university students, school students, and independent learners. Participants may compete individually or as a team. Team size: 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. Participants may submit only one project/team entry. Competition Format Round 1 &ndash; Registration Participants must register through the official registration platform. Teams must provide accurate member details. Round 2 &ndash; Development & Submission Participants will design and develop a website based on the competition theme. Projects can be developed using any web technologies, frameworks, or platforms. Participants must submit: A ZIP file of the project, or A hosted/live website link. A GitHub repository link is highly recommended. All submissions must be made before the submission deadline. Round 3 &ndash; Evaluation Projects will be evaluated by a panel of judges. Judges may access the live website or review the submitted source code. Final results will be announced on the official WebChamp channels. Judging Criteria Projects will be evaluated based on: Creativity and Innovation User Interface (UI) Design User Experience (UX) Functionality and Features Responsiveness and Accessibility Code Quality and Best Practices Performance and Optimization Overall Impact and Presentation Submission Requirements Website must be fully functional. All links and features should work properly. Hosted links must remain accessible during the judging period. Participants must own or have permission to use all assets included in the project. AI tools may be used as development aids, but participants must understand and be able to explain their implementation. Rules All submitted work must be original. Plagiarism or direct copying of existing projects is strictly prohibited. Participants must comply with all deadlines. Offensive, illegal, or inappropriate content will result in immediate disqualification. The organizing committee reserves the right to disqualify submissions that violate competition rules. Judges'' decisions are final and cannot be appealed. By participating, contestants grant the organizers permission to showcase submitted projects for promotional and educational purposes. Participants are responsible for maintaining access to their hosted projects throughout the judging period. Communication All official announcements, updates, and competition-related information will be shared through the WebChamp WhatsApp Community and official communication channels. Certificates & Awards Winners will receive certificates and recognition. Participation certificates will be awarded to eligible participants who successfully complete the competition requirements.', '2026-06-16T00:00:00+05:30', '2026-06-25T10:39:26+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/webchamp-nsbm-green-university-homagama-sri-lanka-1700212', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700041', 'Hackathon: AI for Public Good – Sustainable & Resilient Supply Chains', 'AI for Public Good: Sustainable & Resilient Supply Chains Hackathon The Hackathon is being organized under the Indo-Swiss Research Grant in collaboration with researchers from ETH Zurich, the University of Lausanne, IIIT Allahabad and Manipal University Jaipur alongside WikiClub Tech. Participants will work on real-world challenges in sustainable and resilient supply chains using AI-driven and innovative approaches. Eligibility: Open to undergraduate, postgraduate, and PhD students from all recognized institutions. Students from any discipline are eligible to participate. Inter-college teams are allowed. Inter-specialization/inter-department teams are allowed. Team Formation: Participation is in teams of 1&ndash;3 members. Team members may belong to different colleges, universities, or academic disciplines. One participant can be a member of only one team. Problem Statement: A detailed problem statement will be provided by Lowe''s India, focusing on sustainable and resilient supply chains. Participants are expected to propose innovative solutions addressing the challenge using AI and related technologies. Rules: All submissions must be original work created by the participating team. The use of AI tools (e.g., ChatGPT, Claude, Gemini, etc.) is permitted and encouraged. Teams must clearly explain how AI contributed to refining their solution. Any form of plagiarism will result in immediate disqualification. Teams must adhere to all submission deadlines and guidelines. Organizers reserve the right to modify timelines, evaluation procedures, or event details if required. The decision of the jury and organizing committee will be final and binding. Prizes & Opportunities: Certificates for winning teams. Mentorship and networking opportunities with international researchers and industry experts. Potential research, internship, and collaboration opportunities for outstanding participants. IMPORTANT LINKS Register on Unstop (Hackathon):https://unstop.com/o/UNtyVfK?lb=0rMVMUWm Register on Unstop (Workshop) :https://unstop.com/o/cHq3dRS?lb=0rMVMUWm Join the official WhatsApp community:https://chat.whatsapp.com/ETHdVU9X9Vo8O6LDK4bBY2', '2026-06-16T00:00:00+05:30', '2026-06-30T23:59:00+05:30', 'Online', 'online', 'Official Signed Merit Certificate from Collaborati', 'https://unstop.com/hackathons/hackathon-ai-for-public-good-sustainable-resilient-supply-chains-manipal-university-mu-jaipur-1700041', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699892', 'AI Hackathon.', 'AI & Web Dev Hack-a-Thon &ndash; Hosted by Manas Kumar VermaAPPLY HERE: https://ng.tinyc.co/-aicampAn intensive, project-driven development tournament where elite incoming students compete to build, deploy, and launch production-ready products from scratch. The competition is designed and judged by Manas Kumar Verma, ranked among the Top 15 Programmers in India and a Meta Hacker Cup Winner.The Challenge Blueprint: Over the course of the competition, participants must rapidly architect, code, and deploy 6+ live, real-world projects to climb the leaderboard. The submission portfolio includes: Live News Tracker &ndash; Real-time data streaming and monitoring. Newspaper-Style Web App &ndash; Dynamic content layouts and publishing architecture. Character-Themed Animated UI &ndash; Advanced front-end motion graphics and styling. Document Explorer &ndash; Complex data filtering and search systems. E-Commerce Landing Page &ndash; High-conversion user experience and responsive design. Interactive Browser Piano &ndash; Audio API integration and real-time event handling. Platform: Unstop Timeline & Intensity: Duration: 10 Days of high-intensity, non-stop building and deployment sprints. Eligibility & Rules: Target Audience: Open to students who have successfully passed the 12th grade, including gap-year students (&ldquo;droppers&rdquo;), who are entering engineering colleges. Prerequisites: Zero prior coding experience is required&mdash;your drive to learn, build, and adapt under pressure is what matters. The Golden Rule: This is a pure building competition. Active participation, daily milestone submissions, and completely functional, live-deployed URLs are strictly required to remain in the running.', '2026-06-10T18:11:26+05:30', '2026-08-18T13:06:14+05:30', 'Online', 'online', 'GOOGLE CAMPUS VISIT', 'https://unstop.com/hackathons/ai-hackathon-algo-university-1699892', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699798', 'Ignisys', 'Ignisys Hackathon 2026 A 24-Hour Hackathon at IGNITIA''26 IGNISYS Hackathon 2026 is a 24-hour innovation challenge designed to bring together students, developers, designers, and innovators to build impactful solutions for real-world problems. Participants will collaborate, ideate, develop, and present their projects within the hackathon duration. Eligibility: Open to all Undergraduate and Postgraduate students. Inter-college teams are allowed. Inter-specialization teams are allowed. Team size: 2&ndash;4 members. Format: Round 1: Registration & Team Confirmation Round 2: 24-Hour Development Phase Round 3: Final Project Presentation & Evaluation Themes: Artificial Intelligence & Machine Learning Cybersecurity Healthcare Education Sustainability Open Innovation Productivity & Automation Judging Criteria: Innovation & Creativity Technical Implementation Problem-Solving Approach User Experience Scalability & Impact Presentation & Demonstration Rules: All projects must be developed during the hackathon. Teams must submit an original solution. Use of AI tools, APIs, frameworks, and open-source libraries is permitted. Plagiarism will result in immediate disqualification. Participants must bring their own laptops and necessary accessories. The decision of judges will be final and binding. Perks: Participation Certificates Winner & Runner-Up Recognition Exciting Prize Pool Mentorship & Networking Opportunities  24 Hours. Infinite Possibilities. Don''t Predict the Future. Program It.', '2026-06-16T00:00:00+05:30', '2026-07-28T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ignisys-uem-kolkata-1699798', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699739', 'Innovex 2026', 'Innovex 2026 is a platform for creators, problem-solvers, and aspiring technologists to transform ideas into impactful solutions. Designed to encourage innovation and collaboration, Innovex brings together participants from diverse backgrounds to tackle challenges that matter. Whether you''re passionate about AI, web technologies, cybersecurity, sustainability, or social impact, Innovex provides the opportunity to build, learn, and showcase your talent on a national stage. Challenge Tracks Participants are free to choose any domain, including: Artificial Intelligence & Machine Learning Health & Well-being Education and Learning Solutions Smart Infrastructure & IoT Financial Technologies Green & Sustainable Innovation Cybersecurity and Privacy Agriculture & Rural Development Accessibility and Social Good Open Innovation Who Can Participate? Undergraduate and postgraduate students Fresh graduates and early professionals Individual participants or teams of up to 4 members Innovators from all academic disciplines Competition Journey Phase 1 &ndash; Concept Submission Teams will present their idea along with: Problem Identification Proposed Approach Technologies to be Used Expected Benefits Execution Plan Phase 2 &ndash; Product Development Selected teams will develop their solution and submit: Working Prototype Source Code Repository Documentation Project Demonstration Final Showcase Top teams will pitch their projects before in a detailed video presentation. Judging Parameters Originality and Innovation Technical Excellence Practical Impact User Experience Scalability and Future Potential Participant Benefits Digital Certificates Networking Opportunities Mentorship Sessions Project Showcase Platform Internship and Career Opportunities Exciting Rewards for Top Performers Why Innovex? Innovex is more than a competition&mdash;it''s a community that encourages experimentation, creativity, and meaningful innovation. Think Beyond Limits. Build Solutions. Shape the Future. INNOVEX 2026 &mdash; Where Ideas Evolve Into Impact.', '2026-06-15T00:00:00+05:30', '2026-07-04T01:50:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innovex-2026-jims-engineering-management-technical-campus-jemtec-greater-noida-1699739', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699721', 'Open Source Competition', 'The Elite Coders Open Source Challenge (ECSoC) is a beginner-friendly open source competition designed to help students and developers start their open source journey. Whether you''ve never made a pull request before or you''re already contributing to projects, ECSoC provides a platform to learn, collaborate, and grow. Why Participate? Learn Git & GitHub Make Your First Open Source Contribution Work on Real Projects Connect with Developers Across India Build Your Portfolio Earn Certificates & Recognition Win Swags and Exciting Rewards Who Can Participate? Students Beginners in Open Source Developers Designers Technical Writers Community Builders No prior open source experience required. How It Works Step 1: Register Sign up for ECSoC. Step 2: Join the Community Get access to projects, mentors, and resources. Step 3: Learn & Contribute Choose beginner-friendly issues and start contributing. Step 4: Submit Your Work Create pull requests and complete assigned tasks. Step 5: Get Evaluated Contributions will be reviewed based on quality, impact, and consistency. Contribution Areas Development Frontend Backend Full Stack Mobile Development AI / ML Machine Learning Data Science AI Applications Design UI/UX Design Graphics Branding Content Documentation Technical Writing Tutorials Community Outreach Marketing Community Growth Rewards Top Contributors Digital Certificates Swags & Goodies Community Recognition Internship & Collaboration Opportunities Beginner Support We don''t expect participants to know everything. ECSoC provides: Git & GitHub Guides Open Source Workshops Community Support Mentor Assistance Beginner-Friendly Issues Evaluation Criteria Quality of Contributions Consistency Project Impact Collaboration Documentation Our Mission To help thousands of students make their first open source contribution and become part of the global developer ecosystem. Learn. Contribute. Grow.', '2026-06-15T00:00:00+05:30', '2026-06-30T22:31:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/open-source-competition-elite-coders-1699721', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699516', 'Code Crackdown', 'About the Event Think you have an eye for detail? Put your testing and debugging skills to the test in the ToolsPilot Bug Hunting Challenge! Participants will explore the ToolsPilot platform and identify bugs, glitches, UI/UX issues, broken workflows, security concerns, or any unexpected behavior. Website: https://www.toolspilot.tech/ Registration Period Registration Opens: 15 June 2026 Registration Closes: 27 June 2026 Event Duration Event Starts: 15 June 2026 Event Ends: 28 June 2026 Eligibility Open to all students and professionals. Participants from any college, university, specialization, or organization can participate. Individual participation only. No prior bug-hunting or cybersecurity experience is required. Competition Format Round 1: Bug Hunting Participants will explore the ToolsPilot website and identify bugs (one or more). Bugs may include: Functional bugs UI/UX issues Broken links Workflow errors Performance issues Security vulnerabilities Browser compatibility issues Participants must submit bug reports with: Bug title Steps to reproduce Expected behavior Actual behavior Screenshots or screen recordings (if applicable) Judging Criteria Submissions will be evaluated based on: Severity of the bug Reproducibility Quality of bug report Impact on user experience Originality of findings Duplicate bug reports will be considered only for the participant who submitted them first. Rewards First Prize: Winner Certificate All participants may receive a participation certificate at the discretion of the organizers. Rules Participants must use only legal and ethical testing methods. Any activity that harms the website, servers, or user data is strictly prohibited. Do not attempt Denial-of-Service (DoS/DDoS) attacks. Do not access, modify, or delete data belonging to other users. Automated scanning tools may be used responsibly; however, activities causing excessive traffic are prohibited. Organizers reserve the right to disqualify participants for unethical behavior. The decision of the organizers will be final and binding. By participating, contestants agree that submitted bug reports may be used by ToolsPilot for platform improvement. Submission Process Participants must submit: Bug description Steps to reproduce Evidence (screenshots/videos) The submission link and reporting instructions will be shared with registered participants. Good luck and happy bug hunting!', '2026-06-15T00:00:00+05:30', '2026-06-28T12:00:00+05:30', 'Online', 'online', 'WINNER CERTIFICATE', 'https://unstop.com/hackathons/code-crackdown-amity-university-au-noida-1699516', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699311', 'No Python. No Excuses. Build AI Agents with Mastra', 'HiDevs &times; Mastra Hackathon No PPT. Just Agents. The first AI agent hackathon built exclusively for TypeScript developers. Python was never the gate. It was just the key everyone assumed you needed. For years, the AI agent ecosystem has been dominated by Python-first frameworks. If you wanted to build production-grade agents, you were expected to learn Python before writing your first workflow. Meanwhile, millions of TypeScript developers watched the agent revolution from the sidelines. That changes now. HiDevs &times; Mastra is a flagship AI agent-building hackathon designed for developers who want to build real, production-ready AI systems using TypeScript from end to end. Over multiple rounds, participants will design, architect, and ship autonomous agent systems that solve real-world problems across hiring, finance, legal intelligence, education, incident response, and open innovation. This is not a hackathon for slide decks, mockups, or AI wrappers. Every submission must be a working agent. Event Timeline: The hackathon unfolds across four key milestones, taking participants from architecture design to building and showcasing production-grade AI agents. 13 June &ndash; 19 June 2026 | Registrations Open Register through Luma, Unstop, and the HiDevs Platform. Participants gain access to resources, referral programs, and hackathon updates. 20 June 2026 | Round 1 Begins (Online) Participants receive the problem statements and begin designing their solution architecture using HiDevs Architecture Copilot. The focus of Round 1 is creating a robust agent architecture built around Mastra, Qdrant, and Enkrypt AI. Round 1 Submission Requirements : Participants must submit the following : Product Requirements Document (PRD): outlining the problem, target users, solution approach, key features, user journey, and expected outcomes. Full-Stack Architecture : Document covering agent workflows, Mastra orchestration, Qdrant memory and retrieval, Enkrypt AI evaluation layer, frontend, backend, APIs, databases, integrations, and deployment architecture. Submissions will be evaluated on architecture quality, technical feasibility, innovation, and effective integration of the mandatory technology stack. 2 July 2026 | Round 1 Results The top 300 submissions advance to Round 2. Shortlisted participants will receive feedback on their architecture and begin building their solution based on the architecture submitted in Round 1. 4 July &ndash; 11 July 2026 | Build Sprint Qualified teams will work remotely to transform their approved architecture into a fully functional AI agent using Mastra, Qdrant, and Enkrypt AI. During this phase, participants will build, test, refine, and prepare their solutions for the Grand Finale. 12 July 2026 | Grand Finale (Offline) The top 300 builders will participate in a 12-hour offline hackathon at OJone, Bengaluru, from 10:00 AM to 10:00 PM. Participants will complete final development, receive mentorship, network with fellow builders, and present their working AI agents to judges from Mastra, Qdrant, and Enkrypt AI. Projects will be evaluated on technical implementation, innovation, problem impact, agent capabilities, and effective integration of the mandatory technology stack. Winners will be announced at the conclusion of the event. Prizes, Swags & Recognition: Compete for a ₹50,000 Cash Prize Pool, exclusive sponsor swags, books, and community rewards. ₹50,000 Cash Prize for the Top 5 teams in the Final Round Exclusive Swags from Mastra, Qdrant, and Enkrypt AI Mastra Book for all participants qualifying for Round 2 Top 10 Social Media Awards &ndash; ₹2,000 reward and recognition from HiDevs & Mastra Referral Program &ndash; ₹3,000 reward pool for the Top 20 referrers Total confirmed rewards: ₹50,000 Cash Prize + Qdrant Swags + Enkrypt AI Swags + Mastra Books + Community Recognition. Mandatory Technology Stack: Every submission must integrate all three technologies as core components of the solution. These are not optional integrations or bonus points&mdash;they form the foundation of the entire hackathon experience. Mastra &mdash; Agent Orchestration Layer Mastra powers the intelligence and execution layer of your agent. It is responsible for orchestrating workflows, managing tool calls, routing memory, handling branching logic, enabling human-in-the-loop interactions, and coordinating multi-step agent behavior. Participants are expected to leverage Mastra to build agents that can reason, plan, execute, and adapt across complex workflows rather than relying on isolated prompts. Qdrant &mdash; Memory & Retrieval Layer Qdrant serves as the long-term memory system for your agent. It enables semantic search, vector storage, contextual retrieval, retrieval-augmented generation (RAG), and persistent memory across sessions. Whether you''re building a hiring copilot, a finance advisor, or an incident response system, your agent should be able to remember, retrieve, and reason over historical information to deliver context-aware experiences. Enkrypt AI &mdash; Safety & Evaluation Layer Enkrypt AI ensures that every agent remains reliable, trustworthy, and production-ready. Participants must use Enkrypt AI to evaluate outputs for hallucinations, bias, toxicity, safety violations, and other potential risks before information reaches the end user. The future of AI is not just intelligent&mdash;it must also be safe, transparent, and accountable. Hard Requirement All three technologies&mdash;Mastra, Qdrant, and Enkrypt AI&mdash;must be integrated into every submission. Any project missing even one of the required technologies will be automatically disqualified before judging begins. What You''ll Build: Participants can choose to solve one of several high-impact, real-world challenges designed around autonomous AI agents and production-grade workflows. AI Hiring Copilot: Build an end-to-end recruitment agent capable of analyzing job descriptions, ranking candidates, generating interviews, evaluating responses, and producing recruiter-ready hiring recommendations. Personal Finance & Debt Advisory Agent: Create an intelligent financial advisor that understands spending behavior, analyzes debt obligations, models future financial scenarios, and delivers personalized financial guidance. Legal Document Intelligence Agent: Develop a legal analysis system capable of understanding contracts, identifying risky clauses, answering legal questions, benchmarking against standard practices, and generating safer alternatives. Student Doubt-Solving & Learning Agent: Build a personalized AI tutor that adapts explanations to individual learning levels, tracks weak concepts over time, and provides intelligent academic support across multiple sessions. Incident Response & Post-Mortem Agent: Design an engineering copilot that can analyze logs, detect anomalies, retrieve historical incidents, recommend remediation steps, and automatically generate post-mortem reports. Open Innovation Challenge &mdash; Build Your Own Agent: Have an idea that doesn''t fit a predefined category? Build an original AI agent that solves a meaningful real-world problem using the mandatory technology stack. Across every challenge, participants will design autonomous workflows, retrieval systems, long-term memory architectures, safety evaluation pipelines, and intelligent agent experiences that resemble real production software rather than simple chatbot demos. What Makes This Different: TypeScript-first AI agent development Real production architectures instead of prompt demos Long-term memory powered by Qdrant Agent orchestration with Mastra Safety and evaluation using Enkrypt AI Industry-standard judging focused on engineering depth Direct access to engineers and mentors from the ecosystem Judging Criteria: Projects will be evaluated on: Mastra Integration Depth (25%) Qdrant Integration Quality (20%) Enkrypt AI Coverage (20%) Agent Output Quality (20%) Problem Impact & Novelty (15%) The Challenge: Build an AI-native system that can think, retrieve, remember, evaluate, and act. Not a chatbot. Not a demo. An agent. Because the future of software will be built by interconnected ecosystems of autonomous agents&mdash;and this is where those builders start. Hosted By: HiDevs is a Builder Intelligence Platform for the Agentic Era We help developers transform ideas into production-grade AI agents through personalized guidance, intelligent evaluation, continuous feedback, and contextual memory. By combining specialized AI agents with developer intelligence, HiDevs understands each builder''s goals, tracks their progress, and provides the insights needed to accelerate their journey. Through 100+ community experiences, builder initiatives, and ecosystem collaborations, HiDevs has engaged 15,000+ developers and is building the infrastructure that powers the next generation of AI builders. AIHouse is the community layer powering this ecosystem. Built for founders, researchers, engineers, students, and AI enthusiasts, AI House creates a space where people consistently learn, share, collaborate, and grow together. Through initiatives like 100 Days of AI House, community gatherings, founder conversations, knowledge-sharing sessions, and industry collaborations, AI House has built a thriving network of 15,000+ community members who are actively shaping the future of AI. More than a community, AI House is where meaningful relationships, opportunities, and ideas are created every day. Together, HiDevs and AI House are building one of the fastest-growing AI ecosystems where ideas turn into products, builders become founders, and collaborations turn into impact.', '2026-06-14T00:00:00+05:30', '2026-08-01T21:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/no-python-no-excuses-build-ai-agents-with-mastra-hidevs-1699311', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699309', 'Hack[AI]thon 2.0', 'Hack[AI]Thon 2.0 2026 - Official Event Details About the Hackathon: Hack[AI]Thon 2.0 2026 is a national-level Artificial Intelligence hackathon organized by Sphere Hive in collaboration with VRIF VTU Belagavi. The event brings together students, innovators, and aspiring AI practitioners from across India to compete in a unique Data-Centric AI Challenge. Unlike traditional AI competitions that focus on modifying model architectures, participants will improve AI performance by enhancing dataset quality through intelligent data analysis, strategic labeling, and identification of high-impact samples. Teams will utilize the 3LC.ai platform to analyze embeddings, discover edge cases, optimize training data, and improve overall model performance. The hackathon follows a two-stage competition format, beginning with an online selection round and culminating in a 24-hour offline grand finale hosted at VRIF VTU Belagavi. Eligibility: Open to undergraduate and postgraduate students from recognized institutions across India. Students from all academic disciplines and specializations are eligible to participate. Participants must possess a valid college identity card. Prior experience in Artificial Intelligence or Machine Learning is beneficial but not mandatory. Team Composition: Participation is strictly team-based. Each team must consist of 2 to 4 members. Inter-college teams are permitted. Inter-disciplinary teams are encouraged. Event Format & Venue: Competition Format: Two Rounds Round 1 - Online Selection Round Teams will participate in a virtual screening challenge designed to evaluate problem-solving ability, data analysis skills, and strategic thinking in Data-Centric AI. Round 2 - 24-Hour Offline Grand Finale Selected teams from Round 1 will advance to the final round hosted at VRIF VTU Belagavi, Karnataka. Final Round Dates: 8&ndash;9 August 2026 During the finale, teams will work on a real-world AI challenge focused on image classification and dataset improvement using the tools and workflow provided by the organizers. Competition Structure: Round 1 - Online Selection Round Conducted virtually for all registered teams. Teams will solve a Data-Centric AI challenge within the allotted time. Performance will be evaluated based on the prescribed assessment criteria. Top-performing teams will qualify for the offline finale. Round 2 - 24-Hour Offline Grand Finale Opening ceremony and challenge briefing. Official problem statement release. Continuous 24-hour hacking session. Mentor interactions and technical checkpoints. Final submission, demonstration, and presentation before the judging panel. Prize distribution and closing ceremony. Problem Statement: Participants will receive the challenge statement at the beginning of each round. Teams will be expected to: Analyze datasets and identify quality issues. Detect edge cases and impactful samples. Perform strategic data labeling and curation. Improve model performance through Data-Centric AI techniques. Demonstrate measurable improvements in accuracy and reliability. Evaluation Criteria: Projects will be assessed on: Innovation and creativity Dataset enhancement strategy Improvement in model performance Technical implementation Problem-solving approach Presentation and demonstration quality Rules & Guidelines: All work submitted in the final round must be completed during the official hackathon duration. Teams must provide accurate registration information. Plagiarism, misconduct, or unfair practices will result in immediate disqualification. Participants are expected to maintain professional and respectful conduct throughout the event. Open-source libraries and publicly available resources may be used unless otherwise specified. Participants must bring their own laptops, chargers, and necessary accessories. Internet connectivity and workspace facilities will be provided at the venue. All submissions must be completed before the official deadline announced by the organizers. The organizing committee reserves the right to amend rules, schedules, or procedures if required. All decisions made by the judges and organizers shall be final and binding. Participant Benefits: Certificates for all registered participants. Direct mentorship from industry professionals and AI experts. Networking opportunities with innovators, researchers, and builders. Sponsored goodies and partner benefits. Exposure to modern Data-Centric AI workflows and tools. Opportunity to compete for a ₹35,000 Prize Pool. Additional Information: Cafeteria facilities are available in and around the venue. Limited accommodation support may be available for eligible participants. Detailed instructions regarding the competition, venue access, and reporting procedures will be shared with shortlisted teams before the final round. Beyond Code. Into Intelligence. Hack[AI]Thon 2.0 2026 is more than a competition - it''s a platform to explore the future of Artificial Intelligence through data-driven innovation, collaboration, and problem-solving.', '2026-06-04T00:00:00+05:30', '2026-08-09T00:00:43+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hackaithon-20-sphere-hive-kvg-college-of-engineering-sullia-1699309', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695806', 'TraceBash CTF (Capture The Flag)', 'TraceBash CTF 2026 is a 24-hour online Jeopardy-style Capture The Flag (CTF) competition designed for students, cybersecurity enthusiasts, and professionals from around the world. Whether you''re taking your first steps into cybersecurity or you''re an experienced competitor, TraceBash CTF offers an exciting opportunity to test your skills, learn new techniques, and compete against players globally. Organized by Team TraceBash, one of India''s top-ranked CTF teams, this event features a diverse set of realistic cybersecurity challenges inspired by modern attack and defense scenarios. Event Overview: Format: Team-based or Solo Participation Mode: Online Duration: 24 Hours Start Time: 26 June 2026, 3:00 PM IST End Time: 27 June 2026, 3:00 PM IST Flag Format: TBCTF{example_flag} Prize Pool: ₹5,000 Challenge Release: Two waves of challenges, with the second wave released 12 hours after the competition begins CTF Website: https://ctf.tracebash.xyz/ Discord Link: https://discord.gg/5mgXM9HcM7 Challenge Categories: Participants will encounter challenges across multiple cybersecurity domains, including: Web Security Binary Exploitation (Pwn) Reverse Engineering Cryptography Digital Forensics Open Source Intelligence (OSINT) Miscellaneous Challenges Challenges are designed to test technical knowledge, logical reasoning, creativity, and problem-solving abilities under time constraints. Platform & Community: Participants are strongly encouraged to join the Discord server, where announcements, event updates, support, and public challenge hints will be posted throughout the competition. Rules & Regulations: Participation is open worldwide. Participants may compete individually or as a team. All flag submissions must be made through the official CTF platform. Sharing flags, solutions, or challenge-specific assistance with other participants is prohibited. Attacking event infrastructure, attempting denial-of-service attacks, or abusing unintended platform vulnerabilities is strictly forbidden. Any behavior deemed unfair or against the spirit of the competition may result in penalties or disqualification. Organizers reserve the right to modify rules if required to maintain fairness and event integrity. Scoring & Ranking: Challenges use dynamic scoring. Higher difficulty challenges award more points. Challenge values decrease as more participants solve them. Teams and participants will be ranked based on their cumulative score. In the event of a tie, submission timing may be used as a deciding factor. Support: If you encounter any issues during the competition, support will be available through Discord tickets and event moderators. Technical issues, challenge outages, and platform-related concerns will be addressed as quickly as possible. Why Participate? Compete against players from around the world. Learn practical cybersecurity skills through hands-on challenges. Gain experience across multiple security domains. Win a share of the ₹5,000 prize pool. Join a growing cybersecurity community and connect with fellow enthusiasts. Sharpen your skills, challenge yourself, and prepare to capture the flags. See you on the scoreboard.', '2026-06-06T00:00:00+05:30', '2026-06-27T15:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/tracebash-ctf-capture-the-flag-team-tracebash-1695806', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699053', 'Codesprint2026', 'About the Competition: CodeSprint 2026 is an exciting offline Data Structures and Algorithms (DSA) coding competition designed to test participants'' logical thinking, problem-solving abilities, and programming skills. The competition provides students with an opportunity to showcase their coding talent and compete with fellow programmers in a challenging environment. Participants will solve a set of carefully curated DSA problems ranging from easy to hard difficulty levels within the given time limit. Eligibility: Open to all students of the college. Participants must register before the registration deadline. Individual participation only. No team participation is allowed. Competition Format: Mode: Offline Duration: 90 Minutes Total Questions: 5 Difficulty Levels: Easy: 2 Questions Medium: 2 Questions Hard: 1 Question Programming Languages Allowed: C++ Java Python Rules & Guidelines: Participants must carry their College ID Card. Internet access is strictly prohibited unless permitted by organizers. Any form of plagiarism, copying, or unfair means will lead to immediate disqualification. Participants must submit their solutions before the deadline. The decision of judges and organizers will be final and binding. Late submissions will not be accepted. Participants are expected to maintain discipline throughout the event. Evaluation Criteria: Correctness of Solution &ndash; 70% Time & Space Complexity &ndash; 20% Code Readability & Optimization &ndash; 10% Prizes & Recognition: Winner Certificate Runner-Up Certificate Participation Certificate for all participants Why Participate? Improve Problem-Solving Skills Test Your DSA Knowledge Gain Competitive Coding Experience Build Your Coding Portfolio Network with Fellow Programmers Event Theme: Think Fast &bull; Code Smart &bull; Win Big CodeSprint 2026 &ndash; Where Logic Meets Innovation.', '2026-06-13T00:00:00+05:30', '2026-06-27T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/codesprint2026-technocrats-institute-of-technology-and-main-1699053', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699008', 'Hackathon', 'BGMI PLAYERS, ASSEMBLE!   Ready to drop, loot, survive, and dominate?   Funniche Week BGMI Championship by IIT Guwahati is now open for registrations!   ₹20,000 Prize Pool  FREE Registration Open for Everyone Squad Format (4+1) Tournament: 29 June &ndash; 5 July 2026   Prize Distribution: Champions &ndash; ₹10,000 Runner-Up &ndash; ₹6,000 Second Runner-Up &ndash; ₹4,000   Maps: Erangel Miramar Sanhok Vikendi   ️ Battle against squads from across the country and prove that your team has what it takes to claim the Chicken Dinner!   Don''t have a full squad? No worries! Solo registrations are also allowed, and teams can be formed by the organizers.       Tag your squad and get ready for the ultimate BGMI showdown!     Chicken dinner!!!!!', '2026-06-13T00:00:00+05:30', '2026-06-28T00:00:20+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/indiaruns-2026-national-innovation-challenge-veloris-1699008', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699047', 'Agent{a}thon by Nerds Room', 'About the Event: Agent{a}thon NCR 2026 is a community-driven AI and innovation hackathon designed to bring together ambitious students, developers, builders, and aspiring entrepreneurs from across Delhi NCR and beyond. Hosted by Nerds Room, this hackathon provides a platform for participants to explore the rapidly evolving world of AI agents, automation, and intelligent systems while collaborating with like-minded innovators. Participants will work individually or in teams to build impactful solutions, experiment with emerging technologies, and transform ideas into functional prototypes. Whether you''re a beginner exploring AI for the first time, a developer building your next project, or an aspiring founder validating a startup idea, Agent{a}thon NCR offers a unique opportunity to learn, build, network, and showcase your talent within a thriving technology ecosystem. Theme: Build intelligent solutions powered by AI agents, automation, and emerging technologies that solve real-world challenges across industries and communities. Participants are encouraged to innovate in areas including but not limited to: AI Agents & Autonomous Systems Developer Tools & Productivity Education & Learning Healthcare & Wellness Climate & Sustainability FinTech & Financial Inclusion Community & Social Impact Business Automation Smart Cities & Civic Tech Open Innovation Why Participate? Build Real Projects Transform your ideas into working prototypes and gain hands-on experience with modern AI and software development tools. Learn from Industry Experts Interact with mentors, developers, startup founders, and technology professionals who can guide you throughout the hackathon journey. Expand Your Network Connect with talented students, builders, entrepreneurs, and professionals from diverse backgrounds. Showcase Your Skills Present your solution to judges, mentors, and the broader community. Gain Practical Experience Develop problem-solving, teamwork, communication, and product-building skills through an immersive innovation experience. Access Career Opportunities Demonstrate your abilities, collaborate with industry leaders, and explore future opportunities within the technology ecosystem. Who Can Participate? Agent{a}thon NCR is open to: Engineering Students Computer Science Students Developers AI & Machine Learning Enthusiasts Product Builders Technology Enthusiasts Startup Aspirants Early-Stage Entrepreneurs Designers and Innovators Participants from all academic years and experience levels are welcome. Hackathon Structure: Round 1: Registration & Idea Submission Participants register and submit their profiles, skills, and project ideas. Round 2: Project Proposal Evaluation Shortlisted participants submit a project presentation outlining the problem statement, proposed solution, implementation approach, and expected impact. Round 3: Final Build & Demo Day Selected teams build and present their solutions before a panel of judges, mentors, and community leaders. What You''ll Gain: Hands-on project-building experience Mentorship from industry professionals Exposure to AI and emerging technologies Networking opportunities with builders and founders Recognition for outstanding projects Certificates of participation Community access and future opportunities Event Details Date: 27 June 2026 Duration: 8 Hours Location: Gurugram, Delhi NCR Mode: Offline Team Size: Individual and Team Participation Allowed About Nerds Room: Nerds Room is one of India''s fastest-growing community-driven platforms empowering developers, students, and aspiring entrepreneurs through hackathons, workshops, innovation challenges, networking events, and technical learning initiatives. With a growing network of 25,000+ community members and 100+ community-led initiatives, Nerds Room is committed to fostering innovation, collaboration, and lifelong learning among the next generation of builders. Think. Create. Repeat.', '2026-06-13T00:00:00+05:30', '2026-06-27T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agentathon-by-nerds-room-agentathon-by-nerds-room-vishveshwarya-group-of-institutions-vgi-greater-noida-uttar-1699047', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698998', 'InnovateX', 'InnovateX is a hybrid, project-based hardware product development programme for Indian students, organised by Project GRID in collaboration with the Central Manufacturing Facility (CMF), IIT Delhi. The defining focus of InnovateX is product development, not one-off demos. Every accepted entry must be a hardware product that solves a specific problem for a defined user, with a clear path from a working prototype to a unit that could reach more users. At the pitch stage and again at the final BOM review, participants must address scalability directly: what the product looks like at 100 or 1,000 units, where the bill-of-materials cost sits at volume, and which parts are fragile, hand-tuned, or expensive today and would need to be redesigned for production. Polished answers are not expected, but participants must have thought through these questions and be able to defend them. Originality is valued, but novelty alone is not the gate; the gate is whether the participant thinks like a product builder. Selected participants design and build an original hardware product over roughly three months. GRID funds the bill of materials and reimburses approved purchases against receipts, with each line item reviewed against the product''s scalability story. There is no fixed cap on the BOM. Programme structure (movement between phases depends on GRID approval): Phase 1 - Pitch: Outline the idea, core problem, user, rough materials list, build method, scaling plan, and past work. Phase 2 - Design: Develop the 3D model, schematic, and PCB design; record timelapses; submit a complete materials list for review. Phase 3 - BOM Review and Procurement: GRID reviews every item against the scale story; participants order and are reimbursed for verified purchases. Phase 4 - Build: Assemble, debug, and finalise the build, with required timelapses and optional CMF facility access and mentor review on request. Phase 5 - Exhibition: Final products are exhibited at IIT Delhi before senior figures from government, IIT Delhi leadership, and industry. Eligibility and requirements: Open only to Indian students. InnovateX is a solo programme; team entries are not accepted.  Only 30 participants are shortlisted from across India. Projects must be hardware-focused; software and CS components are welcome only where they support the hardware build. Each project must be framed as a product with a defined problem, user, and form factor, and must address how it could scale beyond the single unit. The bill of materials must be justified line by line and kept lean; each line is reviewed and approved by GRID before procurement. Mentorship philosophy: Mentors review work when students ask. They identify mistakes, suggest directions, and point to references, but they do not design the project or walk students through the build step by step. The aim is to produce students who can read a datasheet, recover from a failed print, think like a product builder, and finish a hardware build under their own steam.', '2026-06-13T00:00:00+05:30', '2026-06-30T20:19:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innovatex-project-grid-1698998', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698930', 'Forge 2 - 1st Edition', 'About the Event: Forge 02 Edition 01 is NMG Labs'' flagship offline Multi-Agent AI Development Sprint, designed for ambitious developers who want to build production-grade AI systems using autonomous agents, modern LLM workflows, and real-world software engineering practices. Unlike traditional hackathons, Forge Sprint 02 challenges participants to build intelligent multi-agent systems where AI agents collaborate through Slack, orchestrate tasks, write code, validate outputs, and ship production-ready solutions within a limited time. This edition is powered by Hermes Agent &times; OpenClaw and brings together some of the country''s most promising builders for an intensive day of learning, building, and competing. Sponsored & Supported By: Forge 02 Edition 01 is proudly sponsored by EastRouter. The event is backed by a growing ecosystem of technology companies, AI startups, and industry partners committed to advancing the next generation of AI builders. Why Participate?: Build a real-world Multi-Agent AI system. Learn production-ready AI workflows used by modern engineering teams. Gain hands-on experience with Hermes Agent, OpenClaw, Slack orchestration, GitHub, and modern AI tooling. Work on a live business challenge under real-world constraints. Showcase your skills before experienced engineers and industry mentors. Network with talented builders from top colleges across India. Gain exposure to leading technology companies and ecosystem partners. Unlock internship and career opportunities at NMG Labs and partner organizations. Event Details: Date: 27 June 2026 Venue: NMG Labs 404, 4th Floor, Global Foyer Mall Golf Course Road, Near Rapid Metro Sector 42-43 Gurugram Mode: Offline Participation Type: Individual Eligibility: B.Tech students (3rd & 4th Year) PG students Recent graduates (within 12 months) Passion for AI, software engineering, and innovation Basic programming knowledge is recommended Participation in previous Forge editions is not required. Sprint Theme: Participants will build a Multi-Agent AI System using: Hermes Agent (Orchestrator) OpenClaw (Coding Agent) Slack GitHub Modern LLMs and AI tooling The challenge statement will be revealed on Sprint Day. Rewards & Opportunities: Champion (1st Prize) &ndash; Cash Prize (To Be Announced) Runner-Up (2nd Prize) &ndash; Cash Prize (To Be Announced) 3rd Place &ndash; Cash Prize (To Be Announced) Additional Benefits: Certificate of Participation NMG Labs Skool Membership Internship opportunities based on performance Priority selection for Forge 03 Opportunity to work on live AI products Learn cutting-edge Multi-Agent AI Development. Hands-on exposure to production AI engineering workflows. Build alongside some of India''s most promising student developers. Industry networking opportunities. Access to the Forge Builder Community. Priority consideration for future NMG Labs events. What to Bring: Personal Laptop Charger Valid College/Government ID Headphones (Recommended) Lunch will be provided by NMG Labs. Selection Process: Registration &rarr; Application Review &rarr; Shortlisting &rarr; Offline Sprint Important Note: This is a highly selective, builder-focused event. Shortlisted participants will receive: Builder Handbook Setup Guide Pre-Sprint Learning Resources Mandatory Prerequisites Event Logistics Participants are expected to arrive with all required software installed and ready to build.', '2026-06-13T00:00:00+05:30', '2026-06-24T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-2-1st-edition-nmg-technologies-1698930', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698904', 'Build.IT ''26', '​Welcome to Build.IT &ndash; the ultimate 48-hour hackathon sprint where code, caffeine, and chaos collide. Coders, designers, storytellers, and makers unite to build bold, original projects &mdash; fast. ​Form a squad of 1 to 4 hackers and get your prompt at kickoff. Then it''s go-time: code, design, and deploy your idea before the clock runs out. Submissions must include your GitHub repo, a short demo video, and a write-up explaining what you built.  Use of AI for help is allowed &ndash; you can use tools like ChatGPT or Copilot for brainstorming, debugging, or clarifying concepts. However, using AI to generate core parts of your project (like major portions of code, designs, or written content) is not allowed. The goal is to showcase your team&rsquo;s creativity and skills, not AI-generated work. Registrations and Updates: Discord: Join for Discord Note: Every teammate needs to register individually on the above link and add the same team name Event Guide(further detail): Updates ​All announcements live on Discord&mdash; so don&rsquo;t miss a beat. ​Whether you&rsquo;re in it for the glory, the grind, or the prizes, Build.IT is where ideas turn real. Do a bit. Try a bit. Win a byte. Judging criteria: Creativity Innovation Prototype Originality  General Rules: The hackathon begins on 15th July 2026 at 12:00 am IST. The prompt will be released at the start of the event. Teams will have 48 hours to build a project based on the prompt. Each team must submit: Project title Brief description Demo or video walkthrough Repository link Submissions must be made on the official platform by 17th July at 12:00 am IST. Only original work will be accepted; plagiarism will lead to instant disqualification. All participants must register in advance using the official registration link. Discord will be used for all event communications. Judges'' decisions are final. Please refrain from messaging the event heads about the decision. Results: Results will be announced on Saturday, 18th July 2026', '2026-06-14T14:01:10+05:30', '2026-07-17T00:00:20+05:30', 'Online', 'online', 'A trophy and certificates of appreciation, 1 XYZ d', 'https://unstop.com/hackathons/buildit-26-bal-bharati-public-school-pitampura-1698904', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697006', 'Mission Y4 Prakasam Police Hackathon 2026', 'Prakasam Police Hackathon 2026 &ndash; Mission Y4 National-Level Online Hackathon Opportunity Description: Prakasam Police Hackathon 2026 &ndash; Mission Y4 is a National-Level Online Hackathon organized by Prakasam District Police in association with Techverza (Sraventix Technologies LLP). The hackathon brings together students, innovators, developers, startups, researchers, and technology professionals to create innovative solutions for real-world public safety and policing challenges using Artificial Intelligence, Data Analytics, Cybersecurity, Automation, and Emerging Technologies. The objective is to encourage technology-driven solutions that can improve public safety, strengthen law enforcement capabilities, enhance citizen services, and contribute towards building a smarter and safer society. Hackathon Theme: "Secure Tomorrow with Next-Generation AI" Join us in developing innovative solutions that strengthen public safety, improve digital security, and create meaningful social impact. Innovate. Secure. Serve. Eligibility: The hackathon is open to: B.Tech Students M.Tech Students MCA Students B.Sc Students Diploma Students IT Professionals Startups Innovators Technology Enthusiasts Team Formation & Registration: Team participation is mandatory. Each team must consist of exactly 3 members. Registration is completely free. One member can register on behalf of the team. Registration must be completed through the official website before the deadline. Registration Deadline: 25 June 2026 11:59 PM IST No registrations will be accepted after the deadline. Rewards & Prizes: 1st Prize: ₹5,000 2nd Prize: ₹2,000 3rd Prize: ₹1,000 Surprise Prize: To be revealed during the Grand Finale Important Timeline: Registration Deadline: 25 June 2026 Project Submission Deadline: 28 June 2026 (11:59 PM IST) Shortlisted Teams Announcement: 30 June 2026 Grand Finale & Top 10 Presentations: 12 July 2026 Grand Finale Presentation: The Top 10 shortlisted teams will be invited to present their projects before the: Superintendent of Police (SP) Prakasam District Police Venue: SP Office, Ongole, Prakasam District, Andhra Pradesh Date: 12 July 2026 The final evaluation and winner selection will be based on innovation, technical implementation, impact, scalability, and presentation quality. Official Problem Statements: Participants may select any one of the following challenge statements and develop an innovative technology solution. Challenge 01 &ndash; AI-Based Social Media Fake Profile & Identity DetectionDifficulty: Medium Focus Areas: Fake Account Detection Identity Verification Deepfake Profile Detection Social Media Fraud Prevention Digital Trust Scoring Challenge 02 &ndash; Smart Vehicle Number Plate Verification SystemDifficulty: Easy Focus Areas: Automatic Number Plate Recognition (ANPR) Stolen Vehicle Detection Fake Registration Identification Traffic Enforcement Automation Challenge 03 &ndash; AI-Powered Crime Detection in Crowded Public AreasDifficulty: Hard Focus Areas: Crowd Anomaly Detection Behavioral Analytics Real-Time Alerts Video Intelligence Challenge 04 &ndash; Criminal Investigation & Suspect TrackingDifficulty: Hard Focus Areas: Suspect Tracking Criminal Intelligence Dashboards Investigation Support Systems Pattern Analysis Challenge 05 &ndash; Cybercrime Detection & Digital FraudDifficulty: Medium Focus Areas: Fraud Detection Scam Identification Cyber Threat Intelligence Transaction Monitoring Phishing Detection Challenge 06 &ndash; Women, Child & Senior Citizen SafetyDifficulty: Medium Focus Areas: SOS Systems Safety Monitoring Emergency Assistance Location-Based Protection Risk Prediction Challenge 07 &ndash; Smart Surveillance & Space MonitoringDifficulty: Hard Focus Areas: Smart City Surveillance AI CCTV Analytics Incident Detection Restricted Area Monitoring Challenge 08 &ndash; Crowd Management & Riot PreventionDifficulty: Expert Focus Areas: Crowd Density Analysis Riot Prediction Event Monitoring Public Gathering Management Challenge 09 &ndash; Traffic Management & Road SafetyDifficulty: Easy Focus Areas: Smart Traffic Control Accident Prediction Traffic Violation Detection Route Optimization Challenge 10 &ndash; Emergency Response & Police DispatchDifficulty: Medium Focus Areas: Dispatch Optimization Emergency Routing Resource Allocation Incident Prioritization Challenge 11 &ndash; Digital Evidence & Investigation AutomationDifficulty: Hard Focus Areas: Evidence Categorization Digital Forensics Support Case Management Automation Investigation Workflow Intelligence Challenge 12 &ndash; Organized Crime & Narcotics IntelligenceDifficulty: Expert Focus Areas: Criminal Network Analysis Intelligence Mapping Pattern Detection Risk Assessment Systems Challenge 13 &ndash; Public Safety & Threat DetectionDifficulty: Medium Focus Areas: Threat Detection Suspicious Activity Monitoring Public Risk Assessment Alert Generation Safety Analytics Project Submission Guidelines: Submission Deadline: 28 June 2026 11:59 PM IST Late submissions will not be accepted. Mandatory Requirement: All team members must join the Official Hackathon Community. Only teams whose members have joined the community will receive access to the Project Submission Form. Required Submission Materials: Project Presentation (PPT) Include: Problem Statement Proposed Solution Technology Stack System Architecture Implementation Details Key Features Impact Future Scope Project Demo Video (2&ndash;3 Minutes) Demonstrate: Project Overview Working Prototype Key Features Innovation Solution Impact Public GitHub Repository Requirements: Complete Source Code Documentation Included Repository Must Be Public Working GitHub Link Private repositories will not be evaluated. Submission Process: Join the Official Hackathon Community Receive Submission Form Access Upload PPT Submit Demo Video Submit Public GitHub Repository Link Complete Submission Before Deadline Evaluation Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Excellence Relevance to Problem Statement Practical Impact Scalability Project Demonstration Code Quality & Documentation Presentation Quality Important Rules: Team size must be exactly 3 members. Every member must join the official community. GitHub repositories must be public. Plagiarism or copied projects will lead to immediate disqualification. Organizers and judges reserve the right to make final decisions. Late submissions will not be accepted. Organized By: Prakasam District Police Technology Partner: Techverza (Sraventix Technologies LLP) Prakasam Police Hackathon 2026 &ndash; Mission Y4 Building Technology for a Safer Tomorrow Free Registration National-Level Online Hackathon Open to Students, Startups & Professionals Top 10 Teams Present at Sp Office, Ongole', '2026-06-09T00:00:00+05:30', '2026-06-22T22:55:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/mission-y4-prakasam-police-hackathon-2026-sraventix-technologies-llp-1697006', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698744', 'Null Origin - 24 Hour CTF Challenge', 'About the Event: Null Origin is a Capture The Flag (CTF) competition designed to challenge and enhance participants'' cybersecurity skills through real-world scenarios and hands-on problem-solving. Participants will face challenges across multiple domains, testing their technical expertise, analytical thinking, and creativity. Whether you''re a beginner exploring cybersecurity or an experienced hacker looking for a challenge, Null Origin provides a competitive platform to learn, compete, and grow. Challenge Categories: Web Security Cryptography Reverse Engineering Digital Forensics OSINT Binary Exploitation Miscellaneous Challenges Event Details: Mode: Online Duration: 24 Hours Team Size: 1-4 Members ( Including Team Leader ) Date: Will be revealed soon. Eligibility: Open to students, professionals, and cybersecurity enthusiasts from all backgrounds. Rules: Participants must follow ethical hacking practices. Attacking the competition infrastructure is strictly prohibited. Flag sharing between teams is not allowed. Any form of unfair advantage may lead to disqualification. Organizers'' decisions will be final and binding. Rewards:  It will be announced soon. We''ve got something really special for you! For queries and support: Official E-mail : nullorigin@cyberhx.com Ready to Trace the Unknown? Join Null Origin and prove your skills where every flag tells a story and every challenge reveals a new attack surface.', '2026-06-12T00:00:00+05:30', '2026-09-18T22:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/null-origin-24-hour-ctf-challenge-cyber-hx-1698744', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698423', 'Agentic Arena : Build the Future with AI Agents', 'Agentic Arena 2026 is a national-level AI innovation challenge designed to bring together students, developers, and technology enthusiasts to explore the power of autonomous AI systems. Participants will design and build intelligent AI agents capable of solving real-world problems across domains such as education, healthcare, productivity, research, customer support, sustainability, and business automation. The challenge encourages innovators to move beyond traditional chatbots and create systems that can reason, plan, utilize tools, and execute tasks autonomously. Whether you are leveraging Large Language Models (LLMs), workflow automation platforms, APIs, multi-agent architectures, or custom AI solutions, this competition provides an opportunity to showcase your creativity, technical expertise, and problem-solving abilities. What Is An Agentic AI? Agentic AI refers to intelligent systems that can independently analyze tasks, make decisions, use tools, and perform actions to achieve specific goals. Unlike conventional AI models that only respond to prompts, agentic systems can plan, reason, and execute multi-step workflows with minimal human intervention. Themes Participants may choose any one of the following themes: Education & Learning: Develop AI agents that enhance learning experiences, provide personalized guidance, assist students, and improve educational accessibility. Healthcare & Wellness: Create intelligent agents that support healthcare awareness, symptom assistance, wellness tracking, and healthcare accessibility. Business & Productivity: Build AI agents that automate workflows, streamline operations, improve decision-making, and enhance workplace productivity. Research & Knowledge Management: Develop agents capable of gathering information, analyzing data, generating reports, and assisting in research activities. Open Innovation: Participants are free to identify and solve any real-world problem using autonomous AI agents beyond the listed themes. Who Can Participate? Undergraduate Students Postgraduate Students AI & ML Enthusiasts Developers & Innovators Individual Participants or Teams Round 1: Agent Blueprint Submission In the first round, participants are required to conceptualize and design an AI Agent that addresses a real-world problem within one of the specified themes. Submission Requirements Problem Statement Proposed Solution Agent Architecture / Workflow Diagram (Optional) Tools, Frameworks, and Technologies to be Used Expected Inputs and Outputs PPT/PDF Submission (Maximum 6 Slides) Evaluation Criteria Innovation & Creativity Problem-Solving Approach Technical Feasibility Clarity of Design Potential Real-World Impact Shortlisted teams will advance to Round 2. Round 2: Agent Implementation & Demo Shortlisted participants must build and demonstrate a working prototype of their proposed AI Agent. Participants may use any suitable technology stack, frameworks, APIs, automation platforms, or AI models to implement their solution. Submission Requirements Working AI Agent Prototype Source Code Repository (GitHub) Demonstration Video (2&ndash;3 Minutes) Project Documentation / README Architecture Diagram Optional Submissions Live Deployment Link n8n Workflow Export Langflow / Flowise Workflow Files API Documentation Evaluation Criteria Functionality & Performance Agent Autonomy & Intelligence Innovation & Technical Complexity User Experience & Usability Documentation & Demonstration Quality Allowed Technologies Participants are free to use any technology stack. Some examples include: OpenAI Gemini Claude n8n LangChain LangGraph Flowise Langflow CrewAI AutoGen Python JavaScript APIs & Automation Platforms Custom AI Solutions Why Participate? Showcase your AI and automation skills. Gain hands-on experience in agentic system design. Build an industry-relevant portfolio project. Compete with talented innovators from across the country. Receive certificates and exciting rewards. Demonstrate your ability to create real-world AI solutions. Note: Live presentations or pitching sessions are not required. All evaluations will be conducted through the submitted documentation, source code repository, architecture design, and demonstration video. Join the Arena The future belongs to intelligent systems that can think, reason, and act. Agentic Arena 2026 invites you to push the boundaries of innovation and build AI agents capable of transforming the way people work, learn, and solve problems. Are you ready to build the next generation of AI agents? Community & Updates All important announcements, updates, deadlines, and participant communications will be shared through the official community group. Join the community here: https://chat.whatsapp.com/KMZh9zQe0gNF4Jdsiozp7h Participants are strongly encouraged to join the community after registration to stay updated throughout the competition.', '2026-06-13T00:00:00+05:30', '2026-06-28T00:00:00+05:30', 'Online', 'online', '₹ 2,000', 'https://unstop.com/hackathons/agentic-arena-build-the-future-with-ai-agents-techverse-solutions-1698423', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693803', 'OSDHack 2026', 'OSDHack 2026 Build AI that runs closer to the user, faster, lighter, more private, and open source. OSDHack 2026 is an online open-source hackathon by Open Source Developers Community (OSDC), built around the theme On Device AI. Your challenge: build something where the core AI feature runs locally on a phone, laptop, desktop, browser, edge device, or embedded system. Think offline-first AI, privacy-friendly tools, browser-based AI, lightweight local models, edge AI, embedded AI, and creative open-source projects that do not depend fully on cloud AI APIs for the main AI functionality. Our Sponsors Theme: On Device AI Your project should focus on AI that runs locally. You can build around: Local AI models Browser-based AI Mobile on-device AI Desktop AI tools Edge or embedded AI Offline-first AI apps Privacy-focused AI utilities Lightweight local inference Cloud services are allowed for support features like hosting, authentication, storage, databases, or deployment. The main AI feature, however, should run on-device, locally, in-browser, on edge, or on embedded hardware. In short: cloud support is fine, but the AI magic should happen locally. Timeline Hackathon Starts: 10 July 2026, 6:00 PM ISTHackathon Ends: 15 July 2026, 6:00 PM ISTFinal Submission Deadline: 15 July 2026, 6:00 PM IST What to Submit Submit your project on Unstop before the deadline. Your submission should clearly show: What you built Why it matters How it works How it uses On Device AI How others can run or try it Your repository should include: Source code Clear README OSI-compliant open-source license Setup or usage instructions Demo video link Screenshots You may use GitHub, GitLab, Codeberg, Bitbucket, or any other public Git hosting platform Mini-Events OSDHack 2026 will also have optional mini-events: CTF MonkeyType CodeBattleships Mini-events are separate from the main hackathon and are open to all. Join our Discord Server for more information Basic Rules To keep things fair and fun: Build around On Device AI Build during the official hackathon period Only commits before 15 July 2026, 6:00 PM IST will be judged Keep your project open source Use an OSI-compliant license Keep your repository public at submission time Respect third-party licenses and give attribution where needed Do not submit copied, plagiarized, harmful, or unsafe projects Detailed rules, FAQs, judging flow, and resources will be shared separately through official communication channels. Stay Connected Join the official Discord server for: Announcements Support Resources Deadline reminders Mini-event updates Community interaction Final Note Build something useful. Keep it open. Try something new. Have fun exploring On Device AI.', '2026-06-08T00:00:00+05:30', '2026-07-15T18:00:00+05:30', 'Online', 'online', '₹ 7,000', 'https://unstop.com/hackathons/osdhack-2026-open-source-developers-communityosdc-1693803', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698293', 'Statify 2.0 - GenAI Bootcamp', 'STATIFY 2.0 is a bootcamp and hackathon organized by FEBS, focused on Generative AI, Agentic AI, and Innovation. The program combines expert-led learning sessions with a competitive Gen AI Hackathon, providing participants an opportunity to learn, build, collaborate, and showcase their skills. "Participation in the bootcamp is entirely free of charge." Event Highlights Industry expert guest sessions Learning resources and guided content Networking opportunities with peers Generative AI Hackathon Skill showcase and competitive learning experience Event Structure 3-Week Learning Phase 1-Week Generative AI Hackathon Learning Phase Requirements Participation in the hackathon is contingent upon attending all weekly learning sessions. Each week includes: Industry Expert Talks Curated Learning Resources Mandatory Quizzes and Assessments Hackathon Specifications Theme: Generative AI Team Size: Up to 4 members Eligibility: Open to participants across India Discord Account: Mandatory for all participants.                                                             ( join the discord community:-https://discord.gg/ymzPmVdg) Important Note Attending the bootcamp sessions is mandatory to participate in the hackathon. Event Date 20th June 2026 &ndash; Bootcamp commencement', '2026-06-11T00:00:00+05:30', '2026-06-18T23:59:00+05:30', 'Online', 'online', '₹ 4,000', 'https://unstop.com/hackathons/statify-20-the-data-science-bootcamp-indian-institute-of-technology-bhubaneswar-1698293', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696915', 'Build With Bharat', 'Build With Bharat 2026 | National Level Hackathon Build With Bharat 2026 is a National Level Hackathon organized by CodeVerse Community, bringing together innovators, developers, designers, and problem-solvers from across India to build impactful solutions for real-world challenges. This hackathon is designed to encourage innovation, collaboration, and technical excellence while providing participants with an opportunity to showcase their skills, network with industry professionals, and compete for exciting rewards. Description: A presentation template will be provided by the organizing team before the event. For now, participants may upload a PPT based on any project idea or concept for registration purposes. Final submission guidelines and the official presentation format will be shared with all shortlisted participants through the official communication channels before the hackathon. Note: The final PPT format and submission requirements will be communicated later by the CodeVerse Community team. Participants are advised to join the official community group for all updates. communication group link- https://chat.whatsapp.com/CQQzfd5AbG2D3Y9EuNdbCj?s=cl&p=i&ilr=4 Event Details: Event Name: Build With Bharat 2026 Organizing Community: CodeVerse Community Date: 01 August 2026 Duration: 8 Hours Mode: Offline Food for All the Participants Venue: Microsoft office Gurugram, Haryana Participation Level: National Team Size: 1&ndash;4 Members Eligibility: Open to all undergraduate and postgraduate students across India. Participants from any branch, specialization, or academic background can apply. Inter-college teams are allowed. Inter-specialization teams are allowed. Participants must register before the registration deadline. Hackathon Format: Phase 1: Registration Participants must register through the official registration portal. Phase 2: Team Formation Participants may participate individually or form teams of up to 4 members. Phase 3: Hackathon Day Teams will work on innovative solutions during the 8-hour hackathon. Phase 4: Project Submission Teams must submit their final project before the submission deadline announced during the event. Phase 5: Evaluation & Results Projects will be evaluated by industry experts and mentors based on predefined judging criteria. Judging Criteria: Innovation & Creativity Problem-Solving Approach Technical Implementation User Experience & Design Scalability & Impact Presentation & Demonstration Rules & Guidelines: Teams can consist of a maximum of 4 members. Inter-college teams are permitted. Inter-specialization teams are permitted. All work must be completed during the hackathon duration. Participants must maintain ethical conduct throughout the event. Any form of plagiarism or copyright infringement may lead to disqualification. The organizing team reserves the right to modify rules if necessary. Judges'' decisions will be final and binding. Participants are responsible for bringing their own laptops and required accessories. Internet access and other event-related facilities will be communicated before the event. Communication: For announcements, updates, venue details, problem statements, and other important information, participants are requested to join the official community group:', '2026-06-09T00:00:00+05:30', '2026-08-01T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/build-with-bharat-codeverse-1696915', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695049', 'HackNexus''26', 'About HackNexus''26: HackNexus''26 is a national-level online hackathon designed to bring together innovative minds from colleges across the country to solve real-world challenges through technology. Whether you''re a developer, designer, innovator, or entrepreneur, HackNexus''26 provides the perfect platform to showcase your skills, collaborate with teammates, and build impactful solutions. With most students on their semester break, HackNexus''26 is structured as a fully online event, allowing participants to learn, build, and compete from anywhere. The hackathon focuses on innovation, problem-solving, technical excellence, and real-world impact. Important Dates: Registration Opens: Live NowLink : https://forms.gle/JWYh9JBu1kBfRBzbA Registration Deadline: 15 July 2026 Round 1 Submission Opens: 10 July 2026 Round 1 Submission Deadline: 20 July 2026 Round 2 and 3 will be announced after these rounds. Registration Fee : Rs. 49/memberRegistration link :  https://forms.gle/JWYh9JBu1kBfRBzbA Check Problem Statements: https://hacknexus.droidecks.sbs/ Eligibility: Open to all college and university students. Participants can register as a team (as per event guidelines). Interdisciplinary teams are encouraged. Hackathon Structure: HackNexus''26 will consist of three competitive rounds. Round 1: PPT & Abstract Submission (Elimination Round) Participants must choose a problem statement from the list of problem statements provided by the organizers and submit: Submission Requirements: Project Abstract Presentation (PPT) PPT Guidelines: There is no predefined template from the organizers. Teams are free to design their presentation creatively. The PPT should contain a maximum of 8&ndash;9 slides covering: Problem Statement Proposed Solution Technical Implementation Approach System/Architecture Diagram Expected Impact Business Model / Scalability Team Information (optional) Conclusion Evaluation Criteria: Problem Understanding Innovation & Creativity Technical Feasibility Impact Potential Presentation Quality Selected teams will advance to the next phase. Round 2: Build Phase Teams shortlisted from Round 1 will develop and implement their proposed solution. Required Deliverables: Source Code Repository (GitHub/GitLab/Bitbucket) Working Project Deployment/Hosting Link Demo Video (Preferred duration: 4&ndash;5 minutes) Project Documentation Impact Statement highlighting the significance of the solution Evaluation Criteria: Technical Implementation Functionality Innovation User Experience Scalability Real-World Impact Documentation Quality Round 3: Final Jury Presentation & Q&A The top-performing teams with exceptional solutions will be invited to the final evaluation round. Format: One-to-one interaction with judges via Google Meet or Zoom Live project demonstration Technical discussion Question & Answer session Evaluation Criteria: Depth of Technical Knowledge Solution Effectiveness Problem-Solving Approach Innovation & Uniqueness Presentation & Communication Skills Impact and Future Scope Why Participate? Compete with talented innovators from across the country. Work on real-world problem statements. Enhance your portfolio with a complete project. Receive recognition from industry and academic experts. Gain valuable experience in ideation, development, and pitching. Ready to Build the Future? Join HackNexus''26, transform your ideas into impactful solutions, and compete with some of the brightest student innovators across the nation. Register now and start your innovation journey!', '2026-06-04T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/hacknexus26-droidecks-1695049', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695186', '#include 1.0', 'About the Event: AWS Student Builder Group (AWS SBG) Hackathon 2026 is a technology innovation challenge designed to encourage students to build impactful solutions using Cloud Computing, Artificial Intelligence, Machine Learning, Data Analytics, and emerging technologies. Participants will collaborate, innovate, and develop real-world solutions to address industry and societal challenges. Eligibility: Open to undergraduate and postgraduate students from all colleges and universities. Students from any department or specialization are eligible to participate. Inter-specialization teams are allowed. Theme: Good Health and Well Being (SDG-3) Quality Education (SDG-4) Sustainable Cities and Communities (SDG-11) Zero Hunger and Sustainable Agriculture(SDG-2) Open Innovation Competition Format: Round 1: Idea Submission Teams submit a problem statement and proposed solution. Round 2: Prototype Development Shortlisted teams develop a working prototype. Teams may use AWS services and other approved technologies. Round 3: Final Presentation & Demo Teams present their solution before the judging panel. Evaluation Criteria: Innovation and Creativity Technical Implementation Feasibility and Scalability User Experience Business/Social Impact Presentation and Demonstration Rules & Guidelines: All submissions must be original work. Plagiarism will result in immediate disqualification. Teams must register before the specified deadline. Participants must adhere to the code of conduct throughout the event. Use of open-source resources is permitted with proper attribution. Organizers reserve the right to modify schedules and rules if required. Decisions made by judges will be final and binding. Teams must submit all deliverables before the deadline. Any unethical, offensive, or inappropriate content will lead to disqualification. Multiple submissions by the same team are not permitted unless explicitly allowed. Deliverables: Project Source Code Presentation Deck (PPT/PDF) Project Documentation Demo Video (if required) Deployment Link (if applicable) Rewards & Benefits: E- Certificates for all participants. Exciting prizes for winners. ( 30 K + Cash Prizes and Swags) Networking opportunities with industry experts. Mentorship from AWS Community Leaders and professionals. Recognition through AWS Student Builder Group community channels. Contact: For queries regarding registration, participation, or event guidelines, participants may contact the organizing committee through the official AWS Student Builder Group communication channels.', '2026-06-05T00:00:00+05:30', '2026-07-25T18:01:00+05:30', 'Online', 'online', '₹ 30,000', 'https://unstop.com/hackathons/include-10-aws-students-builder-groups-smvec-1695186', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697898', 'Hackfluence 2026', 'Hackfluence 2026 is a national-level online innovation challenge for Engineering and B-School students, jointly organized by CodeBenders and Dropp. The hackathon brings together innovators, creators, developers, marketers, and entrepreneurs to solve real-world challenges in AI, creator economy, digital marketing, social commerce, creator monetization, and brand&ndash;creator collaborations. Whether you''re passionate about building AI-powered tools, solving creator challenges, improving influencer marketing, or reimagining the future of digital engagement, Hackfluence 2026 is your opportunity to turn ideas into impactful solutions. Themes: Artificial Intelligence (AI) for Creator tools  Creator Economy Digital Marketing Social Commerce Brand&ndash;Creator Collaboration Creator Growth & Monetization Influencer Discovery & Campaign Management Solutions for Challenges Faced by Creators and Brands Hackathon Tracks: 1. Engineering Track: Round 1: Idea / PPT Submission (17th - 18th June) Teams submit their problem statement, solution, business model, and impact presentation. Round 2: Mentorship & Refinement (19th June)Selected teams receive mentorship and feedback to refine their ideas and execution plans. Round 3: Grand Finale &ndash; Prototype Presentation (21st June)Teams present their working prototype, validation, business potential, and overall solution. 2. B-School Track: Round 1: Idea / PPT Submission (17th - 18th June)Teams submit their problem statement, solution, business model, and impact presentation. Round 2: Grand Finale - Business Solution Presentation (21st June)Teams will present their problem statement, solution, business model, go-to-market strategy, and overall impact. Awards & Recognition: Total Prize Pool: ₹30,000 1st Prize: ₹10,000 Cash Prize 2nd Prize: ₹7,000 Cash Prize 3rd Prize: ₹5,000 Cash Prize 4th Prize: ₹3,000 Cash Prize 5th Prize: ₹1,000 Cash Prize 6th & 7th Position: Exclusive Goodies & Swags Internship Opportunity: The best-performing team will receive an internship opportunity. Certificates for all finalists and recognition across the CodeBenders &times; Dropp community. Why Participate? Solve real-world industry problems Get mentorship from industry experts Build innovative AI-powered solutions Network with creators, founders, and students nationwide Win exciting prizes, certificates, and recognition Just Dropp It.CodeBenders &times; Dropphackathons.ondropp.app Join the official WhatsApp group for queries and updates: https://chat.whatsapp.com/I1dVTS6gnV45kuPyxlnIKP', '2026-06-10T00:00:00+05:30', '2026-06-21T23:59:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/hackfluence-2026-igdtuw-delhi-1697898', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697951', 'TechSpark Hackathon 2026', 'About the Opportunity: Embark on a thrilling journey at the TechSpark Hackathon 2026, proudly presented by Prakash Vidya Mandir Inter College, Kanpur, Uttar Pradesh. This is your chance to dive into the dynamic world of technology through an engaging online coding challenge designed to ignite your problem-solving skills. As an individual participant, you will have the opportunity to showcase your coding prowess and innovative thinking in a virtual environment. This hackathon is a platform to explore your technical capabilities and contribute to the exciting field of technology. Eligibility and Registration: This opportunity is open to individual participants. Competition Structure: The structure for this online coding challenge is as follows: There are no competition stages defined for this event. Join the TechSpark Hackathon 2026 and showcase your coding talent!', '2026-06-11T00:00:00+05:30', '2026-06-25T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/techspark-hackathon-2026-prakash-vidya-mandir-inter-college-kanpur-uttar-pradesh-1697951', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697660', 'Stellan AI Buildathon 2026', 'About the Hackathon: The Stellan AI Buildathon 2026 is a national-level online hackathon designed for students, developers, innovators, and aspiring entrepreneurs who want to build the next generation of AI-powered products. Participants will have the opportunity to solve real-world challenges using Artificial Intelligence, Automation, No-Code Tools, AI Agents, and Emerging Technologies while competing for scholarships, mentorship, internships, and exclusive opportunities. Whether you''re a beginner exploring AI or an experienced builder creating innovative solutions, this hackathon provides the perfect platform to learn, build, and showcase your skills. Theme: Build the Future with AI Create solutions that leverage AI to solve problems in: Education Healthcare Business & Productivity Finance Sustainability Smart Cities Agriculture Creator Economy Student Life Social Impact Eligibility: Undergraduate Students Postgraduate Students Recent Graduates Individual Participants Teams of up to 4 Members Participants from all academic disciplines are welcome. Hackathon Format: Round 1: Idea Submission Submit: Problem Statement Proposed Solution AI Implementation Approach Round 2: Prototype Development Shortlisted teams will develop: MVP AI Solution Automation Workflow AI Agent Web Application Mobile Application Round 3: Final Presentation Present your solution to a panel of mentors, founders, and industry experts. Judging Criteria: Innovation & Creativity Problem-Solving Ability AI Integration Technical Implementation Business Potential User Experience Presentation Quality Rewards & Benefits: Winner 100% Scholarship for the Stellan AI Builder Diploma Program Guaranteed Interview for Internship Opportunities Founder Mentorship Certificate of Excellence First Runner-Up 80% Scholarship for the Stellan AI Builder Diploma Program Career Mentorship Internship Opportunities Second Runner-Up 60% Scholarship for the Stellan AI Builder Diploma Program Industry Mentorship Top 20 Teams Exclusive Builder Community Access Networking Opportunities Special Recognition Certificates All Participants Participation Certificate Access to Exclusive AI Learning Resources Community Membership Why Participate?: Build Real-World AI Projects Showcase Your Skills Gain Industry Exposure Win Scholarships Worth Lakhs Connect with Founders and Mentors Access Internship Opportunities Join a Community of Builders and Innovators', '2026-06-10T00:00:00+05:30', '2026-06-25T14:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/stellan-ai-buildathon-2026-dyndox-1697660', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696924', 'Tech Launchpad 1.0', 'To attend the intro session, join: https://chat.whatsapp.com/KPc3BNtU7cd9ShH1175m5g?mode=gi_t About the Opportunity: With the successful conclusion of MSME Launchpad 2.0, Prodmark Business Consultants Private Limited now presents Tech Launchpad 1.0, an exciting online coding challenge designed for teams to showcase their technical prowess. This event provides a dynamic platform for participants to collaborate and develop innovative solutions in a virtual environment. Problem: Our one of the offerings through MBA Partner (www.mbapartner.in) requires a dynamic website and an application that includes all the possible content that an MBA student requires including, but not limited to, Live Projects, Placements Prep, Case Competitions, Repositories, and Past year testimonials. While we have all these in the best of our capabilities with amazing set of Old IIM Mentors producing magnificent results for 2000+ students in the past, our website doesn''t show it in the best possible manner. Solution: We need a website and a mobile application with amazing UI/UX and an AI Chatbot that helps students navigate through the offerings and get a best experience even before enrollment. Our current website is hosted on Wix and hence, our preference would be to have an alternative one built on the same and integrate it with our existing one. If website built on external platforms can be integrated into Wix, that works as well Eligibility and Registration: This opportunity is open to Team Participation of maximum 3. Seize this chance to join the Tech Launchpad 1.0 online coding challenge and make your mark! Certificates of Appreciation would be given to each one of you.', '2026-06-08T00:00:00+05:30', '2026-06-30T15:59:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/tech-launchpad-10-prodmark-business-consultants-private-limited-1696924', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697413', 'Queue Cure ''26', '76% of India''s 1.5 million clinics still run on paper token slips and shouting. Patients wait 2&ndash;3 hours with zero visibility into when they''ll be called. Doctors have no dashboard. Receptionists manage everything from memory. You''re going to fix that. Queue Cure ''26 is a beginner-friendly Full Stack hackathon hosted on Wooble &mdash; India''s portfolio-first hiring platform where builders get hired on what they build, not what their resume says. What to build: Screen 1 &mdash; Receptionist view: Add patient, call next token, set average consultation time Screen 2 &mdash; Patient waiting room view: Current token being seen, tokens ahead, estimated wait Live sync &mdash; both screens update the moment "Call Next" is clicked  Submission Requirements Submit all 4 of the following to your Wooble portfolio: Working prototype link or demo video GitHub repository with README Socket event diagram Thought process sheet  Evaluation Criteria Criteria Weight Live queue updates correctly across both screens without refresh 40% Wait time computed from real data &mdash; not hardcoded 25% Receptionist screen is fast and mistake-proof 20% Thought process addresses concurrency and edge cases 15% Participant Benefits Participation Certificate Winner Certificate + LinkedIn Badge Portfolio feature on Wooble Interview Opportunity with hiring partners Talent Pool Shortlisting for future roles', '2026-06-10T00:00:00+05:30', '2026-06-25T00:58:00+05:30', 'Online', 'online', '₹ 3,000 + Job Offer/PPI', 'https://unstop.com/hackathons/queue-cure-26-wooble-software-private-limited-1697413', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694233', 'Ship to Get Hired - Gappy AI Hackathon', 'Ship to Get Hired &mdash; Gappy AI Hackathon Build a real AI product. Get hired. Win ₹1 Lakh.Lemma SDK: https://github.com/lemma-work/lemma-platformLive hackathon discussion: https://discord.gg/6dVR7zTvyLemma Docs: https://lemma.work/docsHow to start using lemma: https://lemma-quickstart.vercel.app/ Join our Discord community to stay updated, access how-to guides, find teammates, and get support during the build window. At a Glance Registration: Rolling &mdash; June 8&ndash;29 Build window: June 24&ndash; 2nd July Who can build: Developers, PMs, operators & students Career: Hiring fast-track to partner companies Proof: Project certificates Not just for developers. With Lemma SDK you can build entirely through prompting &mdash; no deep coding background needed. What matters most is clear thinking: a sharply defined problem, real product sense, and the judgment to ship something people would actually use. Developers, PMs, operators, and students are all welcome. What You''ll Build: Build a working agentic app using Lemma SDK as your infrastructure layer. Lemma SDK is upcoming (launching on 24th June) open-source infrastructure for coding agents to build agentic apps that run real work. It provisions ai agents, datastores, document stores, frontend, backend, workflows, functions, and integrations to build ai apps end to end. Pick any real-world problem: a specific user, a clear pain point, and a workflow worth solving. Or build from one of our curated problem statements (to be shared over email after registration) The core loop should work end-to-end and be demoable. Bring your own IDE, AI coding tool, API key, builder platform, and hosting/deployment setup. The Hiring Fast-Track Your submission goes to work for you: Submissions are evaluated for problem clarity, product thinking, and execution quality. Top builders are matched to AI Product Engineer and AI Product Manager roles (full-time and internship role) at partner companies. Your profile &mdash; resume, project summary, and a written rationale &mdash; goes directly to the hiring team. No cold applications. Partner companies may invite you directly for a first-round interview. No CV screening, no recruiter filters. Hiring partners: YesMadam &middot; Binocs &middot; Foxo &middot; Zapdata &middot; CorallyThe Project Track (for top 10 teams, optional): Top 10 teams get the chance to keep building &mdash; with the Lemma team behind them: Two more weeks to refine your submission into a full-fledged product, with direct guidance on architecture, SDK usage, and product decisions. A verified project certificate of contribution &mdash; a real credential, not participation filler. The strongest projects published on the Lemma website as community templates. Timeline: June 8&ndash;29 &mdash; Rolling registrations (the hackathon begins June 24) June 24 &mdash; Lemma SDK launches publicly + build window begins July 2nd &mdash; Submissions close (project + short writeup + working demo) After judging &mdash; Results announced. Winners recognised, and shortlisted builders'' profiles matched and introduced to partner companies. Partner companies may invite you directly for a first-round interview. How We Judge Problem clarity & real-world fit &mdash; 35% Product judgment &mdash; 25% Execution quality &mdash; 25% Lemma SDK utilisation &mdash; 15% What is Lemma? Most software records what happened. Lemma is infrastructure for software that actually does the work &mdash; structured data, AI agents, automated workflows, and custom interfaces in one environment. The SDK is open-source and locally runnable, and it launches publicly on June 24 &mdash; the same day the hackathon begins, so everyone starts fresh.', '2026-06-03T00:00:00+05:30', '2026-07-02T14:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/gappy-ai-hackathon-gappy-ai-1694233', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696682', 'Hackday.Exe 2.0', 'HACKDAY.EXE 2.0 is a 10-hour non-stop virtual hackathon where developers, designers, and problem solvers come together to build AI-powered applications and ship real projects within a single day.join now https://discord.gg/zn4DeAq8d Platform The hackathon will be conducted entirely online via Discord. All announcements, team formation, opening ceremony, mentorship sessions, and event updates will take place on Discord. Participants must join the Discord server before the event begins. Format 10-hour virtual hackathon Individual participation only Opening ceremony on Discord Final submissions through Unstop Prize Categories 1. Best Use of AI APIs Build innovative solutions using Gemini API, Google Cloud AI, or other cutting-edge AI APIs and developer tools. 2. Best Deployed App Develop and deploy a live, production-ready application on cloud infrastructure. Rewards Winners (1st and 2nd place) in each category will receive exclusive gadgets, goodies, official stickers, and sponsor merchandise. Participation certificates will be provided to all participants. Eligibility Open to students, freshers, and developers. No prior experience required. Participants from any college, university, or professional background can apply. Rules & Guidelines Projects must be built entirely during the hackathon window. Gemini API, Google Cloud, or another AI API must be used as a core component of the project. Each participant can submit only one project. Plagiarism or pre-built projects will result in immediate disqualification. All participants must be registered on Unstop. Hackathon Process Step 1 Register on Unstop. Step 2 Join the official Discord server. Step 3 Attend the opening ceremony on 13 June 2026 at 12:00 PM UTC. Step 4 Build your project using Gemini API, Google Cloud, or any AI API. Step 5 Submit your project via Unstop before 10:00 PM UTC. Recommended Tools & APIs Gemini API (Google AI Studio) Google Cloud Platform (GCP) Claude API Other AI and cloud-based APIs', '2026-06-08T00:00:00+05:30', '2026-06-13T23:55:00+05:30', 'Online', 'online', 'Exclusive gadgets + goodies + winner certificate', 'https://unstop.com/hackathons/hackdayexe-20-vel-tech-rangarajan-dr-sagunthala-r-d-institute-of-science-and-technology-1696682', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696902', 'WebForge - A Smart Campus Webathon', 'About the Competition WebForge is a project-based web development competition organized by IEEE Computational Intelligence Society (CIS), MUJ. The event is designed to challenge participants to develop innovative web-based solutions that address real-world problems through technology, creativity, and effective design. Participants will showcase their skills in web development, UI/UX design, problem-solving, teamwork, and project presentation while competing against talented developers from diverse backgrounds. The competition encourages innovation, technical excellence, and user-centric thinking, providing a platform for participants to transform ideas into impactful digital solutions. Eligibility Open to all students. Participants may register individually or as a team. Inter-college teams are allowed. Inter-branch teams are allowed. Participants must complete registration through Unstop before the deadline. Team Rules Each team can have 1 to 3 members. Teams can use any tech stack such as HTML, CSS, JavaScript, React, Node.js, MongoDB, Firebase, Django, Flask, etc. Use of AI tools is allowed, but the team must understand and explain their own project properly. Plagiarism or direct copying of an existing website/template will lead to disqualification. The final submission must be functional enough to demonstrate the main features. Judges&rsquo; decision will be final and binding. The entire event will be conducted in online mode. All rounds, submissions, evaluations, and presentations (if applicable) will take place virtually. Problem Statement: The problem statement will be provided only at the commencement of the event.', '2026-06-08T00:00:00+05:30', '2026-06-14T14:00:00+05:30', 'Online', 'online', '₹ 2,500', 'https://unstop.com/hackathons/webforge-a-smart-campus-webathon-manipal-university-mu-jaipur-1696902', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696130', 'Confluence 2.0 - Beyond The Edge of Possibility', 'About Confluence 2.0: Confluence 2.0 is the flagship international online innovation hackathon organized by THE HELPER, bringing together student innovators, developers, designers, entrepreneurs, and problem-solvers from across the country to build impactful solutions for real-world challenges. Following the success of Confluence 1.0, which empowered hundreds of students to collaborate, innovate, and transform ideas into reality, Confluence 2.0 aims to create an even larger platform for innovation, creativity, and technological excellence. Whether you''re an experienced hacker, a first-time builder, a designer, a visionary entrepreneur, or simply someone passionate about solving meaningful problems, Confluence 2.0 is your opportunity to build, learn, collaborate, and create impact. Tracks: Participants may choose to build solutions in one or more of the following domains:1. Fintech2. Blockchain3. Cyber Security4. AI Automation5. Open Innovation Competition Format: Fully Online Round 1: Registration & Team Formation Participants must register through the official platform. Teams may consist of: Minimum: 2 participant Maximum: 4 participants Participants may participate individually or form teams. Round 2: Idea Submission Registered teams must submit a brief overview of their idea, including: Problem Statement Proposed Solution Expected Impact Team Details Submissions will be evaluated based on innovation, relevance, feasibility, and potential impact. Round 3: PPT Shortlisting Round Shortlisted teams will be required to submit a presentation deck covering: Problem Statement Solution Overview Technical Approach Architecture / Workflow Impact & Scalability Future Scope Teams will be evaluated on creativity, clarity, innovation, feasibility, and presentation quality. Round 4: Hackathon Phase Selected teams will participate in the official hackathon phase and build a working solution within the specified hackathon duration. Teams are encouraged to: Identify real-world challenges Build innovative solutions Demonstrate technical feasibility Create user-centric experiences Present measurable impact Mentorship sessions and expert guidance may be provided during this phase Round 5: Evaluation, Judging & Grand Finale Projects will be evaluated by industry professionals, mentors, and experts based on predefined judging criteria. Top-performing teams will present their solutions before the judging panel through a live demonstration and pitch session. Projects will be judged on: Innovation & Creativity Technical Excellence Problem Solving Impact & Scalability User Experience Presentation & Demonstration Mentorship sessions and expert guidance may be provided during this phase. Eligibility: Open to students from all colleges and universities. Students from any academic discipline are eligible. Inter-college teams are allowed. Inter-specialization teams are allowed. Participants must possess a valid student ID. Individual participation is permitted. Judging Criteria: Projects will be evaluated on: Innovation & Creativity Technical Implementation Problem Relevance User Experience & Design Scalability Impact & Feasibility Presentation & Demonstration Rules & Guidelines: All submitted work must be original. Teams may use open-source tools, frameworks, and APIs. Plagiarism or copying existing solutions may lead to immediate disqualification. Participants must comply with all event timelines and submission deadlines. Organizers reserve the right to disqualify any team violating event policies. Decisions made by judges and organizers will be final and binding. Teams are responsible for ensuring that submitted projects are functional and accessible during evaluation. Any form of misconduct, abuse, or unfair practice may result in disqualification. Submission Requirements: Each team may be required to submit: Project Title Problem Statement Solution Description Presentation Deck Demo Video Source Code Repository Live Prototype (if available) Why Participate? Build impactful solutions Network with innovators from across the country Learn from mentors and industry experts Showcase your skills Compete for exciting rewards and recognition Become part of the growing Confluence innovation community Confluence 2.0: Beyond the Edge of Possibility A Flagship Initiative by THE HELPER', '2026-06-06T00:00:00+05:30', '2026-06-28T17:00:00+05:30', 'Online', 'online', '₹ 20,000', 'https://unstop.com/hackathons/confluence-20-beyond-the-edge-of-possibility-srm-insitute-of-science-and-technology-1696130', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696090', 'IdeaPulley Bug Hunt 2026 — Find Bugs, Win Perks worth $420', 'IdeaPulley Bug Hunt 2026 is a competitive bug-finding challenge open to testers and developers of all skill levels. Participants will explore the ideapulley.com platform and submit well-documented bug reports covering anything from critical security flaws to UI glitches and edge cases. All valid submissions will be reviewed and scored by the IdeaPulley team based on three criteria: severity of the bug, clarity of the report, and reproducibility. The higher the impact, the higher the score. Check the bugs now on www.ideapulley.com and win from perks worth $420 that is ₹40,000, that''s the prize pool so join now!!', '2026-06-05T00:00:00+05:30', '2026-07-05T00:00:00+05:30', 'Online', 'online', 'Velocity Membership(6months) of ideapulley worth $', 'https://unstop.com/hackathons/ideapulley-bug-hunt-2026-find-bugs-win-perks-ideapulley-1696090', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696294', 'FrontEnd Battle 3.0 - VibeCoding Competition', 'Welocme to Frontend Battle 3.0, 2026 , the flagship event of Web and Design Society, IIT Bhubaneswar. This isn''t your typical UI hackathon. You''ll build, optimize, and ship under real-world pressure as each stage pushes your frontend skills in a completely different direction. Expect ambitious requirements, tough constraints, and challenges that test both speed and engineering excellence. No spoilers. Just the clock, the challenge, and your chance to stand out Starts On: 26th June 2026, Ends On: 28th June 2026, Mode: Online (WhatsApp Group) After Registration, Join Our WhatsApp Group Number of Rounds: 2 Eligibility Criteria: This challenge is open to anyone interested in the field of frontend, regardless of experience level or institution. Whether you are a seasoned developer or just starting your journey, we the team of WebnD, IIT Bhubaneswar, welcome you to the epic Frontend Battle where &ldquo;One battle rules them all&rdquo;. Also needless to say, the event being a vibe coded one, use of all the AI tools are permitted without any limitation. Frameworks Allowed: React, Next.js, Vue, Nuxt, SolidJS, Angular, or Vanilla JS. 3D frameworks like three.js are also allowed. Styling Tools: Utility CSS frameworks like Tailwind CSS, Bootstrap, or custom CSS are fully permitted. Round 1: The Qualifying Round Date: 26th June 2026 Time: The problem statement releases at 26th June 2026, 2:00 PM Duration: 4 hours Submission Deadline: 26th June 2026, 6:00 PM Description- The participants will be provided with a  a pre-packed asset ZIP and thier goal is to build a fully responsive, SEO-optimized Web pages. Judgin Criteria and marks distribution upon features added will be mentioned in Problem Statement. Top performers advance to the finale. Round 2: The Finale Date: 28th June 2026 Time: The problem statement releases at 28th June 2026 at 10:00 AM Duration: 12 hours Submission Deadline: 28th June 2026, 10:00 PM Description: The details of this round will be revealed only to the participants who have qualified for this round Bonus : The Bounty Segment This a suprise segment to be introduced in the finale to further spice up the time bound event. Further details to be accordingly shared. FOLLOW OUR INSTAGRAM HANDLE FOR REAL TIME UPDATES AND FASTER REPLY : CLICK HERE', '2026-06-07T17:00:00+05:30', '2026-06-28T22:00:00+05:30', 'Online', 'online', '₹ 12,000', 'https://unstop.com/hackathons/frontend-battle-30-vibecoding-competition-indian-institute-of-technology-bhubaneswar-1696294', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695418', 'Prompt to Product: Build with Gemini', 'Event Details: Date: 13 June 2026Time: 6:00 PM onwardsMode: OnlineTeam Size: 3 Members About the Event: Prompt to Product: Build with Gemini is an online innovation challenge where participants use Google Gemini to transform simple prompts into impactful product ideas. Teams will collaborate to identify real-world problems, generate AI-powered solutions, and present their product concepts. The event is designed to help students develop creativity, problem-solving skills, product thinking, and hands-on experience with Google''s AI ecosystem. Eligibility: Open to all students. Participants from any branch, year, or specialization are eligible. Inter-specialization teams are allowed. Inter-college teams are allowed. Each team must consist of exactly 3 members. Event Format: Round 1: Product Ideation & Development Teams will use Google Gemini to: Identify a real-world problem. Generate an innovative product idea. Define target users and key features. Create a product pitch. Round 2: Product Showcase Duration: 3 Minutes per Team Teams will present: Product Name Problem Statement Solution Overview Key Features Use of Gemini Future Scope Evaluation Criteria: Innovation & Creativity Problem Relevance Effective Use of Gemini Feasibility Presentation & Communication Rules: Teams must contain exactly 3 members. Participants must actively use Google Gemini during the challenge. All submissions must be original. Plagiarism or copied work will result in disqualification. Teams must submit their final work before the deadline announced during the event. Judges'' decisions will be final and binding. Organizers reserve the right to modify the schedule if required. Submission Requirements: Product Name Problem Statement Solution Description Key Features Final Presentation/Pitch Deck Proof of Gemini Usage Event Duration: Approximately 90 -120 Minutes Join us and discover how a simple prompt can become the next big product idea with the power of Gemini AI!  WhatsApp Group Join the official WhatsApp group for event updates, Google Meet links, announcements, and submission details. WhatsApp Group :  Link  All participants must join the group after registration.', '2026-06-05T00:00:00+05:30', '2026-06-13T20:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/prompt-to-product-build-with-gemini-apex-institute-of-management-chandigarh-university-1695418', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695357', 'TradeIQ Quant Street 2026: Emerald Arena Trading Championship', 'Mine the Markets: Minecraft-Themed Trading Challenge for Indian Undergraduates Are you ready to enter the trading arena, mine market opportunities, build your strategy block by block, and survive the volatility? Mine the Markets is a Minecraft-themed simulated trading challenge designed exclusively for current undergraduate students across India. This competition combines the excitement of market trading with the creativity and strategy of Minecraft, giving students a unique platform to test their decision-making, risk management, and analytical skills in a competitive environment. In this challenge, every trade is like placing a block. One wrong move can weaken your structure, but a well-planned strategy can help you build a strong portfolio and climb the leaderboard. Participants will compete in a simulated trading setup where they must identify opportunities, manage capital, control risk, and make smart trading decisions under market-like conditions. This is not just a competition about making the highest profit. It is a challenge of discipline, patience, consistency, and survival. The best traders are not always the ones who take the biggest risks, but the ones who know when to enter, when to exit, and when to protect their capital. Theme: Build. Trade. Survive. Win. Inspired by Minecraft, the challenge is built around the idea of surviving and growing in a dynamic market world. Participants will: Mine opportunities from market movements Craft trading strategies using logic and analysis Build portfolios with disciplined decisions Protect capital from unnecessary risk Survive volatility during uncertain market conditions Climb the leaderboard through consistent performance Just like Minecraft rewards creativity, planning, and survival instincts, this trading challenge rewards students who can think clearly, manage risk, and stay disciplined under pressure. Who Can Participate? This challenge is open to current undergraduate students in India from any college, university, stream, branch, or year of study. You can participate whether you are: A complete beginner curious about trading A finance enthusiast exploring the markets A student interested in competitions and strategy games Someone who wants to test decision-making under pressure A trader looking to compete in a structured simulated environment No professional trading experience is required. The challenge is designed to be beginner-friendly while still being competitive enough for students who already understand the basics of markets. Prize Pool Top-performing participants will compete for an exciting cash prize pool of: ₹20000 Winners may also receive certificates, recognition, and other rewards based on final competition rules. Competition Format Participants will trade in a simulated trading environment. The objective is to perform well while following the rules of the challenge and maintaining proper risk management.NOTE: You have to register through the following link https://www.tradeiqcapital.in/emerald-arena to be eligible to participate in the final competition.', '2026-06-05T00:00:00+05:30', '2026-06-11T23:59:00+05:30', 'Online', 'online', '₹ 2,500', 'https://unstop.com/hackathons/emerald-arena-minecraft-themed-trading-challenge-tradeiq-capital-1695357', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695099', 'Unbound 26 Hackathon', 'About Unbound ''26: Unbound ''26 is the flagship national-level online hackathon organized by FOSS CLUB PU. Over two weeks, student developers, designers, and innovators from across the country will collaborate to build impactful software completely from scratch. Unbound is designed as a 14-day deep dive into Open Innovation, giving participants the time and freedom to architect, build, and refine production-ready prototypes rooted in the philosophy of Free and Open-Source Software (FOSS). Theme: Open Innovation. Participants are free to build any solution that addresses a real-world problem, provided it is open-source. Important Timelines: Registrations Close: June 12, 2026 (Before the Kickoff Hour). Hackathon Kickoff: June 12, 2026. Mid-Way Technical Checkpoint: June 19, 2026. Final Repository Submission & Code Freeze: June 26, 2026 (11:59 PM IST). Results & Winners Announcement: Early July 2026. Golden FOSS Mandates & Rules: Team Size: 1 to 4 members. Cross-college teams are highly encouraged. Every project repository must include a valid OSI-approved open-source license file such as MIT, Apache 2.0, or GNU GPL v3 in the root directory. Submissions without a valid FOSS license will be disqualified. Git commit history will be reviewed to ensure authentic development activity. Single-commit code dumps at the final stage are not permitted. All core logic must be developed during the 14-day hackathon period. The primary application engine must rely on open ecosystem alternatives or open APIs rather than restrictive paid closed-source services. Final Submission Deliverables: Public Git Repository Link (GitHub, GitLab, or Codeberg). Production-ready README.md with setup and installation instructions along with technical architecture details. A 5-minute demo video URL (YouTube or public Google Drive link) showcasing the working prototype. Perks & Benefits: Opportunity to add a production-ready open-source project to your portfolio and resume. Digital certificates for all teams with a valid and verified submission. Hands-on experience in building and contributing to open-source projects. Exposure to collaborative software development and innovation. Additional Information: Break boundaries. Code with freedom. Welcome to Unbound ''26.', '2026-06-04T00:00:00+05:30', '2026-06-28T10:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/unbound-26-hackathon-pondicherry-university-1695099', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694588', 'ELEVATE 2026', 'Elevate 2026: 24 Hours. Infinite Possibilities. A 24-Hour Online Hackathon by Ideakode. About Elevate: Elevate is a 24-hour online hackathon designed to bring together innovators, developers, designers, entrepreneurs, and problem-solvers from across the globe. Participants will collaborate, build impactful solutions, and compete for exciting prizes while networking with industry professionals and fellow creators. Whether you are a beginner or an experienced builder, Elevate provides a platform to transform ideas into reality. Objective: Foster innovation and creativity. Encourage problem-solving through technology. Promote teamwork and collaboration. Provide a platform for learning and networking. Support participants in building impactful solutions. Event Details: Event Name: Elevate 2026. Organizer: Ideakode. Mode: Online. Duration: 24 Hours. Team Size: 1&ndash;4 Members. Registration Fee: Free / As Applicable. Platform: Discord + Devpost/Unstop. Submission Platform: Devpost/Google Form. Result Declaration: Within 7 Days. Eligibility: Open to students, professionals, and tech enthusiasts. Participants must be at least 16 years old. Teams can consist of 1 to 4 members. Cross-college and cross-country teams are allowed. One participant can be part of only one team. Themes: Artificial Intelligence. Healthcare. Education. Sustainability. FinTech. Web3 & Blockchain. Cybersecurity. Smart Cities. Open Innovation. Productivity Tools. Tech Stack: React. Next.js. Angular. Vue.js. Node.js. Python. Java. Flutter. React Native. Blockchain Frameworks. AI/ML Models. Cloud Platforms. Rules & Guidelines: General Rules: All work must be completed during the hackathon period. Teams may use open-source libraries and frameworks. Participants must maintain professional conduct. Any form of plagiarism will result in immediate disqualification. Teams must submit before the deadline. Judges'' decisions will be final and binding. Organizers reserve the right to modify rules if required. Project Rules: Allowed: Open-source libraries. Public APIs. Pre-trained AI Models. Existing frameworks. Design assets with proper attribution. Not Allowed: Copying existing projects. Submitting previously completed projects. Fake demonstrations. Plagiarism. Misrepresentation of team contributions. Judging Criteria: Innovation & Creativity &ndash; 25%. Technical Implementation &ndash; 25%. Problem Solving &ndash; 20%. User Experience & Design &ndash; 15%. Scalability & Impact &ndash; 15%. Total: 100 Points. Submission Requirements: Mandatory: Project Name. Team Details. Problem Statement. Solution Description. GitHub Repository. Live Demo (if applicable). Presentation Deck (PPT/PDF). Demo Video (2&ndash;5 Minutes). Final Presentation: Shortlisted teams may be invited for: Live Product Demonstration. Q&A Session. Technical Discussion. Presentation Time: 5 Minutes Demo. 3 Minutes Q&A. Perks: Participation Certificate. Networking Opportunities. Industry Exposure. Mentorship Sessions. Sponsor Swags. Internship Opportunities. Community Access. Code Of Conduct: Treat everyone with respect. Use inclusive language. Avoid harassment and discrimination. Follow community guidelines. Maintain professionalism. Violations may lead to warnings or disqualification. Communication: Official communication channels: Discord Server. Email. LinkedIn. WhatsApp Community. Participants are responsible for checking announcements regularly.', '2026-06-04T00:00:00+05:30', '2026-06-22T11:01:00+05:30', 'Online', 'online', 'CodeCrafters 2-year VIP membership [EACH MEMBER]', 'https://unstop.com/hackathons/elevate-2026-noida-institute-of-engineering-and-technology-niet-greater-noida-1694588', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694845', 'NetElixir AIgnition 3.0', 'NetElixir AIgnition is an AI and Machine Learning hackathon designed to bring together developers, coders, data scientists, and technology enthusiasts to solve real-world digital marketing challenges using AI/ML technologies. The event focuses on innovation, creativity, and collaboration while providing participants with opportunities to enhance their technical skills, connect with industry professionals, and build impactful solutions. Whether you are an experienced professional or just beginning your journey in AI and ML, AIgnition offers a platform to learn, innovate, and contribute to the future of digital marketing.Join our WhatApp community as it is our primary channel for updates, announcements, and insights throughout the hackathon. Eligibility: Open to coders, developers, data scientists, and machine learning enthusiasts Students, freshers, and professionals can participate Individuals interested in AI, ML, and digital marketing innovation are encouraged to apply Team Size: Individual participation allowed Teams of up to 3 members The first registered participant becomes the team leader and can invite additional members Judging Criteria: Innovation Technical Complexity Real-World Applicability What You''ll Gain: Exposure to real-world digital marketing challenges Hands-on experience in AI and Machine Learning applications Opportunities to collaborate with like-minded innovators Learning through workshops and mentorship sessions Industry networking opportunities Experience working on practical business-focused AI solutions Perks & Benefits: Cash prizes for winning teams Gift cards Exclusive goodies and rewards Networking opportunities with AI and ML professionals Learning and skill development through workshops Recognition and exposure within the AI/ML community Why Participate: Solve real-world business problems using AI and ML Showcase creativity and technical expertise Learn from experienced industry professionals Build meaningful connections within the technology ecosystem Gain practical experience working on impactful projects Compete for exciting rewards and recognition Note: NetElixir AIgnition is more than a hackathon&mdash;it is an opportunity to explore how AI and ML can transform digital marketing while learning, building, and collaborating with innovators from across the country.', '2026-06-04T00:00:00+05:30', '2026-08-05T18:00:00+05:30', 'Online', 'online', '₹ 3,00,000', 'https://unstop.com/hackathons/netelixir-aignition-30-netelixir-1694845', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693945', 'Global Buildathon''26', 'Join the Official Buildathon Community:https://chat.whatsapp.com/Jg9H4Khp9ZNL19k5BqugWiGlobal Buildathon ''26: Global Buildathon ''26 is more than an event. It is a platform for students who want to build, learn, and create impact. About the Event: Vision: To strengthen emerging technologies in our region and encourage students to move from ideas to real solutions Organized by: Baderia Global Institute of Engineering and Management in collaboration with Mew3 India Who should join: Students, beginners, developers, innovators, and problem solvers who want to build something meaningful Themes: EdTech FinTech Web3 and Blockchain AI-Assisted Productivity and Automation Open Innovation Event Details: Date: Sunday, 21st June 2026 Duration: 7:30 AM to 8:00 PM (12 hours) Venue: Baderia Global Institute of Engineering and Management Team Size: 2 to 4 members Prize Pool: ₹10,000+ and certificates Eligibility: Everyone can apply Team Formation: Inter-college and inter-specialization teams are allowed Registration Fee: ₹400 per team Registration Includes: Meals, refreshments, and a full-day innovation experience alongside builders from across colleges and disciplines Judging Criteria: Innovation and creativity Technical implementation Problem-solving approach Scalability and impact User experience and design Important Guidelines: Participants must carry a valid ID card Teams should bring their own laptops and required devices Internet access and event support will be provided Judges&rsquo; decision will be final and binding Plagiarism, copied ideas, or unfair practices may lead to disqualification Additional Awards: Best UI Award Best Innovation Award Best Presentation Award', '2026-06-02T00:00:00+05:30', '2026-06-21T20:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/global-buildathon26-baderia-global-institute-of-engineering-and-management-jabalpur-1693945', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001685358', 'Open Source', 'Themes / Problem Statements: Full Stack Development Open Source SaaS Platforms AI & Automation Tools Cloud & DevOps Utilities Developer Productivity Tools EdTech Solutions API Development & Integrations UI/UX Improvements Bug Fixes & Feature Enhancements Performance Optimization Documentation & Community Contributions Example Contribution Areas: Building new features Resolving existing issues Improving application performance Enhancing UI/UX experience Writing technical documentation Creating reusable components/modules Automating workflows Eligibility and Registration: Open to students and freshers Individual participation is allowed Basic knowledge of Git, GitHub, and programming is recommended Participants from any college, university, or organization can apply Registration is mandatory to participate in the program Registration Process: Register through the official registration portal Join the community and communication channels Access repositories and contribution guidelines Start contributing to assigned/open issues Competition Structure: Phase 1 &ndash; Registration & Onboarding: Participants complete registration Access to repositories, contribution guidelines, and project documentation will be shared Introductory orientation/community session will be conducted Phase 2 &ndash; Issue Selection & Contribution: Participants start contributing to open-source repositories Issues will be categorized based on difficulty: Beginner Intermediate Advanced Phase 3 &ndash; Review & Evaluation: Pull Requests (PRs) will be reviewed by mentors and maintainers Contributions will be evaluated on: Code quality Innovation Documentation Optimization Consistency Phase 4 &ndash; Final Leaderboard & Recognition: Participants with the highest quality contributions and active participation will be featured on the leaderboard Final winners and top contributors will be announced officially Rewards and Prizes: Certificates of Participation Certificates of Excellence for top performers Internship Opportunities Community Recognition Open Source Contribution Experience Mentorship & Networking Opportunities Feature on Official Platforms Swags & Goodies (for selected contributors) Cash Rewards for exceptional contributions Rewards & Prize Details: Top contributors will receive exclusive goodies and certificates Outstanding performers may receive internship opportunities Special recognition will be given to contributors with impactful pull requests and innovative solutions Active contributors may get shortlisted for future hackathons, projects, and hiring opportunities Selected winners may receive cash prizes based on contribution quality and project impact Important Guidelines: All submissions must be original work Plagiarism or spam pull requests will lead to disqualification Participants must follow contribution and code of conduct guidelines Decisions made by mentors and organizers will be final Consistent and quality contributions will be prioritized over quantity Why Participate?: Gain real-world development exposure Build a strong GitHub profile Collaborate with developers nationwide Improve technical and problem-solving skills Work on impactful live projects Unlock internship and career opportunities through open-source contributions', '2026-05-12T22:00:00+05:30', '2026-06-13T11:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/open-source-hackathon-iit-bombay-1685358', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693617', 'CSS Battle', 'CSS BATTLE ABOUT EVENT CSS Battle is a fast-paced frontend competition designed to test your HTML and CSS skills under pressure. Participants will be provided with a target design and must recreate it as accurately as possible using only HTML and CSS within the allotted time. The challenge rewards precision, creativity, optimization, and efficient coding practices. Whether you''re a beginner exploring frontend development or an experienced web designer aiming for pixel-perfect execution, CSS Battle offers the perfect platform to showcase your skills. Judging will focus on visual accuracy, code quality, responsiveness, and innovative CSS techniques. Compete against the best developers, sharpen your frontend expertise, and prove your mastery of modern web design. ELIGIBILITY &bull; Open to all students interested in web development and frontend technologies.&bull; Participants from any college, university, branch, or specialization are eligible.&bull; Both beginners and experienced frontend developers are welcome. PARTICIPATION &bull; Individual Participation Only.&bull; Each participant can register only once. EVENT FORMAT &bull; Participants will be provided with one or more target designs.&bull; The objective is to recreate the design as accurately as possible using HTML and CSS.&bull; JavaScript is not allowed unless explicitly stated by organizers.&bull; Participants must submit their source code before the deadline.&bull; Internet access may be allowed for documentation and references. JUDGING CRITERIA &bull; Visual Accuracy&bull; Code Quality&bull; Responsiveness&bull; Optimization&bull; Creativity and CSS Techniques&bull; Overall Implementation RULES &bull; Only HTML and CSS may be used unless otherwise specified.&bull; External templates and pre-built solutions are prohibited.&bull; Copying another participant''s work will lead to disqualification.&bull; Participants must submit original code created during the event.&bull; Judges may inspect source code during evaluation.&bull; Organizers reserve the right to reject incomplete or invalid submissions.&bull; Judges'' decisions will be final. ADDITIONAL INFORMATION &bull; Event Date: 13 June 2026&bull; Duration: 60&ndash;90 Minutes&bull; Team Size: Individual Participation&bull; Prize Pool: ₹10,000&bull; Certificates for Participants', '2026-06-01T00:00:00+05:30', '2026-06-11T23:30:00+05:30', 'Online', 'online', '₹ 3,000', 'https://unstop.com/hackathons/css-battle-pw-institute-of-innovation-1693617', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693729', 'Vibeathon', 'VIBEATHON ABOUT EVENT Vibeathon is a rapid product-building competition where participants transform ideas into working products within a limited timeframe. A problem statement will be revealed at the beginning of the competition. Teams must design, develop, deploy, and demonstrate a functional MVP that solves the given challenge. Participants are encouraged to leverage modern development tools, AI coding assistants, no-code platforms, and innovative technologies to build impactful solutions. The competition emphasizes execution speed, problem-solving ability, product thinking, user experience, and innovation. If you''ve ever wanted to build a startup idea under pressure and showcase it to judges, Vibeathon is your arena. ELIGIBILITY &bull; Open to all students and technology enthusiasts.&bull; Participants from any college, university, branch, or academic background are eligible.&bull; Developers, designers, innovators, entrepreneurs, and beginners are welcome.&bull; Participants must carry a valid college ID card during verification if required. TEAM FORMATION &bull; Team Size: 1&ndash;2 Participants&bull; Solo participation is allowed.&bull; Cross-college teams are allowed.&bull; Interdisciplinary teams are encouraged.&bull; Each participant can register in only one team. EVENT FORMAT &bull; A problem statement will be revealed at the beginning of the competition.&bull; Teams must ideate, design, develop, and present a working solution within the allotted time.&bull; Participants may use any programming language, framework, technology stack, AI tool, or no-code platform.&bull; The final solution should address the given challenge effectively.&bull; Teams must submit a GitHub repository and a live hosted link before the deadline. JUDGING CRITERIA &bull; Innovation and Creativity&bull; Problem Solving Approach&bull; Product Thinking&bull; Technical Implementation&bull; User Experience and Design&bull; Functionality and Completeness&bull; Presentation and Demonstration RULES &bull; All work must be completed during the competition duration.&bull; Open-source libraries, frameworks, APIs, and AI tools are allowed.&bull; Plagiarism or copying existing solutions will result in immediate disqualification.&bull; Teams must disclose any AI tools, APIs, or third-party services used.&bull; Judges'' decisions will be final and binding.&bull; Organizers reserve the right to modify rules if necessary. ADDITIONAL INFORMATION &bull; Event Date: 13 June 2026&bull; Duration: 60 Minutes&bull; Submission: GitHub Repository + Live Hosted Link&bull; Team Size: 1&ndash;2 Participants&bull; Cash Prizes for Winners&bull; Certificates for All Participants', '2026-06-02T00:00:00+05:30', '2026-06-11T23:30:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/vibeathon-pw-institute-of-innovation-1693729', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693953', 'Willovate Talent Hunt - AI/ML', 'Tired of sending resumes into a black hole? Skip the tedious HR rounds and prove your engineering merit directly on production-level AI architecture. Willovate Lab presents a high-octane 48-hour challenge designed exclusively for elite AI/ML Engineers. The 48-Hour Sprint Timeline Registration Closes: Friday, June 5, 2026 | 11:59 PM IST Challenge Drop: Saturday, June 6, 2026 | 10:00 AM IST Submission Deadline: Sunday, June 7, 2026 | 09:00 PM IST Results Announcement: Wednesday, June 10, 2026 | 4:00 PM IST The Challenge: Intelligent Operational Systems On Saturday morning, you will unlock a production-grade problem statement. You will have exactly 48 hours to build, train, and deploy an AI/ML functional module from scratch. Model Engineering: Efficient data preprocessing, model selection, and optimization for real-time inference. Backend Integration: Seamless deployment of ML models within scalable API architectures (e.g., FastAPI/Flask with Docker). Edge Cases: Handling data drift, latency optimization, and robust error management for production pipelines. Rewards & Perks: Prize Pool: ₹1,000 cash for top leaderboard performers. Direct Internship: Exceptional engineers bypass standard screening and move straight to final internship interviews. Portfolio Asset: Build a concrete, production-ready AI/ML project on your public GitHub to showcase your technical depth. Submission Rules: Participation: Individual (Solo) only. Hosting: All source code and model artifacts must be hosted in a public GitHub repository. Proof of Work: Your repository must include a `README.md` with a 1-minute video link demonstrating your model&rsquo;s performance and live inference capabilities. Entry & Contact: Dev Support: +91 9420020895 The Rule: No Resumes. No Interviews. Just Merged PRs.', '2026-06-02T00:00:00+05:30', '2026-06-05T23:59:00+05:30', 'Online', 'online', '₹ 1,000', 'https://unstop.com/hackathons/willovate-talent-hunt-aiml-willovate-1693953', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694161', 'Build an AI Trading Agent', 'Build an AI agent that trades the market &mdash; and find out if yours is the best. Everyone''s building "AI agents" right now, but no one can really say which one is good. builderr fixes that: you build an agent, we run every agent on the same live market data with the same rules, and rank them fairly. The winner''s code trades a real $100,000 on Nasdaq, with the P&L posted publicly. How to video (no coding knowledge needed) : https://builderr.ai/builderr-intro.mp4  Why take part: Win real money &mdash; 2 Lakh INR prize pool, and the #1 agent trades a real $100,000 (public P&L). Easy to start, even if you''ve never traded &mdash; you write one small agent. Fork the template, run one command to test locally. No install, no API key, no money, no finance background. A basic working bot is a few lines. A standout for AI  &mdash; finishing well proves two things at once: you can build with AI . Real, public proof-of-work with your name on a live leaderboard. What you build: one agent, decide(), that looks at recent prices each day and returns what to buy/sell. We handle data, execution, and scoring. How it works: Fork the starter template (free, open-source). Fill in decide() &mdash; or just rename the sample bot for an instant valid entry. Run python preview.py to see it clear the safety checks in ~10 seconds. Submit your repo link. Improve and resubmit up to 4 times during the round. Who can join: anyone &mdash; students, freshers, professionals. Solo or in a pair. No finance or ML background needed. Rules (kept fair): same data, same fills, same caps for everyone. Long-only, sane risk limits, no using future data. Ranked by risk-adjusted return, with a held-out re-run so the winner has real skill, not luck. Timeline: Round 1 is live now and runs through 2 July 2026. Submit early &mdash; the sooner you''re in, the more of the window your agent trades. Prizes: 1st &mdash; 1,20,000 + your code trades the real $100,000 &middot; 2nd &mdash; 50,000 &middot; 3rd &mdash; 30,000 &middot; Top finishers get a public spotlight. Start: builderr.ai/trading-v0 &middot; Template: github.com/builderr-ai/builderr-trading-template', '2026-06-03T00:00:00+05:30', '2026-06-17T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/build-an-ai-trading-agent-httpsbuilderraitrading-v0-builderrai-1694161', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693833', 'Bharat Academix CodeQuest', 'Please complete this mandatory Google Form:  https://forms.gle/P1Ej9eX3Rf4W5otUA About the Hackathon: Bharat Academix invites students, developers, innovators, designers, and technology enthusiasts from across India to participate in the Bharat Academix CodeQuest Hackathon 2026. This national-level hackathon is designed to encourage participants to build innovative solutions that address real-world challenges using Artificial Intelligence, Machine Learning, Data Science, Web Development, Mobile Applications, Cloud Computing, Cybersecurity, IoT, Blockchain, and other emerging technologies. Participants will collaborate, innovate, and compete to create impactful solutions while gaining valuable experience, networking opportunities, industry exposure, and exciting rewards. Themes: Participants may develop solutions in one or more of the following domains: Artificial Intelligence & Machine Learning Healthcare Technology Education Technology Smart Cities FinTech Agriculture & Rural Development Sustainability & Climate Tech Cybersecurity Social Impact & Accessibility Open Innovation Eligibility: Open to College Students, Freshers, and Professionals. Participants from all academic disciplines are welcome. Individual participation or teams of up to 3 members are allowed. Participants must have access to a laptop and internet connection. Cross-disciplinary teams are encouraged. Hackathon Structure: Round 1: Idea Submission Participants must submit: Problem Statement Proposed Solution Technology Stack Expected Impact Project Roadmap Round 2: Prototype Development Shortlisted teams will: Build a working prototype Submit source code and documentation Prepare a presentation/demo video Demonstrate the feasibility and scalability of the solution Grand Finale: Finalist teams will present their solutions before the evaluation panel comprising industry experts, researchers, and technology professionals. Evaluation Criteria: Innovation & Creativity &ndash; 25% Technical Implementation &ndash; 25% Problem-Solving Approach &ndash; 20% User Experience & Design &ndash; 15% Scalability & Impact &ndash; 15% Rules: Solutions must be developed during the hackathon period. Team members must actively contribute to the project. Plagiarism, copied projects, or fraudulent submissions will result in immediate disqualification. Open-source libraries and frameworks may be used. Participants must own or have permission to use all submitted content. The decision of the judges and organizers shall be final and binding. Bharat Academix reserves the right to modify timelines if required. Additional Benefits: Participation Certificates for all eligible participants Winner & Runner-Up Certificates Internship Opportunities with Bharat Academix Networking with Industry Experts Project Showcase Opportunities Recognition on Official Platforms Career Development Opportunities Why Participate? Build innovative real-world solutions Showcase your technical and problem-solving skills Gain industry recognition Learn from mentors and experts Strengthen your resume and portfolio Compete with talented innovators from across India Win exciting cash prizes and career opportunities Join the Innovation Revolution Innovate. Build. Impact. Join the Bharat Academix CodeQuest Hackathon 2026 and transform your ideas into powerful solutions that can shape the future.', '2026-06-02T00:00:00+05:30', '2026-06-28T16:00:00+05:30', 'Online', 'online', '₹ 1,00,000 + Job Offer/PPI', 'https://unstop.com/hackathons/bharat-academix-codequest-bharat-academix-1693833', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693413', 'DevFusion 3.O | The Developers Hackathon', 'Rules & Guidelines: Read carefully before registering. Participation implies full acceptance of all rules listed below. Eligibility: Open to school and college students. Participants must be from the 2028 to 2032 graduation year batch (college) or currently enrolled in Grade 10, 11, or 12 (school). Teams must have a minimum of 2 members and a maximum of 4 members. Each member must have a separate Unstop account. A participant cannot be part of more than one team. Registering with multiple accounts or teams leads to immediate disqualification. All team members must be registered on Unstop before the registration deadline. Late additions will not be accepted. This hackathon is focused exclusively on app development. Only participants who intend to build mobile applications are eligible and encouraged to register. Registration Rules: Registration is completely free of cost and must be completed via the official Unstop listing only. Registrations through any other channel will not be accepted. Fill out the screening form honestly and completely. Misleading or incomplete submissions will be filtered out at Round 0 itself. A valid portfolio link, GitHub profile, or past project URL must be provided during registration. Blank entries will be rejected. Do not use fake or borrowed profiles. All submissions will be cross-verified during the project review and code review rounds. Registrations close on the deadline date. No extensions will be made under any circumstances. Event Structure &mdash; Four Rounds: Round 0 &mdash; Screening Round An initial screening to assess participant intent and background. Participants must fill out a form covering their app development experience, past projects, and motivation to join. Incomplete or dishonest responses will be filtered at this stage. Round 1 &mdash; Aptitude Round An online aptitude test covering logical reasoning, technical fundamentals, and problem-solving. This round is designed to assess conceptual clarity and analytical thinking. Time-bound and auto-evaluated. Round 2 &mdash; Previous Project Submission Round Shortlisted participants must submit a mobile application they have previously built. This is not the hackathon project &mdash; this is proof of your existing app development capability. Submit the APK or live link, GitHub repository, and a short write-up explaining your role, the tech stack used, and the problem it solves. Round 3 &mdash; Main Hackathon (App Development) The core of DevFusion 3.0. A problem statement will be revealed at the official start time. Teams must build a fully functional mobile application within the defined hackathon window. No pre-built work is allowed. Your app must be submitted with a working APK or live link, GitHub repository, demo video, and README. Round 4 &mdash; Interview Round Top-performing teams from Round 3 will be called for a 15&ndash;30 minute interview with the evaluation panel. Attendance at this round is mandatory to be eligible for final results and offers. Participation & Conduct Rules: What you should do: Work only within your registered team. No external help is allowed. Use any open-source libraries, frameworks, or UI kits freely. Commit your code regularly &mdash; git history will be reviewed by judges. Document your project clearly in the README file. Be respectful and professional toward all participants, judges, and organizers. Reach out to organizers only through the official Unstop messaging system for any clarifications. What you must not do: Take help from anyone outside your registered team during the hackathon window. Submit work that was built before the hackathon officially started. Use paid third-party code or assets without proper disclosure in your README. Copy or plagiarise another team''s solution, idea, or codebase. Use AI tools to generate your entire codebase without any original contribution. Share your solution or the problem statement publicly before results are announced. Harass, bully, or disrespect any participant, judge, or organizer in any manner. AI Tools Policy: Using AI tools like GitHub Copilot, ChatGPT, or similar for assistance is permitted. However, the core logic, architecture, and implementation must be your own original work. Submissions that appear to be entirely AI-generated with no individual thought or structure will be penalised or disqualified at the judges'' discretion. Build Rules (Round 3 &mdash; Main Hackathon) The problem statement will be revealed only at the official start time of Round 3. Building before the problem is released is strictly not allowed. You may use any mobile development framework or language &mdash; Flutter, React Native, Kotlin, Swift, Dart, or anything else you are comfortable with. Open-source libraries, UI component kits, and design templates are allowed as building blocks. You must mention what you have used in your README. Pre-built projects, clones, or work started before the hackathon window are strictly not allowed. Judges will check commit timestamps and history. Your app must be submitted with either a working APK link or a live deployment accessible for testing. Apps that cannot be evaluated will be disqualified. Your GitHub repository must be set to public at the time of submission. Private repositories will not be reviewed. No submission deadline extensions will be granted under any circumstances. Late submissions will be automatically rejected by the system. Submission Guidelines: Every submission must include all of the following. Incomplete submissions will not be evaluated. Working App Link / APK &mdash; A publicly accessible link to install or test your mobile application. The app must remain functional throughout the evaluation period. GitHub Repository Link &mdash; Public repo with full source code and a meaningful commit history. A single "initial commit" dumping all code at once will raise serious flags. Demo Video (3&ndash;5 minutes) &mdash; A screen recording walking through your app, covering the features built, the tech choices made, and what you would improve given more time. Upload to YouTube (unlisted) or Google Drive and paste the link in your submission. README File &mdash; Must include a project overview, tech stack used, local setup and build instructions, list of features built, and any known limitations or future scope. Short Write-up (via Unstop submission form) &mdash; A 100&ndash;200 word description of your approach, the biggest challenge you faced, and what you are most proud of in your submission. Important: Double-check that all your links are working and publicly accessible before hitting submit. Broken links or private repositories will be treated as incomplete and will not be re-evaluated after the deadline. Code of Conduct: Treat all participants, judges, and organizers with respect and professionalism throughout the event. Harassment, bullying, hate speech, or discriminatory behaviour of any kind will result in immediate disqualification and a permanent ban from future events. Sharing your solution or discussing the problem statement publicly on social media, Discord, WhatsApp groups, or any public forum before results are announced is strictly prohibited. Any attempt to bribe, influence, or contact judges directly outside official channels will lead to immediate disqualification. All disputes, concerns, or complaints must be reported to the organizers via the official Unstop messaging system only. Judging & Results: All submissions will be reviewed by a panel of judges. Their decisions are final and binding. Individual scoring breakdowns will not be shared. Projects are evaluated across six criteria: Code Quality &mdash; 25 points App Functionality & Performance &mdash; 25 points UI / UX Design &mdash; 20 points Tech Stack Choices &mdash; 15 points Documentation & README &mdash; 10 points Demo Video & Presentation &mdash; 5 points The top teams from Round 3 will be invited for a 15&ndash;30 minute interview in Round 4. Availability for this call is mandatory to be eligible for final ranking and offers. Results are not negotiable. Requests for re-evaluation, score breakdowns, or personal feedback will not be entertained after the announcement. Results will be declared on Unstop and communicated via email within 5 business days of the final round. Grounds for Immediate Disqualification: Plagiarism or submitting pre-built work Using fake or borrowed profiles Registering with multiple accounts or across multiple teams Sharing the problem statement publicly before results Misconduct or disrespectful behaviour toward any stakeholder Failure to appear for the Round 4 interview without prior notice Intellectual Property: By submitting, you grant the organizers the right to showcase your project &mdash; with full credit to your team &mdash; on our website, social media, or other promotional materials. If you use any third-party assets, templates, or open-source code, ensure they are properly licensed and credited in your README file. General Terms: The organizers reserve the right to modify these rules at any time. Registered participants will be notified of any significant changes via email and the Unstop platform. Continued participation after any rule update implies full acceptance of the revised guidelines. In case of any ambiguity or dispute, the organizers'' interpretation of the rules will be considered final. DevFusion 3.0 is a completely online event. Participants are responsible for their own internet connectivity and device setup.', '2026-06-01T00:00:00+05:30', '2026-06-29T11:01:00+05:30', 'Online', 'online', 'Goodies + Internship Opportunity to Complete Team', 'https://unstop.com/hackathons/devfusion-3o-the-developers-hackathon-iit-bombay-1693413', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001687351', 'SmartAIthon 2026 Campus Ambassador', 'The SmartAIthon 2026 Campus Ambassador Program is an opportunity for enthusiastic students to represent and promote SmartAIthon 2026 &ndash; IEEE Smart Cities AI Hackathon within their campus and student communities. Selected ambassadors will play a key role in expanding the reach of the hackathon through social media promotion, community outreach, and participant engagement. The program is designed to help students develop leadership, communication, networking, and community-building skills while contributing to a large-scale innovation initiative aligned with smart city and AI technologies. Ambassadors will work on promotional tasks such as sharing official posters, promoting the event on LinkedIn and social media, and encouraging student participation from their institutions and networks. Responsibilities: Promote SmartAIthon 2026 on LinkedIn and social media Share event posters in student communities and WhatsApp groups Increase awareness and participant registrations Support outreach activities during the hackathon timeline Benefits: Official Appreciation Certificate Recognition on SmartAIthon social media platforms Networking opportunities with students and organizers Community leadership and event management exposure Recognition: Ambassadors who successfully complete the assigned activities will receive an official Appreciation Certificate on August 25, 2026. Top-performing ambassadors based on outreach and registrations may receive special recognition. Selected ambassadors will be announced in multiple phases during the program timeline.', '2026-06-01T00:00:00+05:30', '2026-06-30T23:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/smartaithon-2026-campus-ambassador-program-httpsbitlysmartaithon-ieee-kce-student-branch-cis-chapter-1687351', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001692241', 'Simply Updify InnovateX 2026 – National Level Online Hackathon', 'Simply Updify InnovateX 2026 is a national-level online hackathon designed to bring together innovators, developers, designers, and problem-solvers to create impactful technology-driven solutions. This hackathon provides participants with an opportunity to showcase creativity, technical skills, and innovation while solving real-world challenges through technology. Objective: The objective of this hackathon is to encourage participants to build innovative, scalable, and practical solutions across various domains using modern technologies. Themes: Participants may build projects under (but not limited to) the following categories: Artificial Intelligence & Machine Learning Web & Mobile Development Cybersecurity Automation & Productivity Tools SaaS Solutions Open Innovation Smart Systems & Emerging Technologies Team Structure: Minimum Team Size: 2 Members Maximum Team Size: 4 Members Competition Format: Phase 1 &ndash; Registration Team Registration Idea / Abstract Submission Phase 2 &ndash; Development Round Project Development Documentation Preparation Demo Creation Phase 3 &ndash; Evaluation Round Project Submission Demonstration & Presentation Jury Evaluation Evaluation Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Implementation Problem-Solving Approach Scalability & Impact Presentation & Demonstration Rules & Guidelines: All submissions must be original work. Plagiarism or copied projects will result in immediate disqualification. Teams must adhere to submission deadlines. Participants must follow all competition guidelines and rules. The decision of the organizing committee and judges shall be final. Eligibility: This hackathon is open to: College Students Freshers Professionals Technology Enthusiasts Mode of Conduct: Online Why Participate? Gain national-level exposure Network with innovators and developers Showcase technical and creative abilities Receive participation certificates and recognition Build impactful solutions for real-world challenges Build. Innovate. Create Impact.', '2026-05-30T00:00:00+05:30', '2026-06-15T00:30:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/simply-updify-innovatex-2026-national-level-online-hackathon-simply-updify-1692241', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001688859', 'Amazon ML Summer School 2026', 'Amazon ML Summer School aims at providing students the opportunity to gain Machine Learning (ML) skills and which is the first step in becoming ready to build a career in ML. This program is an intensive course on key ML topics and is a great opportunity to learn from and interact with Scientists at Amazon who have immense knowledge in their ML domain. After the successful fifth edition in 2025, the sixth edition of Amazon ML Summer School is being launched for students enrolled in any recognized institute in India and who are expected to graduate in 2027 or 2028. Eligibility: Engineering students enrolled in Bachelor&rsquo;s/Master&rsquo;s/ PhD degrees from any recognised institute of India and are expected to graduate in 2027 or 2028 are eligible to enrol in the Amazon ML Summer School.  Competition Structure: Round 1: Registrations: Participants are required to register for the competition and submit their resumes. All submitted resumes will undergo a screening process for shortlisting. Highlight your most relevant experience, skills, projects, and achievements. Round 2: SOP Submission: Shortlisted participants must submit a Statement of Purpose (SOP) in PDF format. The SOP should be within 500 words. The framework for SOP submission will be communicated to shortlisted participants at a later stage. Round 3: Selection Test: Shortlisted participants will take a 60-minute selection test. Part A will consist of 20 MCQs covering Machine Learning fundamentals, Probability, Statistics, and Linear Algebra. Part B will include two programming questions to evaluate coding and problem-solving skills. Shortlisted students from the Selection Test will make their way to the Amazon ML Summer School (MLSS) Program. Click here to view the module delivery timelines. Rewards:  Chance to secure a spot in the Amazon ML Summer School (MLSS) Program Exclusive Amazon SWAGs Official Acknowledgement Letter from the Amazon Team Networking opportunities with Amazon Scientists and industry experts for top-performing scholars', '2026-05-20T11:00:00+05:30', '2026-08-02T23:59:00+05:30', 'Online', 'online', 'Chance to secure a spot in the Amazon ML Summer Sc', 'https://unstop.com/hackathons/crp-amazon-ml-summer-school-2026-amazon-1688859', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001692533', 'CryptX Files', 'CryptX Files: Crypthunt About : CryptX Files is a 30-hour online Alternate Reality Game (ARG) and crypt hunt inspired by some of the internet''s most infamous creepypasta legends. Participants will uncover hidden websites, decode encrypted messages, analyze images and audio files, inspect source code, and follow digital breadcrumbs across multiple interconnected puzzles to uncover the truth behind the files. Event Overview: The hunt consists of five themed chapters: Slender Man Candle Cove Eyeless Jack Ben Drowned The Puppeteer Each chapter contains multiple interconnected puzzles requiring observation, logical thinking, research, and problem-solving skills. Eligibility: Open to all college and university students Individual participation only Prize Pool: Rs 3000 Certificates for all FREE XYZ DOMAINS TO TOP 15 Event Details: Registration Deadline: 5 June, 11:59 PM IST Event Duration: 30 Hours Event Dates: 6&ndash;7 June Mode: Online Total Chapters: 5 Multiple puzzles per chapter Progressive unlocking format (later puzzles unlock only after solving previous ones) Format: Progress through a series of interconnected puzzles and challenges Clues may be hidden across webpages, images, audio files, metadata, source code, external links, and other digital artifacts Event may involve: Cryptography and ciphers Steganography Source code inspection Image and audio analysis Hidden webpages and backlinks Logic and deduction challenges No prior crypt hunt experience required Creativity, persistence, and attention to detail will be valuable Rules: Participants must compete individually Use of publicly available tools and resources is permitted Any attempt to exploit vulnerabilities, bypass puzzles, manipulate scores, or gain unauthorized access will result in immediate disqualification Organizers reserve the right to verify participant details if required Organizers'' decisions will be final and binding   Join our whatsapp group after registering https://chat.whatsapp.com/GLwLXPlsJMQ2vZC5TMTjCb Join our discord server!https://discord.com/invite/xpNYDVnD   EVENT BEGINS AT 10PM,6TH JUNE', '2026-05-30T00:00:00+05:30', '2026-06-06T00:00:00+05:30', 'Online', 'online', '₹ 1,500', 'https://unstop.com/hackathons/cryptx-files-shiv-nadar-university-snu-greater-noida-1692533', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001692604', 'Campus Compass - Build with AI Challenge', 'About the Challenge: Campus Compass is a one-day solo Build with AI challenge conducted by Chakravyuha Technical Club, Amrita Vishwa Vidyapeetham, Amaravati. Participants must build a static website that acts as a complete guide for freshers joining Amrita Amaravati in July 2026, using only free AI tools. The best submissions will be shared with the actual incoming batch of 2026. Real challenge. Real impact. Guidelines: This is a solo challenge &mdash; no teams allowed Only free AI tools are permitted (Framer, Gamma, Wix, Canva AI, ChatGPT, etc.) &mdash; no paid subscriptions The website must be static &mdash; no backend, no database, no login system The live link must be publicly accessible without any password or login Content must be specific to Amrita Vishwa Vidyapeetham, Amaravati &mdash; not generic All 6 mandatory sections must be present in the website Inter-college participation is allowed Duration: June 1st, 2026 &mdash; 10:00 AM to 8:00 PM (single round) Problem Statement: A fresher is joining Amrita Vishwa Vidyapeetham, Amaravati in July 2026. They are excited but completely clueless. You are their senior. Build a "Campus Compass" website that answers every question a fresher might have before their first day. Your website must include these 6 sections: Home Page &mdash; Welcome message, college branding, clean navigation Academic Life &mdash; Branches, class/lab structure, attendance rules, exam pattern, CGPA tips Clubs & Extracurriculars &mdash; Top clubs, how to join, why it matters Campus & Hostel Life &mdash; Daily routine, food, facilities, settling-in tips Survival Kit &mdash; Do''s and don''ts, common mistakes, time management tips Must-Have Tools & Resources &mdash; Apps, websites, platforms every CSE fresher should know Deliverables: Participants must submit: A live website link (deployed via Framer, Gamma, Netlify, Vercel, GitHub Pages, Render, Railway, or any free platform) A short note (100&ndash;150 words) on which AI tools were used and how At least one screenshot of the website homepage Judging Criteria: Usefulness &mdash; 25 points AI Tool Usage &mdash; 25 points Design & Visual Appeal &mdash; 20 points Completeness &mdash; 20 points Originality &mdash; 10 points Rules: Submissions after 8:00 PM on June 1st will not be accepted under any circumstances Plagiarism or copying another participant''s work leads to immediate disqualification The website must be the participant''s own work &mdash; AI-assisted, but original ideas and structure Chakravyuha reserves the right to share top submissions with the incoming batch of 2026', '2026-05-30T15:00:00+05:30', '2026-06-01T22:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/campus-compass-build-with-ai-challenge-amrita-vishwa-vidyapeetham-amaravati-andhra-pradesh-1692604', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001687152', 'Compile or Cry Coding Competition 1.0', 'After successful registration, participants must join the official Discord server for announcements, support, and important event communication. Compile or Cry 1.0 is an exciting online coding competition designed to test participants&rsquo; programming, logical thinking, debugging, and problem-solving skills. Compete against passionate coders, solve challenging coding questions, and climb the leaderboard to prove your coding abilities. The competition will be conducted completely online on the Compile or Cry platform. Discord will be used for communication, announcements, support, and important updates throughout the event. Participants must remain connected through Discord during the competition. Competition Levels: Participants will compete in 3 programming levels: Level 1 &ndash; C Programming 10 Questions Level 2 &ndash; Python Programming 10 Questions Level 3 &ndash; Java Programming 10 Questions Competition Duration Total competition time: 2 Hours Leaderboard Rankings Leaderboard rankings will be based on: Total Score Accuracy Fastest Submission Time Eligibility: Open to all students interested in coding and problem solving Individual participation only Participants must complete registration successfully before the event Important Rules: Participants must remain in fullscreen mode during the competition Tab switching, window switching, or unfair practices may lead to disqualification Use of AI tools, code generators, ChatGPT, or any external assistance is strictly prohibited Each participant gets only 10 attempts per question Malicious activities such as exploiting vulnerabilities, SQL injection, DDoS attempts, or platform abuse will result in permanent disqualification Organiser decisions will be final Perks: Competitive coding experience Opportunity to test real-world problem-solving skills Improve logical thinking and debugging abilities Compete with passionate coders from different backgrounds Get ready to code, compete, and survive the challenge in Compile or Cry 1.0!', '2026-05-28T00:00:00+05:30', '2026-06-08T22:48:25+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/compile-or-cry-coding-competition-10-compile-or-cry-1687152', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001691060', 'Nexora''26', 'Event Title: Nexora''26 by Cyber Space Club (Rajasthan Only) About the Hackathon: RAJASTHAN ONLY Get ready to innovate, build, and compete in a state-level online hackathon organized in collaboration with Rabbitt AI. This hackathon is designed for students, developers, innovators, and problem-solvers who are ready to transform ideas into impactful solutions. Build your prototype, present your vision, and compete for exciting rewards, with an opportunity to take your journey even further. Special Opportunity: The 1st Place Team will receive a direct opportunity to enter the Rabbit AI''s Hackathon Finale at Delhi. Event Details: Mode: Online Dates: 20th-21st June 2026 Registration Fee: ₹100 per team  Level: State-Level NOTE: ONLY RAJASTHAN INSTITUTION STUDENTS CAN REGISTER', '2026-05-26T00:00:00+05:30', '2026-06-21T17:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/nexora26-manipal-university-mu-jaipur-1691060', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001691344', 'Hack2Hire: AI-Powered Interview Hackathon', 'Overview: AI-focused hackathon centered around intelligent hiring and adaptive interview systems Focuses on rethinking traditional interviews into human-centered AI evaluation platforms Backed by 12+ successful hackathon editions, 100,000+ impressions, and 3000+ registrations Challenge Statement: Build an AI-Powered Mock Interview Platform Simulate real-world interview environments using an AI Interviewer Evaluate candidates using resume relevance, job description alignment, adaptability, responses, and time managementJoin The WhatsApp Group:https://chat.whatsapp.com/K0QhEhJoBOCGPAzhEPXpBS Core Focus Areas: AI-powered interview simulation Resume & Job Description analysis Adaptive question generation Objective performance evaluation Time-aware interview systems Hiring readiness measurement What You Will Build: Smart AI Interviewer Resume and JD analysis engine Dynamic interview difficulty adaptation system Custom evaluation logic Time-based response evaluation Interview termination logic based on performance thresholds Explainable scoring and readiness frameworkJoin The WhatsApp Group:https://chat.whatsapp.com/K0QhEhJoBOCGPAzhEPXpBS Platform Capabilities: Analyze candidate resumes Interpret Job Descriptions Ask technical, behavioral, conceptual, and scenario-based questions Dynamically adjust interview difficulty Evaluate candidates on: Accuracy Clarity Depth Relevance Time efficiency Expected Outputs: Final Interview Readiness Score Skill-wise performance analysis Strengths and weaknesses report Actionable feedback Hiring readiness indicatorJoin The WhatsApp Group:https://chat.whatsapp.com/K0QhEhJoBOCGPAzhEPXpBS Learning Outcomes: Build adaptive AI systems Think like a product-oriented engineer Handle ambiguous requirements Balance usability with intelligence Design systems aligned with real hiring practices Participant Benefits: Free certificate for every valid submission from UnsaidTalks Discounted career acceleration opportunities WhatsApp Group: https://chat.whatsapp.com/K0QhEhJoBOCGPAzhEPXpBS', '2026-05-27T00:00:00+05:30', '2026-06-01T18:00:00+05:30', 'Online', 'online', '₹3499 Mentorship Program – FREE Pay ₹499 → 100% Re', 'https://unstop.com/hackathons/hack2hire-ai-powered-interview-hackathon-unsaidtalks-education-1691344', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001691905', 'AI Startup Buildathon 2026 – Beauty Salon Marketplace Challenge', 'About the Buildathon: AI is changing the way startups are built &mdash; and SuperXgen is creating a platform for the next generation of builders, creators, developers, designers and entrepreneurs to build real startup ideas using AI. Welcome to the SuperXgen AI Startup Buildathon 2026 &mdash; a 48-hour online hackathon where participants will build a city-based beauty salon marketplace platform using modern AI tools and rapid development workflows. Challenge Statement: Participants need to create a modern startup-style platform for a specific city such as: Mumbai Salon Marketplace Bangalore Luxury Salon Finder Delhi Bridal Beauty Booking Platform Pune Home Salon Service Platform Hyderabad Grooming Marketplace Participants are encouraged to use AI tools like: ChatGPT Claude Cursor Lovable Bolt Replit Figma AI Firebase Vercel And more What You Need to Submit: Live website link GitHub repository 2&ndash;3 minute demo video Short explanation of AI tools/workflow used Judging Criteria: Product Thinking UI/UX Design AI Usage & Innovation Execution Quality User Experience Team Size: 1&ndash;3 Members Why Participate?: Build a real startup-style project Showcase your skills publicly Get featured by SuperXgen Network with builders & founders Internship & collaboration opportunities Community recognition and certificates This is not just a coding competition. This is a challenge to build, innovate and launch using AI. Join India&rsquo;s next generation of AI builders with SuperXgen.', '2026-05-28T00:00:00+05:30', '2026-06-28T14:00:00+05:30', 'Online', 'online', '₹ 3,000', 'https://unstop.com/hackathons/ai-startup-buildathon-2026-beauty-salon-marketplace-challenge-superxgen-ai-builder-series-superxgen-1691905', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690978', 'Biothon 2026', 'Welcome to the Biothon 2026 - by Marwadi University (MU), Gujarat! An exciting offline coding challenge focused on computer Science , Biomedical Engineering, and Life Sciences Research. Please note that registration through Unstop alone does not confirm participation in BIOTHON 2026. Only participants who complete their registration on the official BIOTHON website will be considered successfully registered for the event. Register here our biothon website - https://biothon.xinity.in must join the whatsapp group for updates https://chat.whatsapp.com/Lhr3uFSGnSE6NcOkvg7Cgh About the Opportunity: Marwadi University (MU), Gujarat, presents Biothon 2026, an offline coding challenge designed to bring together bright minds to innovate and solve critical problems. This event offers a unique platform for participants to showcase their technical prowess and creative thinking in domains spanning IT , Biomedical Engineering, and Life Sciences Research. Engage in a dynamic competition that emphasizes Environmental Health and Safety (EHS), Innovation Management, Bioinformatics, Critical Thinking, Creative Thinking, and Engineering Skills. Biothon 2026 is your chance to collaborate, develop impactful solutions, and gain recognition for your problem-solving abilities in a challenging and rewarding environment. Themes/Problem Statements: While exact problems will be revealed to participants, this event focuses on areas related to IT Operations, Biomedical Engineering, Life Sciences Research: Environmental Health and Safety (EHS) Innovation Management Bioinformatics Critical Thinking Creative Thinking Engineering Skills Eligibility and Registration: This opportunity is open for Team Participation. Competition Structure: The structure for this online coding challenge is as follows: Submission PPT: This initial stage requires participants to register online, select a domain and problem statement, and prepare a presentation using the official PPT template. Your submission, covering problem analysis, proposed solution, technology stack, and expected outcomes, must be uploaded by June 20th, 2026. Adherence to the template is crucial for advancement to the next round. Video Submission (20th June 2026): Shortlisted teams from Round 1 will proceed to this stage. You will need to record a detailed walkthrough video (5-7 minutes) of your solution, explaining the problem, approach, and impact. The video link must be submitted by June 25th, 2026, for consideration for the Grand Finale. Grand Finale (Offline) (22th July 2026): The top teams will be invited to Marwadi University, Rajkot, Gujarat, for an offline grand finale. Here, you will demonstrate your complete solutions live to an expert judging panel, engage in Q&A sessions, and present your innovative work. Rewards and Prizes: Rewards & prize details (as provided): Rank 1 (Health Care) includes a cash prize, certificate, and a pre-placement interview opportunity. Rank 2 (Health Care) includes a cash prize and a certificate. Rank 3 (Health Care) includes a cash prize and a certificate. RANK 1 (Agriculture) includes a cash prize, certificate, and a pre-placement interview opportunity. RANK 2 (Agriculture) includes a cash prize and a certificate. RANK 3 (Agriculture) includes a cash prize and a certificate. Rank 1 (Environment & Biodiversity) includes a cash prize, certificate, and a pre-placement interview opportunity. Rank 2 (Environment & Biodiversity) includes a cash prize and a certificate. Rank 3 (Environment & Biodiversity) includes a cash prize and a certificate. Join the Biothon 2026 offline challenge hosted by Marwadi University (MU), Gujarat, and bring your innovative solutions to life!', '2026-05-26T00:00:00+05:30', '2026-07-22T15:02:00+05:30', 'Online', 'online', '₹ 30,000', 'https://unstop.com/hackathons/biothon-2026-marwadi-university-mu-gujarat-1690978', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690790', 'NexWave', 'ViralWave &ndash; Technical Quiz & Coding Competition: ViralWave is a two-round technical competition designed to test both knowledge and practical coding skills. The event begins with Quizify &ndash; The Ultimate Tech Quiz, where participants compete on technical concepts, logical reasoning, and problem-solving. Participants who qualify move on to Codify &ndash; Ultimate Coding Challenge, where they solve coding problems and demonstrate their programming abilities under time constraints. ViralWave provides a competitive platform to learn, challenge yourself, and showcase your technical expertise. Round 1: Codify &ndash; Coding Competition Codify is the second and final round of ViralWave, where participants transform their logic into code. Only top performers from Quizify advance to this stage. This round challenges participants to solve real-world coding problems using efficient algorithms and optimized solutions under time constraints. Format Details: Multiple coding problems (DSA-based) along with core programming questions Problem difficulty levels: Easy and Medium Time-bound contest: 1 hour Participants must write and submit working code Evaluation based on correctness and efficiency Evaluation Criteria: Number of problems solved Code correctness Time taken (used as tiebreaker) Objective: Test problem-solving and coding ability Evaluate algorithmic thinking Encourage optimized and clean coding practices Prizes and Perks: Rewards for top-performing participants Certificates for all participants Eligibility: Open to all students and technology enthusiasts Individual participation only Basic knowledge of programming is recommended Why Participate: Improve technical and programming knowledge Compete with participants from different backgrounds and skill levels Gain experience in technical quizzes and assessments Build confidence for technical interviews and coding challenges Get the opportunity to win rewards and recognition Rules and Guidelines: Participants must strictly follow the allotted time for the quiz. Any form of cheating or unfair practice will result in immediate disqualification. Final Note: ViralWave is designed to test your knowledge, logic, speed, and coding skills in a competitive environment.', '2026-05-25T00:00:00+05:30', '2026-07-21T12:42:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/nexwave-jharkhand-raksha-shakti-university-1690790', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001691536', 'Build-A-Thon', 'Have an idea? Build it. The Unison Tech Club invites all innovators, creators, coders, designers, and problem-solvers to participate in our online BUILD-A-THON &mdash; where ideas turn into impactful solutions. Join the official WhatsApp Group of BUILD-A-THON https://chat.whatsapp.com/GOVMpreb8IgHykPl1CdSNu Choose a domain, collaborate with your team, and build something meaningful. Tracks / Themes: Artificial Intelligence & Machine Learning Cybersecurity Open Innovation Healthcare & MedTech FinTech Sustainability Women Safety & Social Impact Blockchain & Web3 Gaming & Entertainment Tech IoT & Smart Systems &zwj;Open to beginners and experienced builders alike! Why participate? Hands-on building experience Team collaboration & innovation Mentorship and learning opportunities Project showcase opportunity Winners certificates Date: 6th June 2026 Time: 4 PM Mode: Online Team Size: 1-5 members Build. Innovate. Create. Contact the Organisers: Bhavika - +91 9205969968 Rehan - +91 8743973073 Innovative by: Bhavika and Rehan', '2026-05-27T00:00:00+05:30', '2026-06-10T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/build-a-thon-unison-1691536', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690215', 'Hack-The-Den', 'About the Hackathon: A high-energy innovation challenge designed for tech enthusiasts to collaborate, build, and solve real-world problems. This 8 hour hackathon serves as a launchpad for next-generation ideas, bringing together diverse minds to push the boundaries of technology and creativity. Mandatory Step: Fill this Mandatory Form -  https://forms.gle/w7BNbYwiFiXGJ2H27  All participants must join the official WhatsApp update group:  Join my WhatsApp group OR https://chat.whatsapp.com/H0xuUbkKFltCNw3WBrlr4U Themes: AI, Blockchain, Web Development, Open Innovation. Eligibility Criteria: Open to students, developers, designers, and tech enthusiasts across India Cross-college and cross-domain teams are allowed Beginners as well as experienced participants are welcome Each participant can be a part of only one team Team Size: 2-3 members (Solo participation is not allowed) Round 1: PPT / Idea Submission (Online & Elimination Round) Teams must submit an idea presentation (PPT) covering: Problem statement, Proposed solution, Features and workflow, Tech stack, and Innovation & impact. Only shortlisted teams will advance. Round 2: Grand Finale (Offline Round) : Galgotias University Selected teams from Round 1 will compete in a hands-on, offline prototyping and judging round.     Join the community. Build. Learn. Network. Grow. Instagram: @coders_denn LinkedIn: Coders Den LinkedIn Page', '2026-05-24T18:00:00+05:30', '2026-06-10T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hack-the-den-coders-den-1690215', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690749', 'Venture Vortex - Startup and Business Plan Contest', 'Welcome to Venture Vortex 2026 A business plan competition by the Entrepreneurship Development Cell, KSIT. Use Code BLR10 for Flat 10% OFF (Only for first 10 Teams). Event Format The event will consist of a single pitching round. All participating teams must present an original start-up or business idea before the judges on 30th May. The Presentation Should Cover Introduction of the team and business idea. Problem identified and its relevance. Proposed solution or innovation. Target users or customers. Uniqueness of the idea. Business or social impact potential. Expected impact or future scope. Evaluation Process Each team will be given a fixed time slot for presentation and interaction with the judges. Teams will be evaluated based on: Innovation. Creativity. Feasibility. Presentation. Overall impact of the idea. Important Information Team size: 1 to 3 members. Teams must choose only ONE domain. Start-up idea must be original. Mentor guidance is allowed (internal or external). Registration is confirmed only after payment verification.', '2026-05-25T00:00:00+05:30', '2026-06-13T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/venture-vortex-startup-and-business-plan-contest-k-s-institute-of-technology-1690749', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;